/**
 * Adaptation Card Component
 * TypeScript version
 */

import { motion } from 'framer-motion';
import { 
  TrashIcon,
  EyeIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';
import { formatDateTime } from '../../utils/dateFormatter';

interface Adaptation {
  id: string;
  'Match Score'?: number;
  'Status'?: string;
  'Created At'?: string;
  [key: string]: unknown;
}

interface AdaptationCardProps {
  adaptation: Adaptation;
  index: number;
  resumeName: string;
  candidateName?: string;
  adaptedTitle?: string;
  missionTitle: string;
  onView: (adaptation: Adaptation) => void;
  onExport: (adaptation: Adaptation) => void;
  onDelete: (id: string) => void;
  t: (key: string) => string;
}

const getScoreColor = (score: number): string => {
  if (score >= 80) return 'text-green-700 dark:text-green-400';
  if (score >= 60) return 'text-yellow-700 dark:text-yellow-400';
  return 'text-red-700 dark:text-red-400';
};

const getScoreBgColor = (score: number): string => {
  if (score >= 80) return 'bg-green-100 dark:bg-green-900/30';
  if (score >= 60) return 'bg-yellow-100 dark:bg-yellow-900/30';
  return 'bg-red-100 dark:bg-red-900/30';
};

const getStatusColor = (status: string): string => {
  switch (status) {
    case 'Completed': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400';
    case 'Processing': return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400';
    case 'Failed': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400';
    default: return 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300';
  }
};

const AdaptationCard = ({ 
  adaptation, 
  index, 
  resumeName, 
  candidateName,
  adaptedTitle,
  missionTitle, 
  onView, 
  onExport, 
  onDelete, 
  t 
}: AdaptationCardProps): JSX.Element => {
  const createdAt = adaptation['Created At'] 
    ? formatDateTime(adaptation['Created At'])
    : '-';

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.05 }}
      className="bg-white dark:bg-gray-800 rounded-lg shadow hover:shadow-lg transition-shadow border border-gray-200 dark:border-gray-700"
    >
      <div className="p-6">
        <div className="flex items-center justify-between mb-4">
          <div className={`px-3 py-1 rounded-full text-sm font-semibold ${getScoreBgColor(adaptation['Match Score'] || 0)}`}>
            <span className={getScoreColor(adaptation['Match Score'] || 0)}>
              {adaptation['Match Score'] || 0}% Match
            </span>
          </div>
          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(adaptation['Status'] || '')}`}>
            {t(`adaptations.status.${(adaptation['Status'] || 'unknown').toLowerCase()}`)}
          </span>
        </div>

        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-1 truncate">
          {candidateName || resumeName}
        </h3>

        {adaptedTitle && (
          <p className="text-sm font-medium text-blue-600 dark:text-blue-400 mb-2 truncate italic">
            {adaptedTitle}
          </p>
        )}

        <p className="text-sm text-gray-600 dark:text-gray-400 mb-4 truncate">
          ÔåÆ {missionTitle}
        </p>

        <p className="text-xs text-gray-500 dark:text-gray-500 mb-4">
          {createdAt}
        </p>

        <div className="flex items-center gap-2">
          <button
            onClick={() => onView(adaptation)}
            className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 dark:hover:bg-blue-900/50 transition-colors"
          >
            <EyeIcon className="w-4 h-4" />
            <span className="text-sm">{t('adaptations.actions.view')}</span>
          </button>
          <button
            onClick={() => onExport(adaptation)}
            className="p-2 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg hover:bg-green-100 dark:hover:bg-green-900/50 transition-colors"
            title={t('adaptations.actions.export')}
          >
            <ArrowDownTrayIcon className="w-4 h-4" />
          </button>
          <button
            onClick={() => onDelete(adaptation.id)}
            className="p-2 bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-lg hover:bg-red-100 dark:hover:bg-red-900/50 transition-colors"
            title={t('adaptations.actions.delete')}
          >
            <TrashIcon className="w-4 h-4" />
          </button>
        </div>
      </div>
    </motion.div>
  );
};

export { getScoreColor, getScoreBgColor, getStatusColor };
export default AdaptationCard;

/**
 * ErrorToast Component
 * Custom toast component with expandable error details
 */

import { useState } from 'react';
import toast from 'react-hot-toast';
import { ExclamationTriangleIcon, ChevronDownIcon, ChevronUpIcon, XMarkIcon } from '@heroicons/react/24/outline';
import { isSessionRedirectError } from '../utils/apiInterceptor';

interface ErrorToastProps {
  message: string;
  details?: string;
  toastId: string;
}

const ErrorToast = ({ message, details, toastId }: ErrorToastProps): JSX.Element => {
  const [showDetails, setShowDetails] = useState(false);

  return (
    <div className="max-w-md w-full bg-white dark:bg-gray-800 shadow-lg rounded-lg pointer-events-auto ring-1 ring-red-500/20 overflow-hidden">
      <div className="p-4">
        <div className="flex items-start">
          <div className="flex-shrink-0">
            <ExclamationTriangleIcon className="h-6 w-6 text-red-500" />
          </div>
          <div className="ml-3 flex-1 min-w-0">
            <p className="text-sm font-medium text-gray-900 dark:text-white">
              Erreur
            </p>
            <p className="mt-1 text-sm text-gray-600 dark:text-gray-400 break-words">
              {message}
            </p>

            {details && (
              <>
                <button
                  onClick={() => setShowDetails(!showDetails)}
                  className="mt-2 flex items-center gap-1 text-xs text-blue-600 dark:text-blue-400 hover:underline"
                >
                  {showDetails ? (
                    <>
                      <ChevronUpIcon className="h-3 w-3" />
                      Masquer les d├®tails
                    </>
                  ) : (
                    <>
                      <ChevronDownIcon className="h-3 w-3" />
                      Voir les d├®tails
                    </>
                  )}
                </button>

                {showDetails && (
                  <div className="mt-2 p-2 bg-gray-100 dark:bg-gray-900 rounded text-xs font-mono text-gray-600 dark:text-gray-400 max-h-32 overflow-auto whitespace-pre-wrap break-all">
                    {details}
                  </div>
                )}
              </>
            )}
          </div>
          <div className="ml-4 flex-shrink-0">
            <button
              onClick={() => toast.dismiss(toastId)}
              className="rounded-md inline-flex text-gray-400 hover:text-gray-500 dark:hover:text-gray-300 focus:outline-none"
            >
              <span className="sr-only">Fermer</span>
              <XMarkIcon className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * Show error toast with expandable details
 */
export const showErrorWithDetails = (
  message: string,
  details?: string,
  duration = 8000
): string => {
  const toastId = toast.custom(
    (t) => (
      <div className={t.visible ? 'animate-enter' : 'animate-leave'}>
        <ErrorToast message={message} details={details} toastId={t.id} />
      </div>
    ),
    { duration }
  );
  return toastId;
};

/**
 * Parse and show API error with details
 */
export const showApiError = async (
  response: Response,
  defaultMessage = 'Une erreur est survenue'
): Promise<void> => {
  let errorData: Record<string, unknown> = {};
  let details = '';

  try {
    errorData = await response.json();
    details = JSON.stringify(errorData, null, 2);
  } catch {
    details = `Status: ${response.status} ${response.statusText}`;
  }

  const message = (errorData.error as string) || 
                  (errorData.message as string) || 
                  getStatusMessage(response.status) ||
                  defaultMessage;

  showErrorWithDetails(message, details);
};

/**
 * Get user-friendly message from HTTP status
 */
export const getStatusMessage = (status: number): string | null => {
  const messages: Record<number, string> = {
    400: 'Requ├¬te invalide',
    401: 'Session expir├®e - veuillez vous reconnecter',
    403: 'Acc├¿s refus├®',
    404: 'Ressource non trouv├®e',
    408: 'D├®lai d\'attente d├®pass├®',
    413: 'Fichier trop volumineux',
    422: 'Donn├®es invalides',
    429: 'Trop de requ├¬tes - veuillez patienter',
    500: 'Erreur serveur',
    502: 'Service indisponible',
    503: 'Service temporairement indisponible',
    504: 'D├®lai d\'attente du serveur d├®pass├®'
  };
  return messages[status] || null;
};

/**
 * Convert technical error messages to user-friendly messages
 */
export const getUserFriendlyMessage = (error: unknown): { message: string; details: string } => {
  let technicalMessage = '';
  let details = '';

  if (error instanceof Error) {
    technicalMessage = error.message;
    details = error.stack || '';
  } else if (typeof error === 'string') {
    technicalMessage = error;
  } else if (typeof error === 'object' && error !== null) {
    const err = error as Record<string, unknown>;
    technicalMessage = (err.message as string) || (err.error as string) || '';
    details = JSON.stringify(error, null, 2);
  }

  // Map technical messages to user-friendly ones
  const errorMappings: Array<{ pattern: RegExp; message: string }> = [
    { pattern: /fetch|network|net::ERR|Failed to fetch/i, message: 'Impossible de contacter le serveur. V├®rifiez votre connexion internet.' },
    { pattern: /timeout|timed out|ETIMEDOUT/i, message: 'La requ├¬te a pris trop de temps. Veuillez r├®essayer.' },
    { pattern: /401|unauthorized|not authenticated/i, message: 'Votre session a expir├®. Veuillez vous reconnecter.' },
    { pattern: /403|forbidden|access denied/i, message: 'Vous n\'avez pas les droits n├®cessaires pour cette action.' },
    { pattern: /404|not found/i, message: 'La ressource demand├®e n\'existe pas ou a ├®t├® supprim├®e.' },
    { pattern: /500|internal server/i, message: 'Une erreur serveur est survenue. Veuillez r├®essayer plus tard.' },
    { pattern: /502|503|504|bad gateway|service unavailable/i, message: 'Le service est temporairement indisponible. Veuillez r├®essayer.' },
    { pattern: /CORS|cross-origin/i, message: 'Erreur de configuration serveur. Contactez l\'administrateur.' },
    { pattern: /JSON|parse|syntax|Failed to parse/i, message: 'Erreur de format de donn├®es re├ºues du serveur. Veuillez r├®essayer.' },
    { pattern: /Search Analysis|analyze.*response/i, message: 'L\'analyse du CV a ├®chou├®. Veuillez r├®essayer.' },
    { pattern: /abort|cancelled|canceled/i, message: 'L\'op├®ration a ├®t├® annul├®e.' },
    { pattern: /quota|storage|space/i, message: 'Espace de stockage insuffisant.' },
    { pattern: /permission|denied/i, message: 'Permission refus├®e pour cette op├®ration.' },
    { pattern: /invalid|validation/i, message: 'Les donn├®es saisies sont invalides. Veuillez v├®rifier.' },
    { pattern: /duplicate|already exists/i, message: 'Cet ├®l├®ment existe d├®j├á.' },
    { pattern: /rate limit|too many requests/i, message: 'Trop de requ├¬tes. Veuillez patienter quelques instants.' },
    { pattern: /file.*large|size.*exceed/i, message: 'Le fichier est trop volumineux.' },
    { pattern: /unsupported.*type|invalid.*format/i, message: 'Format de fichier non support├®.' },
  ];

  for (const mapping of errorMappings) {
    if (mapping.pattern.test(technicalMessage)) {
      return { message: mapping.message, details: technicalMessage + (details ? '\n\n' + details : '') };
    }
  }

  // If no mapping found, return a generic message but keep technical details
  if (technicalMessage) {
    return { 
      message: 'Une erreur est survenue. Veuillez r├®essayer.', 
      details: technicalMessage + (details ? '\n\n' + details : '')
    };
  }

  return { message: 'Une erreur inattendue est survenue.', details };
};

/**
 * Show error from catch block with user-friendly message and technical details
 * Silently ignores SessionRedirectError (redirect already in progress)
 */
export const showCaughtError = (
  error: unknown,
  _contextMessage = 'Une erreur est survenue'
): void => {
  // Don't show toast for session redirect errors - redirect is already happening
  if (isSessionRedirectError(error)) {
    return;
  }

  const { message, details } = getUserFriendlyMessage(error);
  showErrorWithDetails(message, details);
};

export default ErrorToast;

import React, { useState, useEffect } from 'react';
import { ShieldCheckIcon, ShieldExclamationIcon, KeyIcon, TrashIcon, InformationCircleIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';
import TwoFactorSetup from './TwoFactorSetup';
import { useAuthFetch } from '../hooks/useAuthFetch';
import logger from '../utils/logger.frontend';

interface TwoFactorStatus {
  enabled: boolean;
  enabledAt: string | null;
  backupCodesRemaining: number;
}

export default function TwoFactorSettings() {
  const { t } = useTranslation();
  const { authGet, authPost } = useAuthFetch();
  const [status, setStatus] = useState<TwoFactorStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [showSetup, setShowSetup] = useState(false);
  const [showDisableModal, setShowDisableModal] = useState(false);
  const [showRegenerateModal, setShowRegenerateModal] = useState(false);
  const [disableCode, setDisableCode] = useState('');
  const [regenerateCode, setRegenerateCode] = useState('');
  const [newBackupCodes, setNewBackupCodes] = useState<string[]>([]);
  const [actionLoading, setActionLoading] = useState(false);

  const fetchStatus = async () => {
    try {
      const response = await authGet('/api/2fa/status');
      if (response.ok) {
        const data = await response.json();
        setStatus(data);
      }
    } catch (error) {
      logger.error('[2FA] Failed to fetch status:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStatus();
  }, []);

  const handleDisable = async () => {
    if (!disableCode) {
      toast.error('Entrez votre code 2FA');
      return;
    }

    setActionLoading(true);
    try {
      const response = await authPost('/api/2fa/disable', { code: disableCode });

      const data = await response.json();

      if (response.ok) {
        toast.success('2FA d├®sactiv├®');
        setShowDisableModal(false);
        setDisableCode('');
        fetchStatus();
      } else {
        toast.error(data.message || 'Code invalide');
      }
    } catch (_) {
      toast.error('Erreur lors de la d├®sactivation');
    } finally {
      setActionLoading(false);
    }
  };

  const handleRegenerate = async () => {
    if (!regenerateCode) {
      toast.error('Entrez votre code 2FA');
      return;
    }

    setActionLoading(true);
    try {
      const response = await authPost('/api/2fa/backup-codes/regenerate', { code: regenerateCode });

      const data = await response.json();

      if (response.ok) {
        setNewBackupCodes(data.backupCodes);
        setRegenerateCode('');
        fetchStatus();
      } else {
        toast.error(data.message || 'Code invalide');
      }
    } catch (_) {
      toast.error('Erreur lors de la r├®g├®n├®ration');
    } finally {
      setActionLoading(false);
    }
  };

  const copyBackupCodes = async () => {
    try {
      await navigator.clipboard.writeText(newBackupCodes.join('\n'));
      toast.success('Codes copi├®s !');
    } catch (_) {
      toast.error('Erreur lors de la copie');
    }
  };

  if (loading) {
    return (
      <div className="animate-pulse bg-gray-100 dark:bg-gray-700 rounded-lg p-6">
        <div className="h-6 bg-gray-200 dark:bg-gray-600 rounded w-1/3 mb-4"></div>
        <div className="h-4 bg-gray-200 dark:bg-gray-600 rounded w-2/3"></div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
      <div className="flex items-center gap-3 mb-4">
        <ShieldCheckIcon className="h-6 w-6 text-blue-600" />
        <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
          {t('twoFactor.title')}
        </h3>
      </div>

      {/* OAuth notice */}
      <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg flex items-start gap-2">
        <InformationCircleIcon className="h-5 w-5 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
        <p className="text-sm text-blue-700 dark:text-blue-300">
          {t('twoFactor.loginOnlyNotice')}
        </p>
      </div>

      {status?.enabled ? (
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-green-600 dark:text-green-400">
            <ShieldCheckIcon className="h-5 w-5" />
            <span className="font-medium">2FA activ├®</span>
          </div>

          {status.enabledAt && (
            <p className="text-sm text-gray-500 dark:text-gray-400">
              Activ├® le {new Date(status.enabledAt).toLocaleDateString('fr-FR')}
            </p>
          )}

          <div className="flex items-center gap-2 text-sm">
            <KeyIcon className="h-4 w-4 text-gray-400" />
            <span className="text-gray-600 dark:text-gray-300">
              {status.backupCodesRemaining} codes de secours restants
            </span>
            {status.backupCodesRemaining <= 2 && (
              <span className="text-yellow-600 dark:text-yellow-400 text-xs">
                (Pensez ├á les r├®g├®n├®rer)
              </span>
            )}
          </div>

          <div className="flex flex-wrap gap-3 pt-4">
            <button
              onClick={() => setShowRegenerateModal(true)}
              className="px-4 py-2 text-sm border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 flex items-center gap-2"
            >
              <KeyIcon className="h-4 w-4" />
              R├®g├®n├®rer les codes de secours
            </button>
            <button
              onClick={() => setShowDisableModal(true)}
              className="px-4 py-2 text-sm border border-red-300 dark:border-red-700 text-red-600 dark:text-red-400 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-2"
            >
              <TrashIcon className="h-4 w-4" />
              D├®sactiver 2FA
            </button>
          </div>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="flex items-center gap-2 text-yellow-600 dark:text-yellow-400">
            <ShieldExclamationIcon className="h-5 w-5" />
            <span>2FA non activ├®</span>
          </div>

          <p className="text-sm text-gray-600 dark:text-gray-400">
            Prot├®gez votre compte avec l'authentification ├á deux facteurs. 
            Vous aurez besoin d'une application comme Google Authenticator ou Authy.
          </p>

          <button
            onClick={() => setShowSetup(true)}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
          >
            <ShieldCheckIcon className="h-5 w-5" />
            Activer 2FA
          </button>
        </div>
      )}

      {/* Setup Modal */}
      {showSetup && (
        <TwoFactorSetup
          onClose={() => setShowSetup(false)}
          onSuccess={() => {
            setShowSetup(false);
            fetchStatus();
          }}
        />
      )}

      {/* Disable Modal */}
      {showDisableModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-md w-full p-6">
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
              D├®sactiver 2FA
            </h3>
            <p className="text-gray-600 dark:text-gray-400 mb-4">
              Entrez votre code 2FA actuel pour confirmer la d├®sactivation.
            </p>
            <input
              type="text"
              value={disableCode}
              onChange={(e) => setDisableCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
              placeholder="000000"
              className="w-full text-center text-2xl font-mono tracking-widest px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white mb-4"
              maxLength={6}
              autoFocus
            />
            <div className="flex gap-3">
              <button
                onClick={() => {
                  setShowDisableModal(false);
                  setDisableCode('');
                }}
                className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
              >
                Annuler
              </button>
              <button
                onClick={handleDisable}
                disabled={actionLoading || disableCode.length !== 6}
                className="flex-1 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50"
              >
                {actionLoading ? 'D├®sactivation...' : 'D├®sactiver'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Regenerate Modal */}
      {showRegenerateModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-md w-full p-6">
            {newBackupCodes.length === 0 ? (
              <>
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
                  R├®g├®n├®rer les codes de secours
                </h3>
                <p className="text-gray-600 dark:text-gray-400 mb-4">
                  Entrez votre code 2FA pour g├®n├®rer de nouveaux codes de secours.
                  Les anciens codes seront invalid├®s.
                </p>
                <input
                  type="text"
                  value={regenerateCode}
                  onChange={(e) => setRegenerateCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  placeholder="000000"
                  className="w-full text-center text-2xl font-mono tracking-widest px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white mb-4"
                  maxLength={6}
                  autoFocus
                />
                <div className="flex gap-3">
                  <button
                    onClick={() => {
                      setShowRegenerateModal(false);
                      setRegenerateCode('');
                    }}
                    className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
                  >
                    Annuler
                  </button>
                  <button
                    onClick={handleRegenerate}
                    disabled={actionLoading || regenerateCode.length !== 6}
                    className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                  >
                    {actionLoading ? 'G├®n├®ration...' : 'R├®g├®n├®rer'}
                  </button>
                </div>
              </>
            ) : (
              <>
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-4">
                  Nouveaux codes de secours
                </h3>
