import React, { useState } from 'react';
import { ShieldCheckIcon, KeyIcon, ClipboardDocumentIcon, CheckIcon, XMarkIcon } from '@heroicons/react/24/outline';
import { useTranslation } from 'react-i18next';
import toast from 'react-hot-toast';
import { useAuthFetch } from '../hooks/useAuthFetch';

interface TwoFactorSetupProps {
  onClose: () => void;
  onSuccess: () => void;
}

interface SetupData {
  secret: string;
  qrCodeDataUrl: string;
  backupCodes: string[];
}

export default function TwoFactorSetup({ onClose, onSuccess }: TwoFactorSetupProps) {
  const { t: _t } = useTranslation();
  const { authPost } = useAuthFetch();
  const [step, setStep] = useState<'intro' | 'setup' | 'verify' | 'backup'>('intro');
  const [setupData, setSetupData] = useState<SetupData | null>(null);
  const [verificationCode, setVerificationCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [copiedSecret, setCopiedSecret] = useState(false);
  const [copiedBackup, setCopiedBackup] = useState(false);

  const startSetup = async () => {
    setLoading(true);
    try {
      const response = await authPost('/api/2fa/setup', {});

      if (!response.ok) {
        throw new Error('Failed to start 2FA setup');
      }

      const data = await response.json();
      setSetupData(data);
      setStep('setup');
    } catch (_) {
      toast.error('Erreur lors de l\'initialisation du 2FA');
    } finally {
      setLoading(false);
    }
  };

  const verifyCode = async () => {
    if (verificationCode.length !== 6) {
      toast.error('Le code doit contenir 6 chiffres');
      return;
    }

    setLoading(true);
    try {
      const response = await authPost('/api/2fa/verify', { code: verificationCode });

      const data = await response.json();

      if (!response.ok) {
        toast.error(data.message || 'Code invalide');
        return;
      }

      toast.success('2FA activ├® avec succ├¿s !');
      setStep('backup');
    } catch (_) {
      toast.error('Erreur lors de la v├®rification');
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = async (text: string, type: 'secret' | 'backup') => {
    try {
      await navigator.clipboard.writeText(text);
      if (type === 'secret') {
        setCopiedSecret(true);
        setTimeout(() => setCopiedSecret(false), 2000);
      } else {
        setCopiedBackup(true);
        setTimeout(() => setCopiedBackup(false), 2000);
      }
      toast.success('Copi├® !');
    } catch (_) {
      toast.error('Erreur lors de la copie');
    }
  };

  const handleComplete = () => {
    onSuccess();
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
      <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-md w-full max-h-[90vh] overflow-y-auto relative">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-center gap-3">
            <ShieldCheckIcon className="h-6 w-6 text-blue-600" />
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
              Authentification ├á deux facteurs
            </h2>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
          >
            <XMarkIcon className="h-6 w-6" />
          </button>
        </div>

        <div className="p-6">
          {/* Step: Intro */}
          {step === 'intro' && (
            <div className="space-y-4">
              <p className="text-gray-600 dark:text-gray-300 text-sm leading-relaxed">
                L'authentification ├á deux facteurs (2FA) ajoute une couche de s├®curit├® suppl├®mentaire ├á votre compte.
              </p>
              <p className="text-gray-600 dark:text-gray-300 text-sm leading-relaxed">
                Vous aurez besoin d'une application d'authentification comme :
              </p>
              <ul className="list-disc list-inside text-gray-600 dark:text-gray-300 space-y-1 text-sm">
                <li>Google Authenticator</li>
                <li>Microsoft Authenticator</li>
                <li>Authy</li>
              </ul>
              <button
                onClick={startSetup}
                disabled={loading}
                className="w-full mt-4 px-4 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center gap-2"
              >
                {loading ? (
                  <span className="animate-spin">ÔÅ│</span>
                ) : (
                  <>
                    <KeyIcon className="h-5 w-5" />
                    Configurer 2FA
                  </>
                )}
              </button>
            </div>
          )}

          {/* Step: Setup - QR Code */}
          {step === 'setup' && setupData && (
            <div className="space-y-4">
              <p className="text-gray-600 dark:text-gray-300 text-center">
                Scannez ce QR code avec votre application d'authentification
              </p>

              <div className="flex justify-center">
                <img 
                  src={setupData.qrCodeDataUrl} 
                  alt="QR Code 2FA" 
                  className="w-48 h-48 border-4 border-white rounded-lg shadow-lg"
                />
              </div>

              <div className="bg-gray-100 dark:bg-gray-700 rounded-lg p-3">
                <p className="text-xs text-gray-500 dark:text-gray-400 mb-1">
                  Ou entrez ce code manuellement :
                </p>
                <div className="flex items-center gap-2">
                  <code className="flex-1 text-sm font-mono bg-white dark:bg-gray-800 px-3 py-2 rounded border">
                    {setupData.secret}
                  </code>
                  <button
                    onClick={() => copyToClipboard(setupData.secret, 'secret')}
                    className="p-2 text-gray-500 hover:text-blue-600"
                  >
                    {copiedSecret ? (
                      <CheckIcon className="h-5 w-5 text-green-500" />
                    ) : (
                      <ClipboardDocumentIcon className="h-5 w-5" />
                    )}
                  </button>
                </div>
              </div>

              <button
                onClick={() => setStep('verify')}
                className="w-full px-4 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                Suivant
              </button>
            </div>
          )}

          {/* Step: Verify */}
          {step === 'verify' && (
            <div className="space-y-4">
              <p className="text-gray-600 dark:text-gray-300 text-center">
                Entrez le code ├á 6 chiffres affich├® dans votre application
              </p>

              <input
                type="text"
                value={verificationCode}
                onChange={(e) => setVerificationCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                placeholder="000000"
                className="w-full text-center text-3xl font-mono tracking-widest px-4 py-4 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
                maxLength={6}
                autoFocus
              />

              <div className="flex gap-3">
                <button
                  onClick={() => setStep('setup')}
                  className="flex-1 px-4 py-3 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
                >
                  Retour
                </button>
                <button
                  onClick={verifyCode}
                  disabled={loading || verificationCode.length !== 6}
                  className="flex-1 px-4 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
                >
                  {loading ? 'V├®rification...' : 'V├®rifier'}
                </button>
              </div>
            </div>
          )}

          {/* Step: Backup Codes */}
          {step === 'backup' && setupData && (
            <div className="space-y-4">
              <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 rounded-lg p-4">
                <p className="text-yellow-800 dark:text-yellow-200 font-medium">
                  ÔÜá´©Å Sauvegardez ces codes de secours
                </p>
                <p className="text-yellow-700 dark:text-yellow-300 text-sm mt-1">
                  Si vous perdez l'acc├¿s ├á votre application d'authentification, vous pourrez utiliser ces codes pour vous connecter.
                </p>
              </div>

              <div className="bg-gray-100 dark:bg-gray-700 rounded-lg p-4">
                <div className="grid grid-cols-2 gap-2">
                  {setupData.backupCodes.map((code, index) => (
                    <code 
                      key={index}
                      className="text-center font-mono text-sm bg-white dark:bg-gray-800 px-3 py-2 rounded border"
                    >
                      {code}
                    </code>
                  ))}
                </div>
                <button
                  onClick={() => copyToClipboard(setupData.backupCodes.join('\n'), 'backup')}
                  className="w-full mt-3 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-600 flex items-center justify-center gap-2"
                >
                  {copiedBackup ? (
                    <>
                      <CheckIcon className="h-5 w-5 text-green-500" />
                      Copi├® !
                    </>
                  ) : (
                    <>
                      <ClipboardDocumentIcon className="h-5 w-5" />
                      Copier tous les codes
                    </>
                  )}
                </button>
              </div>

              <button
                onClick={handleComplete}
                className="w-full px-4 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700"
              >
                J'ai sauvegard├® mes codes
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/**
 * Firm Form Modal Component
 * TypeScript version with logo upload support
 */

import { useState, useEffect, FormEvent, ChangeEvent, useRef } from 'react';
import { PhotoIcon, TrashIcon } from '@heroicons/react/24/outline';
import toast from 'react-hot-toast';
import Modal from './Modal';
import userService from '../../utils/userService';

interface Firm {
  id?: string;
  name?: string;
  logo_url?: string;
}

interface FirmFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (data: { name: string }) => void;
  firm: Firm | null;
  t: (key: string) => string;
}

const FirmFormModal = ({ isOpen, onClose, onSubmit, firm, t }: FirmFormModalProps): JSX.Element => {
  const [name, setName] = useState<string>('');
  const [logoUrl, setLogoUrl] = useState<string>('');
  const [logoPreview, setLogoPreview] = useState<string>('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState<boolean>(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setName(firm?.name || '');
    setLogoUrl(firm?.logo_url || '');
    setLogoPreview(firm?.logo_url || '');
    setSelectedFile(null);
  }, [firm, isOpen]);

  const handleSubmit = async (e: FormEvent<HTMLFormElement>): Promise<void> => {
    e.preventDefault();

    // If editing and a new file is selected, upload it first
    if (firm?.id && selectedFile) {
      try {
        setUploading(true);
        await userService.uploadFirmLogo(firm.id, selectedFile);
        toast.success(t('users.management.messages.logoUploaded'));
      } catch (_) {
        toast.error(t('users.management.messages.logoUploadFailed'));
        setUploading(false);
        return;
      }
      setUploading(false);
    }

    onSubmit({ name });
  };

  const handleNameChange = (e: ChangeEvent<HTMLInputElement>): void => {
    setName(e.target.value);
  };

  const handleFileSelect = (e: ChangeEvent<HTMLInputElement>): void => {
    const file = e.target.files?.[0];
    if (file) {
      // Validate file type
      const allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml'];
      if (!allowedTypes.includes(file.type)) {
        toast.error(t('users.management.messages.invalidFileType'));
        return;
      }

      // Validate file size (2MB max)
      if (file.size > 2 * 1024 * 1024) {
        toast.error(t('users.management.messages.fileTooLarge'));
        return;
      }

      setSelectedFile(file);

      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogoPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveLogo = async (): Promise<void> => {
    if (firm?.id && logoUrl) {
      try {
        setUploading(true);
        await userService.deleteFirmLogo(firm.id);
        setLogoUrl('');
        setLogoPreview('');
        toast.success(t('users.management.messages.logoDeleted'));
      } catch (_) {
        toast.error(t('users.management.messages.logoDeleteFailed'));
      }
      setUploading(false);
    } else {
      setSelectedFile(null);
      setLogoPreview('');
    }
  };

  const triggerFileInput = (): void => {
    fileInputRef.current?.click();
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={firm ? t('users.management.modal.editFirm') : t('users.management.modal.addFirm')}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
            {t('users.management.modal.name')} *
          </label>
          <input
            type="text"
            value={name}
            onChange={handleNameChange}
            className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:ring-2 focus:ring-blue-500"
            required
          />
        </div>

        {/* Logo upload section - only show when editing */}
        {firm?.id && (
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              {t('users.management.modal.logo')}
            </label>
            <div className="flex items-center gap-4">
              {/* Logo preview */}
              <div className="w-20 h-20 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-lg flex items-center justify-center overflow-hidden bg-gray-50 dark:bg-gray-800">
                {logoPreview ? (
                  <img 
                    src={logoPreview} 
                    alt="Logo preview" 
                    className="max-w-full max-h-full object-contain"
                  />
                ) : (
                  <PhotoIcon className="w-8 h-8 text-gray-400" />
                )}
              </div>

              {/* Upload/Remove buttons */}
              <div className="flex flex-col gap-2">
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/jpeg,image/png,image/gif,image/webp,image/svg+xml"
                  onChange={handleFileSelect}
                  className="hidden"
                />
                <button
                  type="button"
                  onClick={triggerFileInput}
                  disabled={uploading}
                  className="px-3 py-1.5 text-sm bg-blue-500 text-white rounded hover:bg-blue-600 transition-colors disabled:opacity-50"
                >
                  {t('users.management.modal.selectLogo')}
                </button>
                {(logoPreview || selectedFile) && (
                  <button
                    type="button"
                    onClick={handleRemoveLogo}
                    disabled={uploading}
                    className="px-3 py-1.5 text-sm bg-red-500 text-white rounded hover:bg-red-600 transition-colors disabled:opacity-50 flex items-center gap-1"
                  >
                    <TrashIcon className="w-4 h-4" />
                    {t('users.management.modal.removeLogo')}
                  </button>
                )}
              </div>
            </div>
            <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
              {t('users.management.modal.logoHint')}
            </p>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-4">
          <button
            type="button"
            onClick={onClose}
            disabled={uploading}
            className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors disabled:opacity-50"
          >
            {t('users.management.modal.cancel')}
          </button>
          <button
            type="submit"
            disabled={uploading}
            className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors disabled:opacity-50"
          >
            {uploading ? t('users.management.modal.uploading') : t('users.management.modal.save')}
          </button>
        </div>
      </form>
    </Modal>
  );
};

export default FirmFormModal;

/**
 * MarketTrendsTab - Market Trends Analysis for Market Radar
 * Displays labor market trends from France Travail March├® du Travail API
 * - Hiring data by job type and sector
 * - Employment dynamics indicator
 * - Recruitment difficulties
 * - Proposed salaries by job
 * - AI dynamism indicator
 */

import { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import toast from 'react-hot-toast';
import {
  ArrowPathIcon,
  ChartBarIcon,
  ExclamationTriangleIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';
import Pagination from '../Pagination';
import {
  getTrends,
  getTrendsSummary,
  getTrendFilters,
  triggerTrendsCollection,
  triggerDynamicsCollection,
  MarketTrend,
  TrendsSummary,
  TrendFilters
} from '../../services/marketRadarService';
import { getStoredMetiers, Metier } from '../../services/romeService';
import { TREND_TYPE_LABELS, TREND_TYPE_ICONS, type TrendType } from './marketTrends.types';
import { parseMetadata } from './parseMetadata';
import TrendCard from './TrendCard';

export default function MarketTrendsTab({ className = '' }: { className?: string }) {
  const { t } = useTranslation();
  const [trends, setTrends] = useState<MarketTrend[]>([]);
  const [groupedTrends, setGroupedTrends] = useState<Record<string, MarketTrend[]> | null>(null);
  const [countsByType, setCountsByType] = useState<Record<string, number>>({});
  const [isGrouped, setIsGrouped] = useState(true);
  const [totalCount, setTotalCount] = useState(0);
  const [filters, setFilters] = useState<TrendFilters | null>(null);
  const [summary, setSummary] = useState<TrendsSummary | null>(null);
  const [metiers, setMetiers] = useState<Metier[]>([]);
  const [loading, setLoading] = useState(true);
  const [_collecting, _setCollecting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [_collectionResult, _setCollectionResult] = useState<{ stored: number; created: number; updated: number; duration: number } | null>(null);
  const [filtersLoading, setFiltersLoading] = useState(true);

  // Server-side filters - empty means all types
  const [typeFilter, setTypeFilter] = useState<string>('');
  const [regionFilter, setRegionFilter] = useState<string>('');
  const [romeFilter, setRomeFilter] = useState<string>('');

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const pageSize = 20;

  // Load filters and metiers on mount
  useEffect(() => {
    const loadInitialData = async () => {
      setFiltersLoading(true);
      try {
        // Load filters first
        const filtersResponse = await getTrendFilters();
        if (filtersResponse.filters) {
          setFilters(filtersResponse.filters);
        }

        // Then load summary and metiers in parallel
        const [summaryResponse, metiersData] = await Promise.all([
          getTrendsSummary(),
          getStoredMetiers()
        ]);
        setSummary(summaryResponse.summary);
        setMetiers(metiersData);
      } catch (_) {
        // Set empty filters as fallback
        setFilters({ types: [], regions: [], romeCodes: [] });
      } finally {
        setFiltersLoading(false);
      }
    };
    loadInitialData();
  }, []);

  // Load trends when filters or page change (wait for initial filters to load)
  useEffect(() => {
    // Don't load trends until filters are loaded to avoid race conditions
    if (filtersLoading) return;

    const loadTrends = async () => {
      setLoading(true);
      setError(null);
      try {
        const response = await getTrends({
          type: typeFilter || undefined,
          codeRome: romeFilter || undefined,
          regionCode: regionFilter || undefined,
          page: currentPage,
          pageSize
        });

        if (response.grouped) {
          // Grouped response (no type filter)
          setIsGrouped(true);
          setGroupedTrends(response.groupedTrends || {});
          setCountsByType(response.countsByType || {});
          setTrends([]);
          setTotalPages(1); // No pagination for grouped view
        } else {
          // Paginated response (with type filter)
          setIsGrouped(false);
          setGroupedTrends(null);
          setCountsByType({});
          setTrends(response.trends || []);
          if (response.pagination) {
            setTotalPages(response.pagination.totalPages);
          }
        }
        setTotalCount(response.totalCount);
      } catch (err) {
        setError(err instanceof Error ? err.message : t('marketRadar.errors.loadFailed'));
      } finally {
        setLoading(false);
      }
    };
    loadTrends();
  }, [filtersLoading, typeFilter, regionFilter, romeFilter, currentPage, t]);

  // Reset pagination when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [typeFilter, regionFilter, romeFilter]);

  // Create ROME labels map
  const romeLabelsMap = useMemo(() => {
    return metiers.reduce((acc, m) => {
      acc[m.CodeRome] = m.Libelle;
      return acc;
    }, {} as Record<string, string>);
  }, [metiers]);

  // Group trends by type for display
  // Use backend-grouped data when available, otherwise group locally
  const trendsByType = useMemo(() => {
    if (isGrouped && groupedTrends) {
      return groupedTrends;
    }
    // Fallback: group locally for paginated response
    const grouped: Record<string, MarketTrend[]> = {};
    trends.forEach(t => {
      if (!grouped[t.Type]) grouped[t.Type] = [];
      grouped[t.Type].push(t);
    });
    return grouped;
  }, [isGrouped, groupedTrends, trends]);

  // Handle collection (fire-and-forget)
  const handleCollect = async () => {
    setError(null);
    try {
      const result = await triggerTrendsCollection();
      toast.success(
        t('marketRadar.trends.collection.started') || 
        `Collecte lanc├®e en arri├¿re-plan. Dur├®e estim├®e : ${result.estimatedDuration}`,
        { duration: 5000 }
      );
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Erreur de lancement de la collecte';
      setError(errorMessage);
      toast.error(errorMessage);
    }
  };

  // TEMPORARY: Handle DYN_1 dynamics collection only
  const handleCollectDynamics = async () => {
    setError(null);
    try {
      const result = await triggerDynamicsCollection();
      toast.success(
        `Collecte DYN_1 (dynamique emploi) lanc├®e. Dur├®e estim├®e : ${result.estimatedDuration}`,
        { duration: 5000 }
      );
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Erreur de lancement de la collecte DYN_1';
      setError(errorMessage);
      toast.error(errorMessage);
    }
  };

  if (loading && trends.length === 0) {
    return (
      <div className={`flex items-center justify-center py-12 ${className}`}>
        <ArrowPathIcon className="h-8 w-8 text-indigo-600 dark:text-indigo-400 animate-spin" />
        <span className="ml-2 text-gray-600 dark:text-gray-400">{t('marketRadar.trends.loading')}</span>
      </div>
    );
  }

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Header with refresh and collect buttons */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-4">
        <div className="flex items-center justify-between">
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
            {t('marketRadar.trends.title')}
          </h2>

          <div className="flex items-center gap-2">
            <button
              onClick={async () => {
                setLoading(true);
                setError(null);
                try {
                  const [trendsResponse, summaryResponse, filtersResponse] = await Promise.all([
                    getTrends({ type: typeFilter || undefined, codeRome: romeFilter || undefined, regionCode: regionFilter || undefined, page: currentPage, pageSize }),
                    getTrendsSummary(),
                    getTrendFilters()
                  ]);
                  setTrends(trendsResponse.trends || []);
                  setTotalCount(trendsResponse.totalCount);
                  if (trendsResponse.pagination) {
                    setTotalPages(trendsResponse.pagination.totalPages);
                  }
                  setSummary(summaryResponse.summary);
                  setFilters(filtersResponse.filters);
                } catch (err) {
                  setError(err instanceof Error ? err.message : t('marketRadar.errors.loadFailed'));
                } finally {
                  setLoading(false);
                }
              }}
              disabled={loading}
              className="inline-flex items-center px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50 disabled:cursor-not-allowed"
              title={t('marketRadar.trends.refresh')}
            >
              <ArrowPathIcon className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
            </button>

            <button
              onClick={handleCollect}
              className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
              <ArrowPathIcon className="h-4 w-4 mr-2" />
              {t('marketRadar.trends.collection.button')}
            </button>

            {/* TEMPORARY: DYN_1 only collection button */}
            <button
              onClick={handleCollectDynamics}
              className="inline-flex items-center px-4 py-2 border border-orange-500 rounded-md shadow-sm text-sm font-medium text-orange-700 dark:text-orange-300 bg-orange-50 dark:bg-orange-900/20 hover:bg-orange-100 dark:hover:bg-orange-900/30 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500"
              title="TEMPORAIRE: Collecte uniquement DYN_1 (dynamique emploi)"
            >
              <SparklesIcon className="h-4 w-4 mr-2" />
              DYN_1 Only
            </button>
          </div>
        </div>

        {/* Error */}
        {error && (
          <div className="mt-4 p-4 bg-red-50 dark:bg-red-900/30 border border-red-200 dark:border-red-800 rounded-md">
            <div className="flex items-center">
              <ExclamationTriangleIcon className="h-5 w-5 text-red-500 dark:text-red-400" />
              <p className="ml-2 text-sm text-red-700 dark:text-red-400">{error}</p>
            </div>
          </div>
        )}
      </div>

      {/* Summary Stats */}
      {summary && (
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
          {summary.types.map((typeData) => {
            const { type, count, latestDate } = typeData;
            // Get aggregatedValue, isSumType, and valueCount with defaults
            const aggregatedValue = typeData.aggregatedValue ?? 0;
            const isSumType = typeData.isSumType ?? ['embauche', 'demandeur', 'demandeur_entrant', 'offre'].includes(type);
            const valueCount = typeData.valueCount ?? 0;  // Records with valid (non-null) values

            const Icon = TREND_TYPE_ICONS[type] || ChartBarIcon;
            // Card is "selected" if: this type is filtered OR no filter is active (all types shown)
            const isSelected = typeFilter === type || typeFilter === '';

            // Only show aggregated value if there are records with valid values
            const hasValidValues = valueCount > 0;

            // Format aggregated value based on type
            const formatAggregatedValue = (): string => {
              if (!hasValidValues) return '-';
              const val = aggregatedValue ?? 0;
              if (type === 'salaire') {
                return `${Math.round(val).toLocaleString('fr-FR')} Ôé¼`;
              }
              if (type === 'tension' || type === 'dynamique_emploi') {
                return val.toFixed(2);
              }
              // For sum types (embauche, demandeur, etc.)
              return Math.round(val).toLocaleString('fr-FR');
            };

            const aggregatedLabel = isSumType ? 'Total' : 'Moyenne';
            const formattedValue = formatAggregatedValue();

            return (
              <div
                key={type}
                className={`bg-white dark:bg-gray-800 rounded-lg shadow-sm p-4 cursor-pointer transition-colors ${
                  isSelected 
                    ? 'border-2 border-indigo-500 dark:border-indigo-400' 
                    : 'border border-gray-200 dark:border-gray-700 hover:border-indigo-300 dark:hover:border-indigo-600'
                }`}
                onClick={() => setTypeFilter(typeFilter === type ? '' : type as TrendType)}
              >
                <div className="flex items-center gap-2 mb-2">
                  <Icon className={`h-5 w-5 ${isSelected ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-400'}`} />
                  <span className="text-xs text-gray-500 dark:text-gray-400 truncate">
                    {TREND_TYPE_LABELS[type] || type}
                  </span>
                </div>
                <div className="text-2xl font-bold text-gray-900 dark:text-white">{count}</div>
                <div className="text-sm font-medium text-indigo-600 dark:text-indigo-400 mt-1">
                  {aggregatedLabel}: {formattedValue}
                </div>
                {latestDate && (
                  <div className="text-xs text-gray-400 dark:text-gray-500 mt-1">
                    Derni├¿re collecte: {latestDate}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Filters */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-4">
        {filtersLoading ? (
          <div className="flex items-center justify-center py-4">
            <ArrowPathIcon className="h-5 w-5 text-indigo-600 dark:text-indigo-400 animate-spin mr-2" />
            <span className="text-sm text-gray-500 dark:text-gray-400">{t('common.loading')}</span>
          </div>
        ) : (
        <div className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Type {filters?.types?.length ? `(${filters.types.length})` : ''}
              </label>
              <select
                value={typeFilter}
                onChange={(e) => setTypeFilter(e.target.value)}
                className="w-full rounded-md border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-sm"
              >
                <option value="">{t('marketRadar.trends.filters.allTypes')}</option>
                {(filters?.types || []).map(type => (
                  <option key={type} value={type}>{TREND_TYPE_LABELS[type] || type}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                R├®gion {filters?.regions?.length ? `(${filters.regions.length})` : ''}
              </label>
              <select
                value={regionFilter}
                onChange={(e) => setRegionFilter(e.target.value)}
                className="w-full rounded-md border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-sm"
              >
                <option value="">{t('marketRadar.trends.filters.allRegions')}</option>
                {(filters?.regions || []).map(r => (
                  <option key={r.code} value={r.code}>{r.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                M├®tier {filters?.romeCodes?.length ? `(${filters.romeCodes.length})` : ''}
              </label>
              <select
                value={romeFilter}
                onChange={(e) => setRomeFilter(e.target.value)}
                className="w-full rounded-md border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-sm"
              >
                <option value="">{t('marketRadar.facts.filters.allMetiers')}</option>
                {(filters?.romeCodes || []).map(code => (
                  <option key={code} value={code}>{romeLabelsMap[code] || code}</option>
                ))}
              </select>
            </div>
          </div>
          {(typeFilter || regionFilter || romeFilter) && (
            <div className="flex justify-end">
              <button
                onClick={() => { setTypeFilter(''); setRegionFilter(''); setRomeFilter(''); }}
                className="inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-lg bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
              >
                {t('common.resetFilters')}
              </button>
            </div>
          )}
        </div>
        )}
      </div>

      {/* Trends Display */}
      {(trends.length === 0 && Object.keys(trendsByType).length === 0) ? (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-12 text-center">
          <ChartBarIcon className="h-12 w-12 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">{t('marketRadar.trends.noData')}</h3>
          <p className="text-gray-500 dark:text-gray-400">
            {t('marketRadar.facts.collection.startCollection')}
          </p>
        </div>
      ) : (
        <div className="space-y-6">
          {/* Pagination - only show when filtered by type (not grouped) */}
          {!isGrouped && (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={setCurrentPage}
              loading={loading}
              itemName={t('marketRadar.trends.results')}
            />
          )}

          {/* Display trends grouped by type with proper headers */}
          {Object.entries(trendsByType).map(([type, typeTrends]) => {
            const Icon = TREND_TYPE_ICONS[type] || ChartBarIcon;
            // Get total count for this type from countsByType (backend) or summary
            const typeTotal = countsByType[type] || summary?.types?.find(t => t.type === type)?.count || typeTrends.length;
            return (
              <div key={type} className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                <div className="px-6 py-4 bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-semibold text-gray-900 dark:text-white flex items-center gap-2">
                    <Icon className="h-5 w-5 text-indigo-600 dark:text-indigo-400" />
                    {TREND_TYPE_LABELS[type] || type}
                    <span className="text-sm font-normal text-gray-500 dark:text-gray-400">
                      ({typeTrends.length} affich├®s / {typeTotal} total)
                    </span>
                  </h3>
                </div>
                <div className="p-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                    {typeTrends.map((trend) => {
                      const parsed = parseMetadata(trend.Metadata || null, type, trend.Value);
                      return (
                        <TrendCard
                          key={trend.id}
                          trend={trend}
                          type={type}
                          parsed={parsed}
                          romeLabel={trend.CodeRome ? romeLabelsMap[trend.CodeRome] : undefined}
                        />
                      );
                    })}
                  </div>
                </div>
              </div>
            );
          })}

          {/* Bottom Pagination - only show when filtered by type (not grouped) */}
          {!isGrouped && (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={setCurrentPage}
              loading={loading}
              itemName={t('marketRadar.trends.results')}
            />
          )}
        </div>
      )}
    </div>
  );
}

/**
 * TrendMetadataDisplay - Reusable component for displaying trend metadata
 * Used in both MarketTrendsTab (cards) and FranceMapTab (hover tooltips)
 */

import { useMemo } from 'react';

// Types for metadata parsing
interface PeriodeData {
  libPeriode?: string;
  libActivite?: string;
  libNomenclature?: string;
  codeNomenclature?: string;
  libTerritoire?: string;
  codeTerritoire?: string;
  codePeriode?: string;
  datMaj?: string;
  valeurPrincipaleNombre?: number;
  valeurPrincipaleMontant?: number;
  valeurPrincipaleTaux?: number;
  valeurPrincipaleDecimale?: number;
  valeurSecondairePourcentage?: number;
  valeurSecondarieNombre?: number;
  valeurSecondaireMontant?: number;
  listeValeurParCaract?: CaracteristiqueData[];
  codeTypePeriode?: string;
  codeTypeActivite?: string;
  codeTypeTerritoire?: string;
}

interface CaracteristiqueData {
  codeCaract?: string;
  libCaract?: string;
  codeTypeCaract?: string;
  nombre?: number;
  montant?: number;
  taux?: number;
  pourcentage?: number;
}

interface SalairePeriodeData {
  codeActivite?: string;
  libActivite?: string;
  libPeriode?: string;
  salaireValeurMontant?: Array<{
    codeNomenclature?: string;
    valeurPrincipaleMontant?: number;
  }>;
}

interface SalaireActivite {
  codeActivite: string;
  libActivite: string;
  periode?: string;
  salaireDebutant?: number;
  salaireExperimente?: number;
  salaireMoyen?: number;
}

interface TensionIndicator {
  code: string;
  label: string;
  value: number;
  decimal: number;
  color: string;
}

interface AgeBreakdown {
  label: string;
  value: number;
}

interface EmbaucheDetails {
  genre?: { hommes: number; femmes: number; hommesNombre?: number; femmesNombre?: number };
  contrats?: { cdi: number; cdd: number; autres: number };
  qualification?: { cadres: number; techniciens: number; employes: number; ouvriers?: number };
  experience?: { debutant: number; experimente: number };
  age?: { jeunes: number; adultes: number; seniors: number };
  ageDetaille?: AgeBreakdown[];
  formation?: { sansQualif: number; bac: number; bacPlus: number };
  formationDetaille?: AgeBreakdown[];
  periode?: string;
  territoire?: string;
  pourcentageTotal?: number;
}

export interface ParsedMetadata {
  indicateur?: string;
  codeIndicateur?: string;
  territoire?: string;
  activite?: string;
  periode?: string;
  nomenclature?: string;
  valeurPrincipale?: number;
  valeurPrincipaleType?: 'nombre' | 'montant' | 'taux';
  valeurSecondaire?: number;
  valeurSecondarieType?: 'pourcentage' | 'nombre' | 'montant';
  caracteristiques?: Array<{
    label: string;
    nombre?: number;
    montant?: number;
    taux?: number;
    pourcentage?: number;
  }>;
  typeSpecific?: {
    tensionLevel?: string;
    tensionColor?: string;
    tensionIndicators?: TensionIndicator[];
    salairesParActivite?: SalaireActivite[];
    salaireMin?: number;
    salaireMax?: number;
    salaireMedian?: number;
    totalCount?: number;
    evolutionPercent?: number;
    embaucheDetails?: EmbaucheDetails;
    tendance?: 'hausse' | 'baisse' | 'stable';
    tendanceLabel?: string;
    tendanceDescription?: string;
    dynamiqueDetails?: {
      territoire?: string;
      codeTerritoire?: string;
      activite?: string;
      periode?: string;
      codePeriode?: string;
      dateMaj?: string;
      dateMajGlobale?: string;
    };
  };
}

/**
 * Parse metadata from trend data
 */
export function parseMetadata(metadata: Record<string, unknown> | string | null, type: string, trendValue?: number | string | null): ParsedMetadata | null {
  let parsedMeta: Record<string, unknown> = {};
  if (metadata) {
    if (typeof metadata === 'string') {
      try {
        parsedMeta = JSON.parse(metadata);
      } catch {
        // Invalid JSON
      }
    } else {
      parsedMeta = metadata;
    }
  }

  const result: ParsedMetadata = {
    indicateur: parsedMeta.libIndicateur as string,
    codeIndicateur: parsedMeta.codeIndicateur as string,
    territoire: parsedMeta.libTerritoire as string,
    typeSpecific: {}
  };

  const periodes = parsedMeta.listeValeursParPeriode as PeriodeData[] | undefined;
  if (periodes?.length) {
    const p = periodes[0];
    result.periode = p.libPeriode;
    result.activite = p.libActivite;
    result.nomenclature = p.libNomenclature;

    // Metadata value is the primary source of truth
    if (p.valeurPrincipaleNombre !== undefined) {
      result.valeurPrincipale = p.valeurPrincipaleNombre;
      result.valeurPrincipaleType = 'nombre';
    } else if (p.valeurPrincipaleMontant !== undefined) {
      result.valeurPrincipale = p.valeurPrincipaleMontant;
      result.valeurPrincipaleType = 'montant';
    } else if (p.valeurPrincipaleTaux !== undefined) {
      result.valeurPrincipale = p.valeurPrincipaleTaux;
      result.valeurPrincipaleType = 'taux';
    }

    // Secondary value from metadata
    if (p.valeurSecondairePourcentage !== undefined) {
      result.valeurSecondaire = p.valeurSecondairePourcentage;
      result.valeurSecondarieType = 'pourcentage';
    } else if (p.valeurSecondarieNombre !== undefined) {
      result.valeurSecondaire = p.valeurSecondarieNombre;
      result.valeurSecondarieType = 'nombre';
    } else if (p.valeurSecondaireMontant !== undefined) {
      result.valeurSecondaire = p.valeurSecondaireMontant;
      result.valeurSecondarieType = 'montant';
    }

    // Characteristics from metadata
    if (p.listeValeurParCaract?.length) {
      result.caracteristiques = p.listeValeurParCaract.map((c: CaracteristiqueData) => ({
        label: c.libCaract || '',
        nombre: c.nombre,
        montant: c.montant,
        taux: c.taux,
        pourcentage: c.pourcentage
      }));
    }
  }

  // Fallback to trendValue only if metadata didn't provide a value
  if (result.valeurPrincipale === undefined && trendValue !== undefined && trendValue !== null) {
    result.valeurPrincipale = typeof trendValue === 'string' ? parseFloat(trendValue) : trendValue;
    result.valeurPrincipaleType = 'nombre';
  }

  // Type-specific parsing
  switch (type) {
    case 'tension':
      const tensionIndicators: TensionIndicator[] = [];
      let mainTensionValue: number | undefined;

      if (periodes?.length) {
        periodes.forEach((p: PeriodeData) => {
          const code = p.codeNomenclature;
          const label = p.libNomenclature;
          const value = p.valeurPrincipaleNombre;
          const decimal = p.valeurPrincipaleDecimale;

          if (code && label && value !== undefined) {
            let color = 'gray';
            if (value >= 4) color = 'red';
            else if (value >= 3) color = 'orange';
            else if (value >= 2) color = 'yellow';
            else if (value >= 1) color = 'green';

            tensionIndicators.push({ code, label, value, decimal: decimal ?? 0, color });

            if (code === 'PERSPECTIVE') {
              mainTensionValue = value;
            }
          }
        });
      }

      // Metadata value (from listeValeursParPeriode) is primary
      // mainTensionValue from PERSPECTIVE indicator is secondary
      // trendValue is fallback (already applied to result.valeurPrincipale if metadata was empty)
      const tensionValue = result.valeurPrincipale ?? mainTensionValue;

      if (tensionValue !== undefined && !isNaN(tensionValue)) {
        result.valeurPrincipale = tensionValue;
        if (tensionValue >= 4) {
          result.typeSpecific!.tensionLevel = 'Tr├¿s forte tension';
          result.typeSpecific!.tensionColor = 'red';
        } else if (tensionValue >= 3) {
          result.typeSpecific!.tensionLevel = 'Forte tension';
          result.typeSpecific!.tensionColor = 'orange';
        } else if (tensionValue >= 2) {
          result.typeSpecific!.tensionLevel = 'Tension mod├®r├®e';
          result.typeSpecific!.tensionColor = 'yellow';
        } else if (tensionValue >= 1) {
          result.typeSpecific!.tensionLevel = 'Tension faible';
          result.typeSpecific!.tensionColor = 'green';
        } else {
          result.typeSpecific!.tensionLevel = 'Pas de tension';
          result.typeSpecific!.tensionColor = 'gray';
        }
      }

      if (tensionIndicators.length > 0) {
        result.typeSpecific!.tensionIndicators = tensionIndicators;
      }
      break;

    case 'salaire':
      const salairePeriodes = parsedMeta.valeursParPeriode as SalairePeriodeData[] | undefined;
      if (salairePeriodes?.length) {
        const salairesParActivite: SalaireActivite[] = [];
        const allSalaires: number[] = [];

        salairePeriodes.forEach(sp => {
          if (sp.libActivite && sp.salaireValeurMontant?.length) {
            const activite: SalaireActivite = {
              codeActivite: sp.codeActivite || '',
              libActivite: sp.libActivite,
              periode: sp.libPeriode
            };

            sp.salaireValeurMontant.forEach(sv => {
              if (sv.valeurPrincipaleMontant !== undefined) {
                allSalaires.push(sv.valeurPrincipaleMontant);
                switch (sv.codeNomenclature) {
                  case 'SAL1': activite.salaireDebutant = sv.valeurPrincipaleMontant; break;
                  case 'SAL2': activite.salaireExperimente = sv.valeurPrincipaleMontant; break;
                  case 'SAL3': activite.salaireMoyen = sv.valeurPrincipaleMontant; break;
                }
              }
            });

            salairesParActivite.push(activite);
          }
        });

        if (salairesParActivite.length > 0) {
          result.typeSpecific!.salairesParActivite = salairesParActivite;
        }

        if (allSalaires.length > 0) {
          allSalaires.sort((a, b) => a - b);
          result.typeSpecific!.salaireMin = allSalaires[0];
          result.typeSpecific!.salaireMax = allSalaires[allSalaires.length - 1];
          result.typeSpecific!.salaireMedian = allSalaires[Math.floor(allSalaires.length / 2)];
        }
      }
      break;

    case 'dynamique_emploi':
      if (periodes?.length) {
        const p = periodes[0];
        result.typeSpecific!.dynamiqueDetails = {
          territoire: p.libTerritoire as string,
          codeTerritoire: p.codeTerritoire as string,
          activite: p.libActivite as string,
          periode: p.libPeriode as string,
          codePeriode: p.codePeriode as string,
          dateMaj: p.datMaj as string
        };
      }

      if (parsedMeta.datMaj) {
        if (!result.typeSpecific!.dynamiqueDetails) {
          result.typeSpecific!.dynamiqueDetails = {};
        }
        result.typeSpecific!.dynamiqueDetails.dateMajGlobale = parsedMeta.datMaj as string;
      }

      // valeurPrincipale is set from metadata (primary) or trendValue (fallback)
      const dynamiqueValue = result.valeurPrincipale;

      if (dynamiqueValue !== undefined && !isNaN(dynamiqueValue)) {
        if (dynamiqueValue >= 1) {
          result.typeSpecific!.tendance = 'hausse';
          result.typeSpecific!.tendanceLabel = 'Dynamique positive';
          result.typeSpecific!.tendanceDescription = 'Le march├® de l\'emploi est en croissance';
        } else if (dynamiqueValue <= 0) {
          result.typeSpecific!.tendance = 'baisse';
          result.typeSpecific!.tendanceLabel = 'Dynamique n├®gative';
          result.typeSpecific!.tendanceDescription = 'Le march├® de l\'emploi est en recul';
        } else {
          result.typeSpecific!.tendance = 'stable';
          result.typeSpecific!.tendanceLabel = 'Dynamique stable';
          result.typeSpecific!.tendanceDescription = 'Le march├® de l\'emploi est stable';
        }
      }
      break;

    case 'embauche':
    case 'offre':
    case 'demandeur':
    case 'demandeur_entrant':
      // valeurPrincipale is set from metadata (primary) or trendValue (fallback)
      result.typeSpecific!.totalCount = result.valeurPrincipale;
      if (result.valeurSecondaire !== undefined && result.valeurSecondarieType === 'pourcentage') {
        result.typeSpecific!.evolutionPercent = result.valeurSecondaire;
      }

      if (periodes?.length) {
        const firstPeriode = periodes[0];
        const caracts = firstPeriode.listeValeurParCaract;

        if (caracts?.length) {
          const embaucheDetails: EmbaucheDetails = {
            periode: firstPeriode.libPeriode,
            territoire: firstPeriode.libTerritoire
          };

          const hommes = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'H');
          const femmes = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'F');
          if (hommes || femmes) {
            embaucheDetails.genre = {
              hommes: hommes?.pourcentage || 0,
              femmes: femmes?.pourcentage || 0,
              hommesNombre: hommes?.nombre,
              femmesNombre: femmes?.nombre
            };
          }

          const cdi = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CDI');
          const cdd1 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CDD1');
          const cdd2 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CDD2');
          const cdd3 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CDD3');
          const autres = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'AUTR');
          if (cdi || cdd1 || cdd2 || cdd3 || autres) {
            embaucheDetails.contrats = {
              cdi: cdi?.pourcentage || 0,
              cdd: (cdd1?.pourcentage || 0) + (cdd2?.pourcentage || 0) + (cdd3?.pourcentage || 0),
              autres: autres?.pourcentage || 0
            };
          }

          const cadres = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CADRE');
          const tech = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'TECH');
          const eq = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'EQ');
          const enq = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'ENQ');
          const oq = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'OQ');
          const onq = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'ONQ');
          if (cadres || tech || eq || enq || oq || onq) {
            embaucheDetails.qualification = {
              cadres: cadres?.pourcentage || 0,
              techniciens: tech?.pourcentage || 0,
              employes: (eq?.pourcentage || 0) + (enq?.pourcentage || 0),
              ouvriers: (oq?.pourcentage || 0) + (onq?.pourcentage || 0)
            };
          }

          const exp2 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'EXP2');
          const exp3 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'EXP3');
          const exp4 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'EXP4');
          const exp5 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'EXP5');
          if (exp2 || exp3 || exp4 || exp5) {
            embaucheDetails.experience = {
              debutant: (exp2?.pourcentage || 0) + (exp3?.pourcentage || 0),
              experimente: (exp4?.pourcentage || 0) + (exp5?.pourcentage || 0)
            };
          }

          const age1 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'AGE1');
          const age2 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'AGE2');
          const age3 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'AGE3');
          if (age1 || age2 || age3) {
            embaucheDetails.age = {
              jeunes: age1?.pourcentage || 0,
              adultes: age2?.pourcentage || 0,
              seniors: age3?.pourcentage || 0
            };
          }

          // Tranches d'├óge d├®taill├®es
          const ageDetails: AgeBreakdown[] = [];
          const ageMapping: Record<string, string> = {
            'AGE1524': '15-24 ans',
            'AGE2549': '25-49 ans',
            'AGE50P': '50 ans et +',
            'AGE2534': '25-34 ans',
            'AGE3549': '35-49 ans',
            'AGE1': '< 25 ans',
            'AGE2': '25-49 ans',
            'AGE3': '50 ans et +'
          };
          Object.entries(ageMapping).forEach(([code, label]) => {
            const ageCaract = caracts.find((c: CaracteristiqueData) => c.codeCaract === code);
            if (ageCaract?.pourcentage !== undefined) {
              ageDetails.push({ label, value: ageCaract.pourcentage });
            }
          });
          if (ageDetails.length > 0) {
            embaucheDetails.ageDetaille = ageDetails;
          }

          const sans = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'SANS');
          const capbep = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'CAPBEP');
          const bac = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'BAC');
          const bac2 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'BAC2');
          const bac3 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'BAC3EP');
          const bac5 = caracts.find((c: CaracteristiqueData) => c.codeCaract === 'BAC5EP');
          if (sans || capbep || bac || bac2 || bac3 || bac5) {
            embaucheDetails.formation = {
              sansQualif: (sans?.pourcentage || 0) + (capbep?.pourcentage || 0),
              bac: bac?.pourcentage || 0,
              bacPlus: (bac2?.pourcentage || 0) + (bac3?.pourcentage || 0) + (bac5?.pourcentage || 0)
            };

            // Formation d├®taill├®e
            const formationDetails: AgeBreakdown[] = [];
            const formMapping: Record<string, string> = {
              'SANS': 'Sans dipl├┤me',
              'CAPBEP': 'CAP/BEP',
              'BAC': 'Bac',
              'BAC2': 'Bac+2',
              'BAC3EP': 'Bac+3/4',
              'BAC5EP': 'Bac+5 et +'
            };
            Object.entries(formMapping).forEach(([code, label]) => {
              const formCaract = caracts.find((c: CaracteristiqueData) => c.codeCaract === code);
              if (formCaract?.pourcentage !== undefined) {
                formationDetails.push({ label, value: formCaract.pourcentage });
              }
            });
            if (formationDetails.length > 0) {
              embaucheDetails.formationDetaille = formationDetails;
            }
          }

          // Pourcentage du total (valeur secondaire)
          if (firstPeriode.valeurSecondairePourcentage !== undefined) {
            embaucheDetails.pourcentageTotal = firstPeriode.valeurSecondairePourcentage;
          }

          result.typeSpecific!.embaucheDetails = embaucheDetails;
        }
      }
      break;
  }

  return result;
}

// Progress bar component for percentages
function ProgressBar({ value, color = 'indigo', label }: { value: number; color?: string; label?: string }) {
  const colorClasses: Record<string, string> = {
    indigo: 'bg-indigo-500',
    green: 'bg-green-500',
    red: 'bg-red-500',
    orange: 'bg-orange-500',
    yellow: 'bg-yellow-500',
    blue: 'bg-blue-500',
    purple: 'bg-purple-500',
    teal: 'bg-teal-500'
  };

  return (
    <div className="flex items-center gap-2">
      {label && <span className="text-xs text-gray-500 dark:text-gray-400 w-16 truncate">{label}</span>}
      <div className="flex-1 h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
        <div 
          className={`h-full ${colorClasses[color] || colorClasses.indigo} rounded-full transition-all`}
          style={{ width: `${Math.min(100, Math.max(0, value))}%` }}
        />
      </div>
      <span className="text-xs font-medium text-gray-700 dark:text-gray-300 w-10 text-right">{value.toFixed(0)}%</span>
    </div>
  );
}

