      {/* Detailed breakdowns */}
      {parsed.typeSpecific?.embaucheDetails?.contrats && (
        <div className="space-y-1 mt-2">
          <div className="text-xs font-medium text-gray-700 dark:text-gray-300">Contrats</div>
