      )}

      {parsed.typeSpecific?.embaucheDetails?.qualification && (
        <div className="space-y-1 mt-2">
          <div className="text-xs font-medium text-gray-700 dark:text-gray-300">Qualification</div>
          <ProgressBar value={parsed.typeSpecific.embaucheDetails.qualification.cadres} color="purple" label="Cadres" />
          <ProgressBar value={parsed.typeSpecific.embaucheDetails.qualification.techniciens} color="blue" label="Tech." />
        </div>
      )}

      {parsed.typeSpecific?.embaucheDetails?.experience && (
        <div className="space-y-1 mt-2">
          <div className="text-xs font-medium text-gray-700 dark:text-gray-300">Exp├®rience</div>
          <ProgressBar value={parsed.typeSpecific.embaucheDetails.experience.debutant} color="teal" label="D├®butant" />
          <ProgressBar value={parsed.typeSpecific.embaucheDetails.experience.experimente} color="indigo" label="Exp├®riment├®" />
        </div>
      )}
    </div>
  );
}

/**
 * Authentication Context
 * TypeScript version with full type safety
 */

import { createContext, useContext, useState, useCallback, useEffect, ReactNode } from 'react';
import { authService, User, RegisterData, RegisterResponse, SignInResponse } from '../services/authService';
import { setSessionExpiredHandler, resetSessionState } from '../utils/apiInterceptor';
import toast from 'react-hot-toast';
import logger from '../utils/logger.frontend';

// Prevent duplicate auth calls in StrictMode
let authCheckInProgress = false;

// ============================================
// TYPES
// ============================================

interface AuthContextType {
  user: User | null;
  loading: boolean;
  error: string | null;
  signIn: (email: string, password: string) => Promise<User | SignInResponse>;
  signOut: () => Promise<void>;
  register: (userData: RegisterData) => Promise<RegisterResponse>;
  isAuthenticated: boolean;
}

interface AuthProviderProps {
  children: ReactNode;
}

// ============================================
// CONTEXT
// ============================================

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

// ============================================
// PROVIDER
// ============================================

export const AuthProvider = ({ children }: AuthProviderProps): JSX.Element => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState<boolean>(true); // Start with loading true
  const [error, setError] = useState<string | null>(null);
  const [initialized, setInitialized] = useState<boolean>(false);

  // Fetch current user from server on mount (session restored via httpOnly cookies)
  useEffect(() => {
    const fetchCurrentUser = async () => {
      // Prevent duplicate calls in React StrictMode
      if (authCheckInProgress) {
        return;
      }
      authCheckInProgress = true;

      // Skip fetching user if we're on the signin page with expired flag
      // This prevents infinite loops when session has expired
      if (window.location.pathname === '/signin' && window.location.search.includes('expired=true')) {
        // Reset session state to clear isSessionExpiring flag and stale CSRF token
        // This ensures the first login attempt after expiration will work
        resetSessionState();
        setUser(null);
        authService.setCurrentUser(null);
        setLoading(false);
        setInitialized(true);
        return;
      }

      try {
        // First try to get user with current token
        const response = await fetch('/api/auth/me', {
          method: 'GET',
          credentials: 'include'
        });
        
        if (response.ok) {
          const data = await response.json();
          setUser(data.user);
          authService.setCurrentUser(data.user);
        } else if (response.status === 401 || response.status === 403) {
          // Check if it's a JWT error that shouldn't trigger refresh
          let errorData: { error?: string; message?: string; code?: string } = {};
          try {
            errorData = await response.clone().json();
          } catch {
            // Ignore JSON parse errors
          }
          
          const errorMessage = (errorData.error || errorData.message || '').toLowerCase();
          const isJwtError = ['kid_malformed', 'jwt malformed', 'jwt expired', 'invalid token', 'invalid signature']
            .some(pattern => errorMessage.includes(pattern.toLowerCase()));
          
          // If it's a JWT error, don't try to refresh - just clear state
          if (isJwtError) {
            logger.warn('JWT error detected during session restore, clearing state:', errorMessage);
            resetSessionState();
            setUser(null);
            authService.setCurrentUser(null);
          } else {
            // Token might be expired, try to refresh
            const refreshResponse = await fetch('/api/auth/refresh', {
              method: 'POST',
              credentials: 'include',
              headers: { 'Content-Type': 'application/json' }
            });
            
            if (refreshResponse.ok) {
              // Retry getting user after refresh
              const retryResponse = await fetch('/api/auth/me', {
                method: 'GET',
                credentials: 'include'
              });
              
              if (retryResponse.ok) {
                const data = await retryResponse.json();
                setUser(data.user);
                authService.setCurrentUser(data.user);
              } else {
                setUser(null);
                authService.setCurrentUser(null);
              }
            } else {
              // Refresh failed - user is not authenticated
              setUser(null);
              authService.setCurrentUser(null);
            }
          }
        } else {
          setUser(null);
          authService.setCurrentUser(null);
        }
      } catch (err) {
        logger.error('Failed to fetch current user:', err);
        resetSessionState();
        setUser(null);
        authService.setCurrentUser(null);
      } finally {
        setLoading(false);
        authCheckInProgress = false;
        setInitialized(true);
      }
    };

    fetchCurrentUser();
  }, []);

  const signIn = useCallback(async (email: string, password: string): Promise<User | SignInResponse> => {
    try {
      setLoading(true);
      setError(null);
      const result = await authService.signIn(email, password);
      
      // Check if 2FA is required
      if ('requires2FA' in result && result.requires2FA) {
        return result as SignInResponse;
      }
      
      // Normal login - set user
      setUser(result as User);
      return result;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'An error occurred';
      setError(errorMessage);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const register = useCallback(async (userData: RegisterData): Promise<RegisterResponse> => {
    try {
      setLoading(true);
      setError(null);
      const result = await authService.register(userData);
      toast.success(result.message, { duration: 6000 });
      return result;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'An error occurred';
      setError(errorMessage);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const signOut = useCallback(async (): Promise<void> => {
    try {
      await authService.signOut();
      setUser(null);
    } catch (err) {
      logger.error('Sign out error:', err);
    }
  }, []);

  const handleSessionExpired = useCallback((): void => {
    logger.warn('[AuthContext] Session expired, cleaning up and redirecting');
    
    // Set user to null first to trigger component unmounts
    setUser(null);
    
    // Clean up TinyMCE editors to prevent "isUnsaved" errors
    try {
      const tinymce = (window as unknown as { tinymce?: { editors?: Array<{ remove: () => void }> } }).tinymce;
      if (tinymce?.editors) {
        // Remove all TinyMCE editors before redirect
        [...tinymce.editors].forEach(editor => {
          try {
            editor.remove();
          } catch {
            // Ignore errors during cleanup
          }
        });
      }
    } catch {
      // Ignore TinyMCE cleanup errors
    }
    
    // Sign out (clears tokens)
    authService.signOut();
    
    // Small delay to allow React to process state changes before redirect
    setTimeout(() => {
      window.location.replace('/signin?expired=true');
    }, 50);
  }, []);

  useEffect(() => {
    setSessionExpiredHandler(handleSessionExpired);
    
    return () => {
      setSessionExpiredHandler(null as unknown as () => void);
    };
  }, [handleSessionExpired]);

  // Handle both 'status' (backend) and 'Status' (legacy) property names
  const userStatus = user?.status || user?.Status || '';
  
  const value: AuthContextType = {
    user,
    loading,
    error,
    signIn,
    signOut,
    register,
    isAuthenticated: !!user && (userStatus === 'Active' || userStatus === 'active')
  };

  // Don't render children until we've checked authentication status
  if (!initialized) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export default AuthContext;

/**
 * ChatbotContext - Manages chatbot enabled state globally
 * Allows dynamic updates without page refresh
 */

import { createContext, useContext, useState, useCallback, ReactNode } from 'react';

interface ChatbotContextType {
  chatbotEnabled: boolean;
  setChatbotEnabled: (enabled: boolean) => void;
  refreshChatbotStatus: () => void;
}

const ChatbotContext = createContext<ChatbotContextType | undefined>(undefined);

interface ChatbotProviderProps {
  children: ReactNode;
}

export const ChatbotProvider = ({ children }: ChatbotProviderProps): JSX.Element => {
  const [chatbotEnabled, setChatbotEnabled] = useState<boolean>(true);
  const [, setRefreshKey] = useState<number>(0);

  const refreshChatbotStatus = useCallback(() => {
    // Increment key to trigger re-fetch in ChatBot component
    setRefreshKey(prev => prev + 1);
  }, []);

  return (
    <ChatbotContext.Provider value={{ chatbotEnabled, setChatbotEnabled, refreshChatbotStatus }}>
      {children}
    </ChatbotContext.Provider>
  );
};

export const useChatbot = (): ChatbotContextType => {
  const context = useContext(ChatbotContext);
  if (context === undefined) {
    throw new Error('useChatbot must be used within a ChatbotProvider');
  }
  return context;
};

export default ChatbotContext;

/**
 * Resume Context
 * TypeScript version with full type safety
 */

import { createContext, useContext, useState, useCallback, ReactNode } from 'react';
import { extractResumeText } from '../utils/resumeProcessing';
import { useAuth } from './AuthContext';
import { createAuthOptionsWithCsrf, fetchWithAuth } from '../utils/apiInterceptor';
import logger from '../utils/logger.frontend';
import { showCaughtError, getUserFriendlyMessage } from '../components/ErrorToast';

// Import centralized types
import { Resume } from '../types/entities';

// Re-export Resume type for backward compatibility
export type { Resume };

// Candidate info for GDPR
export interface CandidateInfo {
  profileType: 'employee' | 'external';
  candidateName: string;
  candidateEmail: string;
  firmId?: string;
}

// ============================================
// TYPES
// ============================================

export type ProcessingStep = 'upload' | 'extract' | 'analyze' | 'improving' | 'analyzing' | null;

interface ResumeContextType {
  resumes: Resume[];
  currentResume: Resume | null;
  loading: boolean;
  processingStep: ProcessingStep;
  processingError: string | null;
  deleting: boolean;
  setProcessingError: (error: string | null) => void;
  setCurrentResume: (resume: Resume | null) => void;
  setResumes: React.Dispatch<React.SetStateAction<Resume[]>>;
  uploadResume: (file: File, candidateInfo?: CandidateInfo) => Promise<Resume | undefined>;
  improveCurrentResume: () => Promise<Resume>;
  updateResumeAnalysis: (resumeId: string, analysisData: Partial<Resume>) => Promise<Resume>;
  fetchResumes: () => Promise<void>;
  updateImprovedContent: (resumeId: string, content: string) => Promise<{ success: boolean; currentVersion?: number }>;
  updateOriginalContent: (resumeId: string, content: string) => Promise<{ success: boolean }>;
  deleteResume: (resumeId: string) => Promise<void>;
}

interface ResumeProviderProps {
  children: ReactNode;
}

// ============================================
// CONTEXT
// ============================================

const ResumeContext = createContext<ResumeContextType | undefined>(undefined);

export const useResume = (): ResumeContextType => {
  const context = useContext(ResumeContext);
  if (!context) {
    throw new Error('useResume must be used within a ResumeProvider');
  }
  return context;
};

// ============================================
// PROVIDER
// ============================================

export const ResumeProvider = ({ children }: ResumeProviderProps): JSX.Element => {
  const { user } = useAuth();
  const [resumes, setResumes] = useState<Resume[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [currentResume, setCurrentResume] = useState<Resume | null>(null);
  const [processingStep, setProcessingStep] = useState<ProcessingStep>(null);
  const [processingError, setProcessingError] = useState<string | null>(null);
  const [abortController, setAbortController] = useState<AbortController>(new AbortController());
  const [deleting, setDeleting] = useState<boolean>(false);

  const updateResumeAnalysis = useCallback(async (resumeId: string, analysisData: Partial<Resume>): Promise<Resume> => {
    if (abortController.signal.aborted) throw new Error('Operation aborted');
    
    try {
      const updateOptions = await createAuthOptionsWithCsrf({
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(analysisData)
      });
      
      const response = await fetchWithAuth(`/api/resumes/${resumeId}`, updateOptions);
      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Failed to update resume' }));
        throw new Error(errorData.error || 'Failed to update resume');
      }
      
      const updatedResume = await response.json();

      if (!abortController.signal.aborted) {
        setResumes(prev =>
          prev.map(resume =>
            resume.id === resumeId ? updatedResume : resume
          )
        );
        setCurrentResume(updatedResume);
      }

      return updatedResume;
    } catch (error) {
      if (!abortController.signal.aborted) {
        logger.error('Error updating resume analysis:', error);
      }
      throw error;
    }
  }, [abortController]);

  const fetchResumes = useCallback(async (): Promise<void> => {
    const controller = new AbortController();
    setAbortController(controller);

    try {
      setLoading(true);
      const fetchOptions = await createAuthOptionsWithCsrf({ method: 'GET' });
      const response = await fetchWithAuth('/api/resumes', fetchOptions);
      if (!response.ok) {
        throw new Error('Failed to fetch resumes');
      }
      const data = await response.json();
      const fetchedResumes = data.resumes || data;
      
      if (!controller.signal.aborted) {
        setResumes(fetchedResumes);
      }
    } catch (error) {
      if (!controller.signal.aborted) {
        // Don't log session expiration errors - user will be redirected
        const errorMessage = error instanceof Error ? error.message : '';
        if (!errorMessage.includes('Session expired')) {
          logger.error('Error fetching resumes:', error);
        }
      }
    } finally {
      if (!controller.signal.aborted) {
        setLoading(false);
      }
    }
  }, []);

  const uploadResume = useCallback(async (file: File, candidateInfo?: CandidateInfo): Promise<Resume | undefined> => {
    const controller = new AbortController();
    setAbortController(controller);
    
    let initialRecord: Resume | null = null;

    try {
      if (controller.signal.aborted) return;
      
      setLoading(true);
      setProcessingError(null);
      setProcessingStep('upload');

      const MAX_FILE_SIZE = 50 * 1024 * 1024;
      if (file.size > MAX_FILE_SIZE) {
        throw new Error('File size exceeds 50MB limit');
      }

      const validTypes = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
      if (!validTypes.includes(file.type)) {
        throw new Error('Invalid file type. Please upload a PDF, DOC, or DOCX file');
      }

      if (controller.signal.aborted) return;

      // Upload file to backend API with GDPR candidate info
      const formData = new FormData();
      formData.append('file', file);
      formData.append('name', file.name);
      formData.append('title', '');
      
      // Add GDPR candidate info if provided
      if (candidateInfo) {
        formData.append('profile_type', candidateInfo.profileType);
        formData.append('candidate_name', candidateInfo.candidateName);
        if (candidateInfo.candidateEmail) {
          formData.append('candidate_email', candidateInfo.candidateEmail);
        }
        // Add firm_id for admin users selecting a different firm
        if (candidateInfo.firmId) {
          formData.append('firm_id', candidateInfo.firmId);
        }
      }
      
      const uploadOptions = await createAuthOptionsWithCsrf({
        method: 'POST',
        body: formData
      });
      
      // Remove Content-Type header to let browser set it with boundary for multipart/form-data
      if (uploadOptions.headers) {
        delete uploadOptions.headers['Content-Type'];
      }
      
      const uploadResponse = await fetchWithAuth('/api/resumes/upload', {
        ...uploadOptions,
        signal: controller.signal
      });
      
      if (!uploadResponse.ok) {
        const errorData = await uploadResponse.json().catch(() => ({ error: 'Failed to upload resume' }));
        throw new Error(errorData.error || 'Failed to upload resume');
      }
      
      initialRecord = await uploadResponse.json();

      setProcessingStep('extract');
      const text = await extractResumeText(file);
      
      if (!text || text.length === 0) {
        throw new Error('Failed to extract text from resume');
      }
      
      if (controller.signal.aborted) return;

      setProcessingStep('analyze');
      
      // Call backend API for analysis (same endpoint used for post-improvement analysis)
      const analysisOptions = await createAuthOptionsWithCsrf({
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ text })
      });
      
      const analysisResponse = await fetchWithAuth('/api/resumes/analyze-text', {
        ...analysisOptions,
        signal: controller.signal
      });
      
      if (!analysisResponse.ok) {
        const errorData = await analysisResponse.json().catch(() => ({ error: 'Failed to analyze resume' }));
        const errorMessage = typeof errorData === 'string' 
          ? errorData 
          : (errorData?.error || errorData?.message || JSON.stringify(errorData) || 'Failed to analyze resume');
        throw new Error(errorMessage);
      }
      
      const analysis = await analysisResponse.json();
      
      // Ensure tags and suggestions have default values if not present
      const tags = analysis.tags || { skills: [], industries: [], tools: [], softSkills: [] };
      const suggestions = analysis.suggestions || {};
      
      // Use structuredText from analysis if available, otherwise use raw text
      const originalText = analysis.structuredText || text;
      
      // Update resume with analysis data via API
      const updateOptions = await createAuthOptionsWithCsrf({
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          'Original Text': originalText,
          'Global Rating': analysis.globalRating,
          'Skills Score': analysis.skillsRating,
          'Experience Score': analysis.experiencesRating,
          'Education Score': analysis.educationRating,
          'ATS Score': analysis.atsOptimizationRating,
          'Executive Summary Score': analysis.executiveSummaryRating,
          'Hobbies Languages Score': analysis.hobbiesLanguagesRating,
          'Skills': tags.skills || [],
          'Industries': tags.industries || [],
          'Tools': tags.tools || [],
          'Soft Skills': tags.softSkills || [],
          'Key Improvements': JSON.stringify(suggestions),
          'Name': analysis.name,
          'Original Name': analysis.originalName || analysis.name,
          'Title': analysis.title,
          'Status': 'Analyzed',
          'Analysis Date': new Date().toISOString(),
          'FirmName': user?.FirmName || undefined
        })
      });
      
      const updateResponse = await fetchWithAuth(`/api/resumes/${initialRecord!.id}`, {
        ...updateOptions,
        signal: controller.signal
      });
      
      if (!updateResponse.ok) {
        const errorData = await updateResponse.json().catch(() => ({ error: 'Failed to update resume' }));
        logger.error('[ResumeContext] Update failed:', errorData);
        throw new Error(errorData.error || 'Failed to update resume');
      }
      
      if (controller.signal.aborted) return;

      const updatedRecord = await updateResponse.json();
      const newResume = updatedRecord;
      setResumes(prev => [newResume, ...prev]);
      setCurrentResume(newResume);

      return newResume;
    } catch (error) {
      if (!controller.signal.aborted) {
        // Convert technical error to user-friendly message
        const { message: userFriendlyMessage } = getUserFriendlyMessage(error);
        setProcessingError(userFriendlyMessage);
        logger.error('[ResumeContext] ERROR during upload:', error);
        showCaughtError(error);

        if (initialRecord?.id) {
          // Update resume status to Error via API
          try {
            const errorUpdateOptions = await createAuthOptionsWithCsrf({
              method: 'PUT',
              headers: {
                'Content-Type': 'application/json',
              },
              body: JSON.stringify({
                'Status': 'Error'
              })
            });
            
            await fetchWithAuth(`/api/resumes/${initialRecord.id}`, errorUpdateOptions);
          } catch (updateError) {
            logger.error('[ResumeContext] Failed to update resume status to Error:', updateError);
          }
        }
      }
      throw error;
    } finally {
      if (!controller.signal.aborted) {
        setLoading(false);
        setProcessingStep(null);
      }
    }
  }, [user]);

  const improveCurrentResume = useCallback(async (): Promise<Resume> => {
    if (!currentResume) {
      throw new Error('No resume selected for improvement');
    }

    setLoading(true);
    setProcessingStep('improving');
    
    try {
      const text = currentResume['Original Text'];
      const currentAnalysis = {
        globalRating: currentResume['Global Rating'],
        skillsRating: currentResume['Skills Score'],
        experiencesRating: currentResume['Experience Score'],
        educationRating: currentResume['Education Score'],
        atsOptimizationRating: currentResume['ATS Score'],
        executiveSummaryRating: currentResume['Executive Summary Score'],
        hobbiesLanguagesRating: currentResume['Hobbies Languages Score'],
        suggestions: currentResume['Key Improvements'] 
          ? JSON.parse(currentResume['Key Improvements']) 
          : {},
        name: currentResume['Name'],
        originalName: currentResume['Original Name'] || currentResume['Name'],
        title: currentResume['Title']
      };

      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 300000);
      
      let response: Response;
      try {
        const authOptions = await createAuthOptionsWithCsrf({
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            text: text,
            analysis: currentAnalysis
          })
        });
        response = await fetchWithAuth('/api/resumes/improve', {
          ...authOptions,
          signal: controller.signal
        });
        clearTimeout(timeoutId);
      } catch (fetchError) {
        clearTimeout(timeoutId);
        logger.error('Fetch error:', fetchError);
        if (fetchError instanceof Error && fetchError.name === 'AbortError') {
          throw new Error('Request timed out after 5 minutes.');
        }
        throw new Error('Network error: Unable to connect to the server.');
      }

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Failed to improve resume' }));
        throw new Error(errorData.error || 'Failed to improve resume');
      }

      const responseData = await response.json();
      const { text: improvedText, analysis: improvedAnalysis } = responseData;
      
      setProcessingStep('analyzing');
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      // Save improved analysis data
      // Key Improvements = original suggestions (pre-improvement)
      // Improved Key Improvements = suggestions from post-improvement analysis
      const improvedSuggestions = improvedAnalysis?.suggestions || improvedAnalysis?.['Key Improvements'] || {};
      
      // Helper to get score value (handles 0 as valid value)
      const getScore = (primary: number | string | undefined, fallback: number | string | undefined): number => {
        if (primary !== undefined && primary !== null) return typeof primary === 'number' ? primary : parseInt(String(primary).replace('%', ''), 10) || 0;
        if (fallback !== undefined && fallback !== null) return typeof fallback === 'number' ? fallback : parseInt(String(fallback).replace('%', ''), 10) || 0;
        return 0;
      };

      const updatePayload = {
        'Original Text': text,
        'Improved Text': improvedText,
        'Improved Global Rating': String(getScore(improvedAnalysis?.globalRating, improvedAnalysis?.['Global Rating'])),
        'Improved Skills Score': String(getScore(improvedAnalysis?.skillsRating, improvedAnalysis?.['Skills'])),
        'Improved Experience Score': String(getScore(improvedAnalysis?.experiencesRating, improvedAnalysis?.['Experience'])),
        'Improved Education Score': String(getScore(improvedAnalysis?.educationRating, improvedAnalysis?.['Education'])),
        'Improved ATS Score': String(getScore(improvedAnalysis?.atsOptimizationRating, improvedAnalysis?.['ATS Compatibility'])),
        'Improved Executive Summary Score': String(getScore(improvedAnalysis?.executiveSummaryRating, improvedAnalysis?.['Executive Summary'])),
        'Improved Hobbies Languages Score': String(getScore(improvedAnalysis?.hobbiesLanguagesRating, improvedAnalysis?.['Hobbies Languages'])),
        // Save improved tags from post-improvement analysis
        'Improved Skills': JSON.stringify(improvedAnalysis?.tags?.skills || []),
        'Improved Industries': JSON.stringify(improvedAnalysis?.tags?.industries || []),
        'Improved Tools': JSON.stringify(improvedAnalysis?.tags?.tools || []),
        'Improved Soft Skills': JSON.stringify(improvedAnalysis?.tags?.softSkills || []),
        // Save suggestions from post-improvement analysis
        'Improved Key Improvements': JSON.stringify(improvedSuggestions),
        'Status': 'Improved' as const,
        'Last Improved': new Date().toISOString(),
        'FirmName': user?.FirmName || undefined
      };
      
      const updatedResume = await updateResumeAnalysis(currentResume.id, updatePayload);

      return updatedResume;
    } catch (error) {
      logger.error('Error improving resume:', error);
      showCaughtError(error);
      throw error;
    } finally {
      setLoading(false);
      setProcessingStep(null);
    }
  }, [currentResume, updateResumeAnalysis, user]);

  const updateImprovedContent = useCallback(async (resumeId: string, content: string): Promise<{ success: boolean; currentVersion?: number }> => {
    try {
      const updateOptions = await createAuthOptionsWithCsrf({
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 'Improved Text': content })
      });
      const response = await fetchWithAuth(`/api/resumes/${resumeId}`, updateOptions);
      if (!response.ok) {
        throw new Error('Failed to update improved content');
      }

      const updatedData = await response.json();
      const newVersion = updatedData['Current Version'] || 0;

      // Update currentResume
      setCurrentResume(prev => prev ? {
        ...prev,
        'Improved Text': content,
        'Current Version': newVersion
      } : null);

      // Also update the resumes list to keep it in sync
      setResumes(prev => prev.map(resume => 
        resume.id === resumeId 
          ? { ...resume, 'Improved Text': content, 'Current Version': newVersion }
          : resume
      ));

      return { success: true, currentVersion: newVersion };
    } catch (error) {
      logger.error('Error updating improved content:', error);
      throw error;
    }
  }, []);

  const updateOriginalContent = useCallback(async (resumeId: string, content: string): Promise<{ success: boolean }> => {
    try {
      const updateOptions = await createAuthOptionsWithCsrf({
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 'Original Text': content })
      });
      const response = await fetchWithAuth(`/api/resumes/${resumeId}`, updateOptions);
      if (!response.ok) {
        throw new Error('Failed to update original content');
      }

      // Update currentResume
      setCurrentResume(prev => prev ? {
        ...prev,
        'Original Text': content
      } : null);

      // Also update the resumes list to keep it in sync
      setResumes(prev => prev.map(resume => 
        resume.id === resumeId 
          ? { ...resume, 'Original Text': content }
          : resume
      ));

      return { success: true };
    } catch (error) {
      logger.error('Error updating original content:', error);
      throw error;
    }
  }, []);

  const deleteResume = useCallback(async (resumeId: string): Promise<void> => {
    const controller = new AbortController();
    setAbortController(controller);
    setDeleting(true);
    try {
      const deleteOptions = await createAuthOptionsWithCsrf({ method: 'DELETE' });
      const response = await fetchWithAuth(`/api/resumes/${resumeId}`, deleteOptions);
      if (!response.ok) {
        throw new Error('Failed to delete resume');
      }
      if (!controller.signal.aborted) {
        setResumes(prevResumes => prevResumes.filter(resume => resume.id !== resumeId));
        if (currentResume?.id === resumeId) {
          setCurrentResume(null);
        }
      }
    } catch (error) {
      if (!controller.signal.aborted) {
        logger.error('Error deleting resume:', error);
        const { message: userFriendlyMessage } = getUserFriendlyMessage(error);
        setProcessingError(userFriendlyMessage);
      }
    } finally {
      if (!controller.signal.aborted) {
        setDeleting(false);
      }
    }
  }, [currentResume]);

  const value: ResumeContextType = {
    resumes,
    currentResume,
    loading,
    processingStep,
    processingError,
    deleting,
    setProcessingError,
    setCurrentResume,
    setResumes,
    uploadResume,
    improveCurrentResume,
    updateResumeAnalysis,
    fetchResumes,
    updateImprovedContent,
    updateOriginalContent,
    deleteResume
  };

  return (
    <ResumeContext.Provider value={value}>
      {children}
    </ResumeContext.Provider>
  );
};

export default ResumeContext;

/**
 * Adaptations Page Component
 * TypeScript version
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { SparklesIcon, EyeIcon, ArrowDownTrayIcon, TrashIcon } from '@heroicons/react/24/outline';
import { useAuthFetch } from '../hooks/useAuthFetch';
import resumeAdaptationService from '../utils/resumeAdaptationService';
import { templateService } from '../utils/templateService';
import toast from 'react-hot-toast';
import { createSafeHtml } from '../utils/sanitizer.frontend';
import ExportModal from './AdaptationsPage_ExportModal';
import AdaptationAnalysisView from '../components/AdaptationAnalysisView';
import { createAuthOptionsWithCsrf, fetchWithAuth } from '../utils/apiInterceptor';
import logger from '../utils/logger.frontend';
import { formatDateTime } from '../utils/dateFormatter';

import { StatsCards, SearchAndFilters } from '../components/AdaptationsPage';
import Pagination from '../components/Pagination';
import { loadTinyMCE } from '../utils/lazyTinyMCE';
import { SkeletonAdaptationList } from '../components/ui/Skeleton';
import Breadcrumbs from '../components/Breadcrumbs';
import { removeSuggestionMarkers } from '../utils/tinymceSuggestionsPlugin';

interface Adaptation {
  id: string;
  Resume?: string[];
  Mission?: string[];
  'Resume ID'?: string;
  'Mission ID'?: string;
  'Resume Name'?: string;
  'Candidate Name'?: string;
  'Adapted Title'?: string;
  'Adapted Text'?: string;
  'Match Score'?: number;
  'Match Analysis'?: string;
  'Mission Title'?: string;
  'Mission Content'?: string;
  Status?: string;
  'Created At'?: string;
  [key: string]: unknown;
}

interface Resume {
  id: string;
  Name?: string;
  Title?: string;
  [key: string]: unknown;
}

interface Mission {
  id: string;
  Title?: string;
  Content?: string;
  Client?: string;
  Location?: string;
  [key: string]: unknown;
}

interface Template {
  id: string;
  Name: string;
  Status?: string;
  TemplateContent?: string;
  Stylesheet?: string;
  HeaderContent?: string;
  FooterContent?: string;
  FooterHeight?: number;
}

interface Stats {
  total: number;
  completed: number;
  processing: number;
  failed: number;
  avgScore: number;
}

const AdaptationsPage = (): JSX.Element => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { authGet } = useAuthFetch();
  const [adaptations, setAdaptations] = useState<Adaptation[]>([]);
  const [resumes, setResumes] = useState<Resume[]>([]);
  const [missions, setMissions] = useState<Mission[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [debouncedSearch, setDebouncedSearch] = useState<string>('');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  
  // Server-side pagination state
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [totalCount, setTotalCount] = useState<number>(0);
  const [, setHasMore] = useState<boolean>(false);
  const pageSize = 12;
  const [selectedAdaptation, setSelectedAdaptation] = useState<Adaptation | null>(null);
  const [showDetailModal, setShowDetailModal] = useState<boolean>(false);
  const [activeTab, setActiveTab] = useState<string>('analysis');
  const [editedAdaptedText, setEditedAdaptedText] = useState<string>('');
  const [isSaving, setIsSaving] = useState<boolean>(false);
  const editorRef = useRef<any>(null);
  const [editorReady, setEditorReady] = useState<boolean>(false);
  const [templates, setTemplates] = useState<Template[]>([]);
  const [selectedTemplate, setSelectedTemplate] = useState<string>('');
  const [loadingTemplates, setLoadingTemplates] = useState<boolean>(false);
  const [exportLoading, setExportLoading] = useState<boolean>(false);
  const [showExportModal, setShowExportModal] = useState<boolean>(false);
  const [adaptationToExport, setAdaptationToExport] = useState<Adaptation | null>(null);
  const [tinymceLoaded, setTinymceLoaded] = useState<boolean>(false);

  useEffect(() => {
    let mounted = true;
    loadTinyMCE().then(() => { if (mounted) setTinymceLoaded(true); }).catch((err) => { logger.error('Failed to load TinyMCE:', err); });
    return () => { mounted = false; };
  }, []);

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setCurrentPage(1); // Reset to first page on search
    }, 300);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  // Reset page when filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [filterStatus]);

  // eslint-disable-next-line react-hooks/exhaustive-deps -- fetchData/fetchTemplates use deps that match the effect array
  useEffect(() => { fetchData(); fetchTemplates(); }, [currentPage, debouncedSearch, filterStatus]);

  const fetchTemplates = async (): Promise<void> => {
    try {
      setLoadingTemplates(true);
      const fetchedTemplates = await templateService.getAllTemplates();
      setTemplates(fetchedTemplates.filter((t: Template) => t.Status === 'Active'));
      if (fetchedTemplates.length > 0) setSelectedTemplate(fetchedTemplates[0].id);
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching templates:', error);
        toast.error('Erreur lors du chargement des templates');
      }
    } finally {
      setLoadingTemplates(false);
    }
  };

  const fetchData = async (): Promise<void> => {
    try {
      setLoading(true);
      
      // Build query params for adaptations
      const params = new URLSearchParams();
      params.append('page', currentPage.toString());
      params.append('limit', pageSize.toString());
      if (debouncedSearch) params.append('search', debouncedSearch);
      if (filterStatus && filterStatus !== 'all') params.append('status', filterStatus);

      const [adaptationsRes, resumesRes, missionsRes] = await Promise.all([
        authGet(`/api/adaptations?${params.toString()}`),
        authGet('/api/resumes?limit=100'),
        authGet('/api/missions?limit=100')
      ]);
      
      // Handle paginated adaptations response
      if (adaptationsRes.ok) {
        const data = await adaptationsRes.json();
        if (data.data && data.pagination) {
          setAdaptations(data.data);
          setTotalCount(data.pagination.totalCount || data.data.length);
          setHasMore(data.pagination.hasMore || false);
        } else {
          setAdaptations(Array.isArray(data) ? data : []);
          setTotalCount(Array.isArray(data) ? data.length : 0);
          setHasMore(false);
        }
      }
      
      // Handle resumes and missions (for dropdowns)
      if (resumesRes.ok) { 
        const resumesData = await resumesRes.json(); 
        setResumes(resumesData.data || resumesData); 
      }
      if (missionsRes.ok) { 
        const missionsData = await missionsRes.json(); 
        setMissions(missionsData.data || missionsData); 
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching data:', error);
        toast.error('Erreur lors du chargement des adaptations');
      }
    } finally {
      setLoading(false);
    }
  };

  // Calculate total pages
  const totalPages = Math.ceil(totalCount / pageSize);

  // Pagination handler
  const goToPage = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handleDelete = async (adaptationId: string): Promise<void> => {
    if (!window.confirm('├ètes-vous s├╗r de vouloir supprimer cette adaptation ?')) return;
    try {
      await resumeAdaptationService.deleteAdaptation(adaptationId);
      setAdaptations(adaptations.filter(a => a.id !== adaptationId));
      toast.success('Adaptation supprim├®e');
    } catch (error) {
      logger.error('Error deleting adaptation:', error);
      toast.error(t('adaptations.messages.deleteError'));
    }
  };

  const _handleView = (adaptation: Adaptation): void => {
    setSelectedAdaptation(adaptation);
    setEditedAdaptedText(adaptation['Adapted Text'] || '');
    setShowDetailModal(true);
    setActiveTab('mission');
    setEditorReady(false);
  };

  const handleExportPDF = (adaptation: Adaptation): void => {
    setAdaptationToExport(adaptation);
    setShowExportModal(true);
  };

  const handleConfirmExport = async (): Promise<void> => {
    if (!adaptationToExport || !selectedTemplate) { toast.error('Veuillez s├®lectionner un template'); return; }
    try {
      setExportLoading(true);
      const template = await templateService.getTemplateById(selectedTemplate);
      if (!template) throw new Error('Template not found');

      const resumeId = adaptationToExport.Resume?.[0];
      const resume = resumes.find(r => r.id === resumeId);
      const candidateName = adaptationToExport['Candidate Name'] || resume?.Name || 'Candidat';
      const candidateTitle = adaptationToExport['Adapted Title'] || resume?.Title || 'Titre Professionnel';
      const customerName = resume?.CustomerName || '';
      // Clean suggestion markers from content before export
      const rawContent = adaptationToExport['Adapted Text'] || '';
      const content = removeSuggestionMarkers(rawContent);
      
      // Use trigram if anonymized, otherwise use candidate name
      const isAnonymized = resume?.Anonymized === true || resume?.Anonymized === 'true';
      const exportName: string = isAnonymized 
        ? (resume?.Trigram as string || candidateName.substring(0, 3).toUpperCase())
        : candidateName;
      
      // Format: CandidateName_CustomerName (no spaces, no dashes)
      const baseFilename = customerName 
        ? `${exportName}_${customerName}`
        : exportName;
      
      const simplifiedFilename = baseFilename.replace(/[^a-zA-Z0-9_]/g, '') + '.pdf';

      const stylesheet = template.Stylesheet || '';
      
      // Process body content
      let processedBody = template.TemplateContent || '';
      processedBody = processedBody.replace(/-name-/g, candidateName);
      processedBody = processedBody.replace(/-title-/g, candidateTitle);
      processedBody = processedBody.replace(/-content-/g, content);
      
      // Process header content (if exists)
      let processedHeader = template.HeaderContent || '';
      if (processedHeader) {
        processedHeader = processedHeader.replace(/-name-/g, candidateName);
        processedHeader = processedHeader.replace(/-title-/g, candidateTitle);
      }
      
      // Process footer content (if exists)
      let processedFooter = template.FooterContent || '';
      if (processedFooter) {
        processedFooter = processedFooter.replace(/-name-/g, candidateName);
        processedFooter = processedFooter.replace(/-title-/g, candidateTitle);
      }

      const response = await fetchWithAuth('/generate-pdf', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json; charset=utf-8' },
        body: JSON.stringify({ 
          htmlContent: processedBody, 
          filename: simplifiedFilename,
          stylesheet: stylesheet,
          headerContent: processedHeader || undefined,
          footerContent: processedFooter || undefined,
          footerHeight: template.FooterHeight || 25
        })
      });

      if (!response.ok) throw new Error('Failed to generate PDF');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      // Clean filename: remove all non-alphanumeric except underscores
      a.download = `${baseFilename.replace(/[^a-zA-Z0-9_]/g, '')}.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
      toast.success('PDF export├® avec succ├¿s');
      setShowExportModal(false);
      setAdaptationToExport(null);
    } catch (error) {
      logger.error('Error exporting PDF:', error);
      toast.error('Erreur lors de l\'export PDF');
    } finally {
      setExportLoading(false);
    }
  };

  const getResumeName = (adaptation: Adaptation): string => {
    // First try direct field from API
    if (adaptation['Resume Name']) return adaptation['Resume Name'];
    // Fallback to lookup by Resume ID or linked array
    const resumeId = adaptation['Resume ID'] || (adaptation.Resume && adaptation.Resume[0]);
    if (resumeId) {
      const resume = resumes.find(r => r.id === resumeId);
      if (resume?.Name) return resume.Name;
    }
    return t('adaptations.card.noName');
  };

  const getMissionTitle = (adaptation: Adaptation): string => {
    // First try direct field from API
    if (adaptation['Mission Title']) return adaptation['Mission Title'];
    // Fallback to lookup by Mission ID or linked array
    const missionId = adaptation['Mission ID'] || (adaptation.Mission && adaptation.Mission[0]);
    if (missionId) {
      const mission = missions.find(m => m.id === missionId);
      if (mission?.Title) return mission.Title;
    }
    return t('adaptations.card.unknownMission');
  };

  const getMissionData = (missionLinks?: string[]): Mission | null => {
    if (!missionLinks || missionLinks.length === 0) return null;
    const missionId = missionLinks[0];
    return missions.find(m => m.id === missionId) || null;
  };

  const initEditor = useCallback((): void => {
    const tinymce = window.tinymce as unknown as { init: (config: Record<string, unknown>) => void; get: (id: string) => { remove: () => void; getContent: () => string; setContent: (content: string) => void; on: (event: string, callback: () => void) => void } | null } | undefined;
    if (tinymceLoaded && tinymce && activeTab === 'adapted' && showDetailModal) {
      try {
        const existingEditor = tinymce.get('adaptedCVEditor');
        if (existingEditor) existingEditor.remove();
        
        tinymce.init({
          selector: '#adaptedCVEditor',
          license_key: 'gpl',
          height: 500,
          menubar: true,
          plugins: 'advlist autolink lists link charmap preview code fullscreen table wordcount',
          toolbar: 'undo redo | formatselect | bold italic | alignleft aligncenter alignright | bullist numlist | link | code fullscreen',
          content_style: 'body { font-family: Arial, sans-serif; font-size: 14px; }',
          setup: (editor: { on: (event: string, callback: () => void) => void; setContent: (content: string) => void; getContent: () => string }) => {
            editorRef.current = editor;
            editor.on('init', () => { setEditorReady(true); editor.setContent(editedAdaptedText || ''); });
            editor.on('change', () => { setEditedAdaptedText(editor.getContent()); });
          }
        });
      } catch (error) {
        logger.error('Error initializing TinyMCE:', error);
      }
    }
  }, [tinymceLoaded, activeTab, showDetailModal, editedAdaptedText]);

  useEffect(() => {
    if (activeTab === 'adapted' && showDetailModal) {
      const timer = setTimeout(() => { initEditor(); }, 100);
      return () => clearTimeout(timer);
    }
    return () => {
      const tinymce = window.tinymce as unknown as { init: (config: Record<string, unknown>) => void; get: (id: string) => { remove: () => void; getContent: () => string; setContent: (content: string) => void; on: (event: string, callback: () => void) => void } | null } | undefined;
      if (tinymce) { const editor = tinymce.get('adaptedCVEditor'); if (editor) editor.remove(); }
      editorRef.current = null;
      setEditorReady(false);
    };
  }, [activeTab, showDetailModal, initEditor]);

  const handleSaveAdaptedCV = async (): Promise<void> => {
    if (!selectedAdaptation || !editorRef.current) return;
    setIsSaving(true);
    try {
      const content = editorRef.current.getContent();
      const authOptions = await createAuthOptionsWithCsrf({ method: 'PUT', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ 'Adapted Text': content }) });
      const response = await fetchWithAuth(`/api/adaptations/${selectedAdaptation.id}`, authOptions);
      if (!response.ok) throw new Error('Failed to save adapted CV');
      setAdaptations(adaptations.map(a => a.id === selectedAdaptation.id ? { ...a, 'Adapted Text': content } : a));
      setSelectedAdaptation({ ...selectedAdaptation, 'Adapted Text': content });
      toast.success(t('adaptations.messages.saveSuccess'));
    } catch (error) {
      logger.error('Error saving adapted CV:', error);
      toast.error(t('adaptations.messages.saveError'));
    } finally {
      setIsSaving(false);
    }
  };

  // No client-side filtering needed - server handles it
  const filteredAdaptations = adaptations;

  const getScoreColor = (score: number): string => {
    if (score >= 80) return 'text-green-600 dark:text-green-400';
    if (score >= 60) return 'text-yellow-600 dark:text-yellow-400';
    return 'text-red-600 dark:text-red-400';
  };

  const getScoreBgColor = (score: number): string => {
    if (score >= 80) return 'bg-green-100 dark:bg-green-900/20';
    if (score >= 60) return 'bg-yellow-100 dark:bg-yellow-900/20';
    return 'bg-red-100 dark:bg-red-900/20';
  };

  const stats: Stats = {
    total: totalCount,
    completed: adaptations.filter(a => a.Status?.toLowerCase() === 'completed' || a.Status?.toLowerCase() === 'final').length,
    processing: adaptations.filter(a => a.Status?.toLowerCase() === 'processing' || a.Status?.toLowerCase() === 'draft').length,
    failed: adaptations.filter(a => a.Status?.toLowerCase() === 'failed').length,
    avgScore: adaptations.length > 0 ? Math.round(adaptations.reduce((sum, a) => sum + (a['Match Score'] || 0), 0) / adaptations.length) : 0
  };

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }} className="p-6 max-w-7xl mx-auto">
      <Breadcrumbs className="mb-4" />
      
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">{t('adaptations.title')}</h1>
        <p className="text-gray-600 dark:text-gray-400">{t('adaptations.subtitle')}</p>
      </div>

      <StatsCards stats={stats} t={t} />
      <SearchAndFilters searchTerm={searchTerm} onSearchChange={setSearchTerm} filterStatus={filterStatus} onFilterChange={setFilterStatus} onRefresh={fetchData} onReset={() => { setSearchTerm(''); setFilterStatus('all'); }} t={t} />

      {/* Top pagination */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('adaptations.results')}
      />

      {loading ? (
        <SkeletonAdaptationList count={6} />
      ) : filteredAdaptations.length === 0 ? (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-12 text-center">
          <SparklesIcon className="w-16 h-16 mx-auto text-gray-400 mb-4" />
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">{t('adaptations.noAdaptations')}</h3>
          <p className="text-gray-600 dark:text-gray-400">{searchTerm || filterStatus !== 'all' ? t('adaptations.noAdaptationsFiltered') : t('adaptations.noAdaptationsPrompt')}</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredAdaptations.map((adaptation, index) => (
            <motion.div key={adaptation.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: index * 0.05 }} className="bg-white dark:bg-gray-800 rounded-lg shadow hover:shadow-lg transition-shadow border border-gray-200 dark:border-gray-700">
              <div className="p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className={`px-3 py-1 rounded-full text-sm font-semibold ${getScoreBgColor(adaptation['Match Score'] || 0)}`}>
                    <span className={getScoreColor(adaptation['Match Score'] || 0)}>{adaptation['Match Score'] || 0}% Match</span>
                  </div>
                  <span className={`px-2 py-1 text-xs font-medium rounded ${
                    ['completed', 'final'].includes(adaptation.Status?.toLowerCase() || '') 
                      ? 'bg-green-100 text-green-800 dark:bg-green-900/20 dark:text-green-300' 
                      : ['processing', 'draft'].includes(adaptation.Status?.toLowerCase() || '')
                      ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/20 dark:text-yellow-300' 
                      : 'bg-red-100 text-red-800 dark:bg-red-900/20 dark:text-red-300'
                  }`}>{t(`adaptations.status.${adaptation.Status?.toLowerCase() || 'unknown'}`, adaptation.Status || 'N/A')}</span>
                </div>
                <div className="mb-4">
                  <h3 className="font-semibold text-gray-900 dark:text-white mb-1 line-clamp-1">{adaptation['Candidate Name'] || getResumeName(adaptation)}</h3>
                  {adaptation['Adapted Title'] && (
                    <p className="text-sm font-medium text-blue-600 dark:text-blue-400 mb-1 line-clamp-1 italic">{adaptation['Adapted Title']}</p>
                  )}
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-1"><span className="font-medium">{t('adaptations.mission')}:</span> {getMissionTitle(adaptation)}</p>
                  {adaptation['Created At'] && <p className="text-xs text-gray-500 dark:text-gray-500">{formatDateTime(adaptation['Created At'])}</p>}
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => navigate(`/adaptations/${adaptation.id}`)} className="flex-1 px-3 py-2 bg-blue-500 hover:bg-blue-600 text-white rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-1"><EyeIcon className="w-4 h-4" />{t('adaptations.viewAdaptation')}</button>
                  <button onClick={() => handleExportPDF(adaptation)} className="px-3 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-lg transition-colors" title={t('adaptations.exportPDF')}><ArrowDownTrayIcon className="w-4 h-4" /></button>
                  <button onClick={() => handleDelete(adaptation.id)} className="px-3 py-2 bg-red-100 dark:bg-red-900/20 hover:bg-red-200 dark:hover:bg-red-900/30 text-red-600 dark:text-red-400 rounded-lg transition-colors" title={t('adaptations.delete')}><TrashIcon className="w-4 h-4" /></button>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      )}

      {/* Pagination controls */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('adaptations.results')}
      />

      {showDetailModal && selectedAdaptation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-6xl w-full max-h-[90vh] flex flex-col">
            <div className="flex items-center justify-between p-6 border-b border-gray-200 dark:border-gray-700">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">{t('adaptations.modal.title')}</h2>
                <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">{getResumeName(selectedAdaptation)} ÔåÆ {getMissionTitle(selectedAdaptation)}</p>
              </div>
              <button onClick={() => { setShowDetailModal(false); setActiveTab('mission'); }} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="border-b border-gray-200 dark:border-gray-700 px-6">
              <nav className="flex gap-8">
                <button onClick={() => setActiveTab('mission')} className={`pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${activeTab === 'mission' ? 'border-blue-500 text-blue-600 dark:text-blue-400' : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}>{t('adaptations.modal.tabs.mission')}</button>
                <button onClick={() => setActiveTab('analysis')} className={`pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${activeTab === 'analysis' ? 'border-blue-500 text-blue-600 dark:text-blue-400' : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}>{t('adaptations.modal.tabs.analysis')}</button>
                <button onClick={() => setActiveTab('adapted')} className={`pb-4 px-1 border-b-2 font-medium text-sm transition-colors ${activeTab === 'adapted' ? 'border-blue-500 text-blue-600 dark:text-blue-400' : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-300'}`}>{t('adaptations.modal.tabs.adapted')}</button>
              </nav>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
              {activeTab === 'mission' && (() => {
                const missionTitle = selectedAdaptation['Mission Title'] || getMissionTitle(selectedAdaptation);
                const missionContent = selectedAdaptation['Mission Content'] || '';
                const mission = getMissionData(selectedAdaptation.Mission);
                const missionClient = mission?.Client || '';
                const missionLocation = mission?.Location || '';
                return (
                  <div className="space-y-6">
                    <div>
                      <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-4">{missionTitle}</h3>
                      {missionClient && <div className="mb-4"><span className="text-sm font-semibold text-gray-700 dark:text-gray-300">{t('adaptations.modal.mission.client')} : </span><span className="text-sm text-gray-600 dark:text-gray-400">{missionClient}</span></div>}
                      {missionLocation && <div className="mb-4"><span className="text-sm font-semibold text-gray-700 dark:text-gray-300">{t('adaptations.modal.mission.location')} : </span><span className="text-sm text-gray-600 dark:text-gray-400">{missionLocation}</span></div>}
                    </div>
                    {missionContent ? (
                      <div><h4 className="text-lg font-semibold text-gray-900 dark:text-white mb-3">{t('adaptations.modal.mission.description')}</h4><div className="prose prose-sm dark:prose-invert max-w-none" dangerouslySetInnerHTML={createSafeHtml(missionContent)} /></div>
                    ) : (
                      <div className="text-center py-8"><p className="text-gray-500 dark:text-gray-400">{t('adaptations.modal.mission.noDescription')}</p></div>
                    )}
                  </div>
                );
              })()}
              {activeTab === 'analysis' && <AdaptationAnalysisView adaptation={selectedAdaptation} />}
              {activeTab === 'adapted' && <div><textarea id="adaptedCVEditor" defaultValue={editedAdaptedText} className="hidden" /></div>}
            </div>

            <div className="flex items-center justify-end gap-3 p-6 border-t border-gray-200 dark:border-gray-700">
              {activeTab === 'adapted' && (
                <button onClick={handleSaveAdaptedCV} disabled={isSaving || !editorReady} className="px-6 py-2 bg-green-500 hover:bg-green-600 disabled:bg-gray-400 text-white rounded-lg font-medium transition-colors flex items-center gap-2">
                  {isSaving ? (<><div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>{t('adaptations.modal.saving')}</>) : (<><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>{t('adaptations.modal.save')}</>)}
                </button>
              )}
              <button onClick={() => handleExportPDF(selectedAdaptation)} className="px-6 py-2 bg-blue-500 hover:bg-blue-600 text-white rounded-lg font-medium transition-colors flex items-center gap-2"><ArrowDownTrayIcon className="w-5 h-5" />{t('adaptations.exportPDF')}</button>
              <button onClick={() => { setShowDetailModal(false); setActiveTab('analysis'); }} className="px-6 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600 rounded-lg font-medium transition-colors">{t('adaptations.modal.close')}</button>
            </div>
          </motion.div>
        </div>
      )}

      <ExportModal show={showExportModal} onClose={() => { setShowExportModal(false); setAdaptationToExport(null); }} templates={templates} selectedTemplate={selectedTemplate} setSelectedTemplate={setSelectedTemplate} onConfirm={handleConfirmExport} loading={exportLoading} loadingTemplates={loadingTemplates} />
    </motion.div>
  );
};

export default AdaptationsPage;

/**
 * BackupPage Component
 * Standalone page for database backup configuration via FTP/SFTP
 * Admin only access
 */

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import toast from 'react-hot-toast';
import { ArrowPathIcon, ServerStackIcon } from '@heroicons/react/24/outline';
import { useAuthFetch } from '../hooks/useAuthFetch';
import logger from '../utils/logger.frontend';
import type { BackupSettings, BackupHistoryItem, RemoteFile } from './backupPage.types';
import { defaultSettings } from './backupPage.types';
import BackupConfigSection from './BackupConfigSection';
import BackupHistorySection from './BackupHistorySection';
import BackupRestoreSection from './BackupRestoreSection';

const BackupPage = (): JSX.Element => {
    const { t } = useTranslation();
    const { authGet, authPost, authPut, authDelete } = useAuthFetch();

    const [settings, setSettings] = useState<BackupSettings>(defaultSettings);
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [testing, setTesting] = useState(false);
    const [backingUp, setBackingUp] = useState(false);
    const [history, setHistory] = useState<BackupHistoryItem[]>([]);
    const [remoteFiles, setRemoteFiles] = useState<RemoteFile[]>([]);
    const [loadingRemote, setLoadingRemote] = useState(false);
    const [restoring, setRestoring] = useState<string | null>(null);
    const [activeSection, setActiveSection] = useState<'config' | 'history' | 'restore'>('config');


    useEffect(() => {
        fetchSettings();
        fetchHistory();
    }, []);

    const fetchSettings = async () => {
        try {
            const response = await authGet('/api/backup/settings');
            if (response.ok) {
                const data = await response.json();
                if (data && data.id) {
                    setSettings({ 
                        ...defaultSettings, 
                        ...data,
                        tls_mode: data.tls_mode || 'explicit'
                    });
                }
            }
        } catch (error) {
            logger.error('Failed to fetch backup settings:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchHistory = async () => {
        try {
            const response = await authGet('/api/backup/history?limit=20');
            if (response.ok) {
                const data = await response.json();
                setHistory(data.items || []);
            }
        } catch (error) {
            logger.error('Failed to fetch backup history:', error);
        }
    };

    const fetchRemoteFiles = async () => {
        setLoadingRemote(true);
        try {
            const response = await authGet('/api/backup/list-remote');
            if (response.ok) {
                const data = await response.json();
                if (data.success) {
                    setRemoteFiles(data.files || []);
                } else {
                    toast.error(data.message || t('backup.remoteListError'));
                }
            }
        } catch (error) {
            logger.error('Failed to fetch remote files:', error);
            toast.error(t('backup.remoteListError'));
        } finally {
            setLoadingRemote(false);
        }
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            const payload = {
                ...settings,
                password: password || undefined
            };

            const response = await authPut('/api/backup/settings', payload);
            if (response.ok) {
                const data = await response.json();
                setSettings({ ...defaultSettings, ...data });
                setPassword('');
                toast.success(t('backup.saveSuccess'));
            } else {
                toast.error(t('backup.saveError'));
            }
        } catch (error) {
            logger.error('Failed to save backup settings:', error);
            toast.error(t('backup.saveError'));
        } finally {
            setSaving(false);
        }
    };

    const handleTestConnection = async () => {
        setTesting(true);
        try {
            const payload = {
                protocol: settings.protocol,
                tls_mode: settings.tls_mode,
                host: settings.host,
                port: settings.port,
                username: settings.username,
                password: password || undefined,
                remote_path: settings.remote_path
            };

            const response = await authPost('/api/backup/test-connection', payload);
            const data = await response.json();

            if (data.success) {
                toast.success(t('backup.connectionSuccess'));
            } else {
                toast.error(data.message || t('backup.connectionError'));
            }
        } catch (error) {
            logger.error('Connection test failed:', error);
            toast.error(t('backup.connectionError'));
        } finally {
            setTesting(false);
        }
    };

    const handleRunBackup = async () => {
        setBackingUp(true);
        try {
            const response = await authPost('/api/backup/run', {});
            const data = await response.json();

            if (data.success) {
                toast.success(t('backup.backupSuccess'));
                fetchHistory();
            } else {
                toast.error(data.error || t('backup.backupError'));
            }
        } catch (error) {
            logger.error('Backup failed:', error);
            toast.error(t('backup.backupError'));
        } finally {
            setBackingUp(false);
        }
    };

    const handleDeleteHistory = async (id: string) => {
        try {
            const response = await authDelete(`/api/backup/history/${id}`);
            if (response.ok) {
                setHistory(prev => prev.filter(item => item.id !== id));
                toast.success(t('backup.historyDeleted'));
            }
        } catch (error) {
            logger.error('Failed to delete history entry:', error);
        }
    };

    const handleRestore = async (filename: string) => {
        if (!window.confirm(t('backup.restoreConfirm'))) {
            return;
        }

        setRestoring(filename);
        try {
            const response = await authPost('/api/backup/restore', { filename });
            const data = await response.json();

            if (data.success) {
                toast.success(t('backup.restoreSuccess'));
            } else {
                toast.error(data.message || t('backup.restoreError'));
            }
        } catch (error) {
            logger.error('Restore failed:', error);
            toast.error(t('backup.restoreError'));
        } finally {
            setRestoring(null);
        }
    };

    const handleInputChange = (field: keyof BackupSettings, value: string | number | boolean) => {
        setSettings(prev => {
            const updated = { ...prev, [field]: value };

            if (field === 'protocol') {
                if (value === 'sftp') {
                    updated.port = 22;
                } else {
                    updated.port = 21;
                }
            }

            return updated;
        });
    };

    const dayNames = [
        t('backup.sunday'),
        t('backup.monday'),
        t('backup.tuesday'),
        t('backup.wednesday'),
        t('backup.thursday'),
        t('backup.friday'),
        t('backup.saturday')
    ];

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12">
                <ArrowPathIcon className="w-8 h-8 animate-spin text-gray-400" />
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto px-4 py-6">
            {/* Header */}
            <div className="mb-6">
                <div className="flex items-center gap-3 mb-2">
                    <ServerStackIcon className="w-8 h-8 text-blue-600 dark:text-blue-400" />
                    <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
                        {t('backup.pageTitle')}
                    </h1>
                </div>
                <p className="text-sm text-gray-600 dark:text-gray-400">
                    {t('backup.pageDescription')}
                </p>
            </div>

            {/* Section Tabs */}
            <div className="flex space-x-4 border-b border-gray-200 dark:border-gray-700 mb-6">
                <button
                    onClick={() => setActiveSection('config')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors ${
                        activeSection === 'config'
                            ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                            : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400'
                    }`}
                >
                    {t('backup.configTab')}
                </button>
                <button
                    onClick={() => setActiveSection('history')}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors ${
                        activeSection === 'history'
                            ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                            : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400'
                    }`}
                >
                    {t('backup.historyTab')}
                </button>
                <button
                    onClick={() => {
                        setActiveSection('restore');
                        fetchRemoteFiles();
                    }}
                    className={`pb-2 px-1 text-sm font-medium border-b-2 transition-colors ${
                        activeSection === 'restore'
                            ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                            : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400'
                    }`}
                >
                    {t('backup.restoreTab')}
                </button>
            </div>

            {/* Configuration Section */}
            {activeSection === 'config' && (
                <BackupConfigSection
                    settings={settings}
                    password={password}
                    setPassword={setPassword}
                    saving={saving}
                    testing={testing}
                    backingUp={backingUp}
                    dayNames={dayNames}
                    onInputChange={handleInputChange}
                    onSave={handleSave}
                    onTestConnection={handleTestConnection}
                    onRunBackup={handleRunBackup}
                />
            )}

            {/* History Section */}
            {activeSection === 'history' && (
                <BackupHistorySection
                    history={history}
                    onRefresh={fetchHistory}
                    onDelete={handleDeleteHistory}
                />
            )}

            {/* Restore Section */}
            {activeSection === 'restore' && (
                <BackupRestoreSection
                    remoteFiles={remoteFiles}
                    loadingRemote={loadingRemote}
                    restoring={restoring}
                    onRefresh={fetchRemoteFiles}
                    onRestore={handleRestore}
                />
            )}
        </div>
    );
};

export default BackupPage;

/**
 * CRMPage - Manage clients, prospects and deals
 * TypeScript version - Renamed from ClientsPage
 */

import { useState, useEffect, ChangeEvent } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import clientService from '../utils/clientService';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';
import logger from '../utils/logger.frontend';
import {
  BuildingOfficeIcon,
  UserGroupIcon,
  PencilSquareIcon,
  TrashIcon,
  MagnifyingGlassIcon,
  PlusIcon,
  ArrowPathIcon,
  XMarkIcon,
  GlobeAltIcon,
  MapPinIcon,
  BriefcaseIcon,
  PaperAirplaneIcon,
  EyeIcon,
  FolderIcon
} from '@heroicons/react/24/outline';
import { DealsTab } from '../components/CRM';

import {
  ClientFormModal,
  ContactFormModal,
  ClientDetailModal,
  ConfirmDeleteModal
} from '../components/ClientsPage';
import Pagination from '../components/Pagination';
import { Client, ClientContact, ClientType } from '../types/entities';
import { SkeletonClientList } from '../components/ui/Skeleton';
import Breadcrumbs from '../components/Breadcrumbs';

interface Stats {
  totalClients: number;
  totalProspects: number;
  totalContacts: number;
  totalSubmissions: number;
}

interface DeleteTarget {
  id: string;
  name?: string;
  type: 'client' | 'contact';
  clientId?: string;
}

type CRMTab = 'clients' | 'deals';
type ClientFilter = 'all' | 'client' | 'prospect';

const CRMPage = (): JSX.Element => {
  const { t } = useTranslation();
  const [searchParams, setSearchParams] = useSearchParams();

  // Main CRM tab (clients vs deals)
  const [crmTab, setCrmTab] = useState<CRMTab>(
    (searchParams.get('tab') as CRMTab) || 'clients'
  );

  const [clients, setClients] = useState<Client[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [activeTab, setActiveTab] = useState<ClientFilter>('all');
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [debouncedSearch, setDebouncedSearch] = useState<string>('');

  // Pagination state
  const [page, setPage] = useState<number>(1);
  const [totalCount, setTotalCount] = useState<number>(0);
  const [, setHasMore] = useState<boolean>(false);
  const pageSize = 12;

  // Modal states
  const [clientModalOpen, setClientModalOpen] = useState<boolean>(false);
  const [contactModalOpen, setContactModalOpen] = useState<boolean>(false);
  const [detailModalOpen, setDetailModalOpen] = useState<boolean>(false);
  const [deleteModalOpen, setDeleteModalOpen] = useState<boolean>(false);

  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [selectedContact, setSelectedContact] = useState<ClientContact | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<DeleteTarget | null>(null);

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  // Fetch data
  const fetchData = async (): Promise<void> => {
    try {
      setLoading(true);
      const typeFilter = activeTab === 'all' ? '' : activeTab;
      const result = await clientService.getClients({
        page,
        pageSize,
        search: debouncedSearch,
        type: typeFilter
      });

      setClients(result.clients);
      setTotalCount(result.pagination?.totalCount || result.clients.length);
      setHasMore(result.pagination?.hasMore || false);
    } catch (error) {
      logger.error('Error fetching clients:', error);
      toast.error(t('clients.messages.errorFetching'));
    } finally {
      setLoading(false);
    }
  };


  useEffect(() => {
    fetchData();
  }, [page, debouncedSearch, activeTab]);

  // Calculate stats - ensure numeric addition (API may return strings)
  const stats: Stats = {
    totalClients: clients.filter(c => c.type === 'client').length,
    totalProspects: clients.filter(c => c.type === 'prospect').length,
    totalContacts: clients.reduce((sum, c) => sum + Number(c.contacts_count || 0), 0),
    totalSubmissions: clients.reduce((sum, c) => sum + Number(c.submissions_count || 0), 0)
  };

  // Pagination
  const totalPages = Math.ceil(totalCount / pageSize);
  const goToPage = (newPage: number) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Handlers
  const handleClientSubmit = async (formData: Partial<Client>): Promise<void> => {
    try {
      if (selectedClient) {
        await clientService.updateClient(selectedClient.id, formData);
        toast.success(t('clients.messages.clientUpdated'));
      } else {
        await clientService.createClient(formData);
        toast.success(t('clients.messages.clientCreated'));
      }
      setClientModalOpen(false);
      setSelectedClient(null);
      await fetchData();
    } catch (error) {
      logger.error('Error saving client:', error);
      toast.error(selectedClient 
        ? t('clients.messages.errorUpdatingClient') 
        : t('clients.messages.errorCreatingClient'));
    }
  };

  const handleContactSubmit = async (formData: Partial<ClientContact>): Promise<void> => {
    try {
      if (!selectedClient) return;

      if (selectedContact) {
        await clientService.updateContact(selectedClient.id, selectedContact.id, formData);
        toast.success(t('clients.messages.contactUpdated'));
      } else {
        await clientService.createContact(selectedClient.id, formData);
        toast.success(t('clients.messages.contactCreated'));
      }
      setContactModalOpen(false);
      setSelectedContact(null);
      await fetchData();
    } catch (error) {
      logger.error('Error saving contact:', error);
      toast.error(selectedContact 
        ? t('clients.messages.errorUpdatingContact') 
        : t('clients.messages.errorCreatingContact'));
    }
  };

  const handleDelete = async (): Promise<void> => {
    if (!deleteTarget) return;
    try {
      if (deleteTarget.type === 'client') {
        await clientService.deleteClient(deleteTarget.id);
        toast.success(t('clients.messages.clientDeleted'));
      } else if (deleteTarget.type === 'contact' && deleteTarget.clientId) {
        await clientService.deleteContact(deleteTarget.clientId, deleteTarget.id);
        toast.success(t('clients.messages.contactDeleted'));
      }
      setDeleteModalOpen(false);
      setDeleteTarget(null);
      await fetchData();
    } catch (error: unknown) {
      logger.error('Error deleting:', error);
      if (error instanceof Error && error.message.includes('submission')) {
        toast.error(t('clients.messages.cannotDeleteWithSubmissions'));
      } else {
        toast.error(t('clients.messages.errorDeleting'));
      }
    }
  };

  const openClientDetail = async (client: Client) => {
    try {
      const fullClient = await clientService.getClient(client.id);
      setSelectedClient(fullClient);
      setDetailModalOpen(true);
    } catch (error) {
      logger.error('Error fetching client details:', error);
      toast.error(t('clients.messages.errorFetching'));
    }
  };

  const getTypeColor = (type: ClientType): string => {
    return type === 'client' 
      ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300'
      : 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300';
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="p-6 max-w-7xl mx-auto"
    >
      <Breadcrumbs className="mb-4" />

      {/* Header */}
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
          {t('crm.title', 'CRM')}
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          {t('crm.subtitle', 'G├®rez vos clients, prospects et affaires')}
        </p>
      </div>

      {/* CRM Main Tabs */}
      <div className="flex items-center gap-1 mb-6 border-b border-gray-200 dark:border-gray-700">
        <button
          onClick={() => {
            setCrmTab('clients');
            searchParams.set('tab', 'clients');
            searchParams.delete('clientId');
            setSearchParams(searchParams);
          }}
          className={`flex items-center gap-2 px-4 py-3 font-medium border-b-2 transition-colors ${
            crmTab === 'clients'
              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'
          }`}
        >
          <BuildingOfficeIcon className="w-5 h-5" />
          {t('crm.tabs.clients', 'Clients & Prospects')}
        </button>
        <button
          onClick={() => {
            setCrmTab('deals');
            searchParams.set('tab', 'deals');
            setSearchParams(searchParams);
          }}
          className={`flex items-center gap-2 px-4 py-3 font-medium border-b-2 transition-colors ${
            crmTab === 'deals'
              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'
          }`}
        >
          <FolderIcon className="w-5 h-5" />
          {t('crm.tabs.deals', 'Affaires')}
        </button>
      </div>

      {/* Deals Tab Content */}
      {crmTab === 'deals' && (
        <DealsTab preFilterClientId={searchParams.get('clientId') || undefined} />
      )}

      {/* Clients Tab Content */}
      {crmTab === 'clients' && (
        <>
      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 flex items-center gap-3">
          <div className="p-2 bg-green-100 dark:bg-green-900/30 rounded-lg">
            <BuildingOfficeIcon className="w-6 h-6 text-green-600 dark:text-green-400" />
          </div>
          <div>
            <div className="text-sm text-gray-600 dark:text-gray-400">{t('clients.stats.clients')}</div>
            <div className="text-2xl font-bold text-gray-900 dark:text-white">{stats.totalClients}</div>
          </div>
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 flex items-center gap-3">
          <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
            <BriefcaseIcon className="w-6 h-6 text-blue-600 dark:text-blue-400" />
          </div>
          <div>
            <div className="text-sm text-gray-600 dark:text-gray-400">{t('clients.stats.prospects')}</div>
            <div className="text-2xl font-bold text-gray-900 dark:text-white">{stats.totalProspects}</div>
          </div>
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 flex items-center gap-3">
          <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
            <UserGroupIcon className="w-6 h-6 text-purple-600 dark:text-purple-400" />
          </div>
          <div>
            <div className="text-sm text-gray-600 dark:text-gray-400">{t('clients.stats.contacts')}</div>
            <div className="text-2xl font-bold text-gray-900 dark:text-white">{stats.totalContacts}</div>
          </div>
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 flex items-center gap-3">
          <div className="p-2 bg-orange-100 dark:bg-orange-900/30 rounded-lg">
            <PaperAirplaneIcon className="w-6 h-6 text-orange-600 dark:text-orange-400" />
          </div>
