/**
 * M├®tiers et Comp├®tences Page
 * Interface for querying Rome 4.0 API and managing IT m├®tiers
 */

import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import {
  getStoredMetiers,
  collectITMetiers,
  Metier,
  CollectionSummary
} from '../services/romeService';
import {
  MagnifyingGlassIcon,
  ArrowPathIcon,
  BriefcaseIcon,
  AcademicCapIcon,
  ChevronDownIcon,
  ChevronUpIcon,
  ExclamationTriangleIcon,
  CheckCircleIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import { formatDateTime } from '../utils/dateFormatter';

export default function MetiersPage() {
  const { user } = useAuth();
  const isAdmin = user?.role === 'admin';

  // State
  const [metiers, setMetiers] = useState<Metier[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedMetier, setSelectedMetier] = useState<Metier | null>(null);
  const [expandedMetiers, setExpandedMetiers] = useState<Set<string>>(new Set());

  // Collection state
  const [collecting, setCollecting] = useState(false);
  const [collectionResult, setCollectionResult] = useState<CollectionSummary | null>(null);

  // Load stored m├®tiers on mount
  useEffect(() => {
    loadMetiers();
  }, []);

  const loadMetiers = async (search?: string) => {
    try {
      setLoading(true);
      setError(null);
      const data = await getStoredMetiers(search ? { search } : undefined);
      setMetiers(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors du chargement des m├®tiers');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    await loadMetiers(searchQuery);
  };

  const handleCollect = async () => {
    if (!isAdmin) return;

    try {
      setCollecting(true);
      setError(null);
      setCollectionResult(null);

      const result = await collectITMetiers();
      setCollectionResult(result);

      // Reload m├®tiers after collection
      await loadMetiers();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Erreur lors de la collecte');
    } finally {
      setCollecting(false);
    }
  };

  const toggleMetierExpand = (codeRome: string) => {
    const newExpanded = new Set(expandedMetiers);
    if (newExpanded.has(codeRome)) {
      newExpanded.delete(codeRome);
    } else {
      newExpanded.add(codeRome);
    }
    setExpandedMetiers(newExpanded);
  };

  const clearSearch = () => {
    setSearchQuery('');
    loadMetiers();
  };

  return (
    <>
      {/* Full-screen overlay during collection */}
      {collecting && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/50 backdrop-blur-sm">
