        </div>
        <Icon className="w-10 h-10 opacity-50" />
      </div>
    </motion.div>
  );
});
StatCard.displayName = 'StatCard';

const ProgressBar = memo(({ label, value, max, color = 'blue' }: ProgressBarProps): JSX.Element => {
  const percentage = max > 0 ? (value / max) * 100 : 0;
  const colorClasses: Record<string, string> = { blue: 'bg-blue-500', green: 'bg-green-500', yellow: 'bg-yellow-500', red: 'bg-red-500' };
  return (
    <div className="mb-3">
      <div className="flex justify-between text-sm mb-1">
        <span className="text-gray-600 dark:text-gray-400">{label}</span>
        <span className="font-medium">{value} / {max}</span>
      </div>
      <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
        <div className={`h-2 rounded-full ${colorClasses[color]} transition-all duration-500`} style={{ width: `${Math.min(percentage, 100)}%` }} />
      </div>
    </div>
  );
});
ProgressBar.displayName = 'ProgressBar';

interface Metrics {
  server?: { uptimeSeconds?: number; startTime?: string };
  requests?: { 
    total?: number; 
    last24h?: number; 
    byMethod?: Record<string, number>;
    byStatus?: Record<string, number>;
    topEndpoints?: Array<{ endpoint?: string; path?: string; count?: number }>;
  };
  performance?: { avgResponseTime?: number; minResponseTime?: number; maxResponseTime?: number };
  errors?: { rate?: number; total?: number };
  memory?: { heapUsed?: number; heapTotal?: number; rss?: number; external?: number };
  cache?: { hitRate?: number; hits?: number; misses?: number };
  llm?: { 
    requests?: number; 
    totalTokens?: number; 
    estimatedCost?: number;
    byProvider?: Record<string, { requests?: number } | number>;
  };
}

interface DatabaseMetrics {
  database?: { size?: number; sizePretty?: string };
  tables?: Array<{ name: string; rowCount: number; deadRows: number; lastVacuum?: string; lastAnalyze?: string }>;
  connections?: { total?: number; active?: number; idle?: number };
  queryTime?: string;
  timestamp?: string;
}

interface APMMetrics {
  config?: {
    slowThreshold?: number;
    verySlowThreshold?: number;
    criticalThreshold?: number;
  };
  summary?: {
    totalTracked?: number;
    last5min?: number;
    last1h?: number;
    avgDuration?: number;
    severityCounts?: {
      slow?: number;
      very_slow?: number;
      critical?: number;
    };
  };
  topSlowEndpoints?: Array<{
    endpoint: string;
    count: number;
    avgDuration: number;
    maxDuration: number;
  }>;
  timestamp?: string;
}

const MetricsPage = (): JSX.Element => {
  const { t } = useTranslation();
  const [metrics, setMetrics] = useState<Metrics | null>(null);
  const [dbMetrics, setDbMetrics] = useState<DatabaseMetrics | null>(null);
  const [apmMetrics, setApmMetrics] = useState<APMMetrics | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [autoRefresh, setAutoRefresh] = useState<boolean>(true);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchMetrics = async (): Promise<void> => {
    try {
      const response = await fetchWithAuth('/api/metrics', createAuthOptions());
      if (!response.ok) {
        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
        if (response.status === 403) toast.error(t('metrics.accessDenied'));
        else if (response.status === 401) toast.error(t('metrics.sessionExpired'));
        else toast.error(`${t('common.error')} ${response.status}: ${errorData.error || t('metrics.error')}`);
        throw new Error(`Failed to fetch metrics: ${response.status}`);
      }
      const data = await response.json();
      setMetrics(data);
      setLastUpdated(new Date());
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching metrics:', error);
      }
    }
  };

  const fetchDbMetrics = async (): Promise<void> => {
    try {
      const response = await fetchWithAuth('/api/metrics/database', createAuthOptions());
      if (response.ok) {
        const data = await response.json();
        setDbMetrics(data);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching database metrics:', error);
      }
    }
  };

  const fetchApmMetrics = async (): Promise<void> => {
    try {
      const response = await fetchWithAuth('/api/metrics/apm', createAuthOptions());
      if (response.ok) {
        const data = await response.json();
        setApmMetrics(data);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching APM metrics:', error);
      }
    }
  };

  const exportMetrics = (format: 'json' | 'csv'): void => {
    if (!metrics) return;
    
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const filename = `metrics-${timestamp}.${format}`;
    
    let content: string;
    let mimeType: string;
    
    if (format === 'json') {
      const exportData = {
        exportedAt: new Date().toISOString(),
        metrics,
        database: dbMetrics
      };
      content = JSON.stringify(exportData, null, 2);
      mimeType = 'application/json';
    } else {
      // CSV format - flatten key metrics
      const rows = [
        ['Metric', 'Value'],
        ['Uptime (seconds)', String(metrics.server?.uptimeSeconds || 0)],
        ['Total Requests', String(metrics.requests?.total || 0)],
        ['Requests Last 24h', String(metrics.requests?.last24h || 0)],
        ['Avg Response Time (ms)', String(metrics.performance?.avgResponseTime || 0)],
        ['Error Rate', String((metrics.errors?.rate || 0) * 100) + '%'],
        ['Total Errors', String(metrics.errors?.total || 0)],
        ['Heap Used (bytes)', String(metrics.memory?.heapUsed || 0)],
        ['Heap Total (bytes)', String(metrics.memory?.heapTotal || 0)],
        ['Cache Hit Rate', String((metrics.cache?.hitRate || 0) * 100) + '%'],
        ['Cache Hits', String(metrics.cache?.hits || 0)],
        ['Cache Misses', String(metrics.cache?.misses || 0)],
        ['LLM Requests', String(metrics.llm?.requests || 0)],
        ['LLM Total Tokens', String(metrics.llm?.totalTokens || 0)],
        ['DB Size', dbMetrics?.database?.sizePretty || 'N/A'],
        ['DB Connections Total', String(dbMetrics?.connections?.total || 0)],
        ['DB Connections Active', String(dbMetrics?.connections?.active || 0)]
      ];
      content = rows.map(row => row.join(',')).join('\n');
      mimeType = 'text/csv';
    }
    
    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    
    toast.success(t('metrics.exportSuccess', `M├®triques export├®es (${format.toUpperCase()})`));
  };

  useEffect(() => {
    const loadData = async (): Promise<void> => {
      setLoading(true);
      await Promise.all([fetchMetrics(), fetchDbMetrics(), fetchApmMetrics()]);
      setLoading(false);
    };
    // Load immediately without delay for faster initial render
    loadData();
  }, []);

  useEffect(() => {
    if (!autoRefresh) return;
    const interval = setInterval(async () => {
      await Promise.all([fetchMetrics(), fetchDbMetrics(), fetchApmMetrics()]);
    }, 30000);
    return () => clearInterval(interval);
  }, [autoRefresh]);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.5 }} className="p-6">
      <Breadcrumbs className="mb-4" />
      
      <div className="mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">{t('metrics.title')}</h1>
            <p className="text-gray-600 dark:text-gray-400">{t('metrics.subtitle')}</p>
          </div>
          <div className="flex items-center gap-4">
            <label className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
              <input type="checkbox" checked={autoRefresh} onChange={(e: ChangeEvent<HTMLInputElement>) => setAutoRefresh(e.target.checked)} className="rounded border-gray-300 dark:border-gray-600 text-blue-600 focus:ring-blue-500" />
              {t('metrics.autoRefresh')}
            </label>
            <button onClick={fetchMetrics} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
              <ArrowPathIcon className="w-4 h-4" />
              {t('metrics.refresh')}
            </button>
            <div className="relative group">
              <button className="flex items-center gap-2 px-4 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors">
                <ArrowDownTrayIcon className="w-4 h-4" />
                {t('metrics.export', 'Export')}
              </button>
              <div className="absolute right-0 mt-2 w-32 bg-white dark:bg-gray-800 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-10">
                <button onClick={() => exportMetrics('json')} className="w-full px-4 py-2 text-left text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-t-lg">
                  JSON
                </button>
                <button onClick={() => exportMetrics('csv')} className="w-full px-4 py-2 text-left text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-b-lg">
                  CSV
                </button>
              </div>
            </div>
          </div>
        </div>
        {lastUpdated && <p className="text-xs text-gray-400 dark:text-gray-500 mt-2">{t('metrics.lastUpdate')}: {formatDateTime(lastUpdated)}</p>}
      </div>

      {metrics ? (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            <StatCard title={t('metrics.uptime')} value={formatUptime(safeNumber(metrics.server?.uptimeSeconds))} subtitle={`${t('metrics.startedAt')}: ${metrics.server?.startTime ? formatDateTime(metrics.server.startTime) : 'N/A'}`} icon={ServerIcon} color="green" />
            <StatCard title={t('metrics.totalRequests')} value={formatNumber(safeNumber(metrics.requests?.total))} subtitle={`${t('metrics.last24h')}: ${formatNumber(safeNumber(metrics.requests?.last24h))}`} icon={ChartBarIcon} color="blue" />
            <StatCard title={t('metrics.avgResponseTime')} value={`${safeNumber(metrics.performance?.avgResponseTime).toFixed(0)}ms`} subtitle={`Min: ${safeNumber(metrics.performance?.minResponseTime)}ms / Max: ${safeNumber(metrics.performance?.maxResponseTime)}ms`} icon={ClockIcon} color="purple" />
            <StatCard title={t('metrics.errorRate')} value={`${(safeNumber(metrics.errors?.rate) * 100).toFixed(2)}%`} subtitle={`${t('metrics.totalErrors')}: ${safeNumber(metrics.errors?.total)}`} icon={ExclamationTriangleIcon} color={safeNumber(metrics.errors?.rate) > 0.05 ? 'red' : 'green'} />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="rounded-xl border bg-indigo-50 text-indigo-600 border-indigo-200 dark:bg-gray-800 dark:text-indigo-400 dark:border-indigo-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.serverMemory')}</p>
                  <p className="text-2xl font-bold mt-1">{formatBytes(safeNumber(metrics.memory?.heapUsed))}</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.heapUsed', { total: formatBytes(safeNumber(metrics.memory?.heapTotal)) })}</p>
                </div>
                <CpuChipIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="w-full bg-indigo-200 dark:bg-indigo-900/50 rounded-full h-2 mb-4">
                <div className="h-2 rounded-full bg-indigo-500 transition-all duration-500" style={{ width: `${safeNumber(metrics.memory?.heapTotal) > 0 ? (safeNumber(metrics.memory?.heapUsed) / safeNumber(metrics.memory?.heapTotal)) * 100 : 0}%` }} />
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div className="bg-indigo-100 dark:bg-indigo-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.rss')}</p><p className="font-semibold">{formatBytes(safeNumber(metrics.memory?.rss))}</p></div>
                <div className="bg-indigo-100 dark:bg-indigo-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.external')}</p><p className="font-semibold">{formatBytes(safeNumber(metrics.memory?.external))}</p></div>
              </div>
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }} className="rounded-xl border bg-green-50 text-green-600 border-green-200 dark:bg-gray-800 dark:text-green-400 dark:border-green-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.cachePerformance')}</p>
                  <p className="text-2xl font-bold mt-1">{(safeNumber(metrics.cache?.hitRate) * 100).toFixed(1)}%</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.cacheHitRate')}</p>
                </div>
                <CircleStackIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div className="bg-green-100 dark:bg-green-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.cacheHits')}</p><p className="font-semibold">{formatNumber(safeNumber(metrics.cache?.hits))}</p></div>
                <div className="bg-green-100 dark:bg-green-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.cacheMisses')}</p><p className="font-semibold">{formatNumber(safeNumber(metrics.cache?.misses))}</p></div>
              </div>
            </motion.div>
          </div>

          {/* Database Metrics Section */}
          {dbMetrics && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
              <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.15 }} className="rounded-xl border bg-orange-50 text-orange-600 border-orange-200 dark:bg-gray-800 dark:text-orange-400 dark:border-orange-700 p-6">
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <p className="text-sm font-medium opacity-80">{t('metrics.database', 'Base de donn├®es')}</p>
                    <p className="text-2xl font-bold mt-1">{dbMetrics.database?.sizePretty || 'N/A'}</p>
                    <p className="text-xs mt-1 opacity-60">{t('metrics.dbSize', 'Taille totale')}</p>
                  </div>
                  <TableCellsIcon className="w-10 h-10 opacity-50" />
                </div>
                <div className="grid grid-cols-3 gap-3 text-sm mb-4">
                  <div className="bg-orange-100 dark:bg-orange-900/30 rounded-lg p-3">
                    <p className="opacity-70">{t('metrics.connections', 'Connexions')}</p>
                    <p className="font-semibold">{safeNumber(dbMetrics.connections?.total)}</p>
                  </div>
                  <div className="bg-orange-100 dark:bg-orange-900/30 rounded-lg p-3">
                    <p className="opacity-70">{t('metrics.active', 'Actives')}</p>
                    <p className="font-semibold">{safeNumber(dbMetrics.connections?.active)}</p>
                  </div>
                  <div className="bg-orange-100 dark:bg-orange-900/30 rounded-lg p-3">
                    <p className="opacity-70">{t('metrics.idle', 'Inactives')}</p>
                    <p className="font-semibold">{safeNumber(dbMetrics.connections?.idle)}</p>
                  </div>
                </div>
                <p className="text-xs opacity-60">{t('metrics.queryTime', 'Temps de requ├¬te')}: {dbMetrics.queryTime || 'N/A'}</p>
              </motion.div>

              <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.18 }} className="rounded-xl border bg-orange-50 text-orange-600 border-orange-200 dark:bg-gray-800 dark:text-orange-400 dark:border-orange-700 p-6">
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <p className="text-sm font-medium opacity-80">{t('metrics.tables', 'Tables')}</p>
                    <p className="text-2xl font-bold mt-1">{dbMetrics.tables?.length || 0}</p>
                    <p className="text-xs mt-1 opacity-60">{t('metrics.topTables', 'Tables principales')}</p>
                  </div>
                  <ServerIcon className="w-10 h-10 opacity-50" />
                </div>
                <div className="overflow-x-auto max-h-48">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b border-orange-200 dark:border-orange-700">
                        <th className="text-left py-2 px-2 font-medium opacity-70">{t('metrics.tableName', 'Table')}</th>
                        <th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.rows', 'Lignes')}</th>
                        <th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.deadRows', 'Mortes')}</th>
                      </tr>
                    </thead>
                    <tbody>
                      {dbMetrics.tables?.slice(0, 8).map((table, index) => (
                        <tr key={index} className="border-b border-orange-100 dark:border-orange-800">
                          <td className="py-2 px-2 font-mono text-xs truncate max-w-[120px]">{table.name}</td>
                          <td className="py-2 px-2 text-right font-semibold">{formatNumber(table.rowCount)}</td>
                          <td className="py-2 px-2 text-right opacity-70">{formatNumber(table.deadRows)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </motion.div>
            </div>
          )}

          {/* APM (Application Performance Monitoring) Section */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
              <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.19 }} className="rounded-xl border bg-rose-50 text-rose-600 border-rose-200 dark:bg-gray-800 dark:text-rose-400 dark:border-rose-700 p-6">
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <p className="text-sm font-medium opacity-80">{t('metrics.apm', 'Performance (APM)')}</p>
                    <p className="text-2xl font-bold mt-1">{safeNumber(apmMetrics?.summary?.totalTracked)}</p>
                    <p className="text-xs mt-1 opacity-60">{t('metrics.slowRequests', 'Requ├¬tes lentes')} ({t('metrics.last5min', '5 min')}: {safeNumber(apmMetrics?.summary?.last5min)})</p>
                  </div>
                  <BoltIcon className="w-10 h-10 opacity-50" />
                </div>
                <div className="grid grid-cols-3 gap-3 text-sm mb-4">
                  <div className="bg-rose-100 dark:bg-rose-900/30 rounded-lg p-3">
                    <p className="opacity-70 text-xs">{t('metrics.slow', 'Lentes')}</p>
                    <p className="font-semibold">{safeNumber(apmMetrics?.summary?.severityCounts?.slow)}</p>
                    <p className="text-xs opacity-50">&gt; {apmMetrics?.config?.slowThreshold || 1000}ms</p>
                  </div>
                  <div className="bg-rose-100 dark:bg-rose-900/30 rounded-lg p-3">
                    <p className="opacity-70 text-xs">{t('metrics.verySlow', 'Tr├¿s lentes')}</p>
                    <p className="font-semibold">{safeNumber(apmMetrics?.summary?.severityCounts?.very_slow)}</p>
                    <p className="text-xs opacity-50">&gt; {apmMetrics?.config?.verySlowThreshold || 5000}ms</p>
                  </div>
                  <div className="bg-rose-100 dark:bg-rose-900/30 rounded-lg p-3">
                    <p className="opacity-70 text-xs">{t('metrics.critical', 'Critiques')}</p>
                    <p className="font-semibold text-rose-700 dark:text-rose-300">{safeNumber(apmMetrics?.summary?.severityCounts?.critical)}</p>
                    <p className="text-xs opacity-50">&gt; {apmMetrics?.config?.criticalThreshold || 30000}ms</p>
                  </div>
                </div>
                {safeNumber(apmMetrics?.summary?.totalTracked) === 0 && (
                  <p className="text-xs text-green-600 dark:text-green-400 flex items-center gap-1">
                    <span className="inline-block w-2 h-2 bg-green-500 rounded-full"></span>
                    {t('metrics.noSlowRequests', 'Aucune requ├¬te lente d├®tect├®e')}
                  </p>
                )}
                {safeNumber(apmMetrics?.summary?.avgDuration) > 0 && (
                  <p className="text-xs opacity-60 mt-2">
                    {t('metrics.avgDuration', 'Dur├®e moyenne')}: {safeNumber(apmMetrics?.summary?.avgDuration)}ms
                  </p>
                )}
              </motion.div>

              <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.21 }} className="rounded-xl border bg-rose-50 text-rose-600 border-rose-200 dark:bg-gray-800 dark:text-rose-400 dark:border-rose-700 p-6">
                <div className="flex items-center justify-between mb-4">
                  <div>
                    <p className="text-sm font-medium opacity-80">{t('metrics.slowEndpoints', 'Endpoints lents')}</p>
                    <p className="text-2xl font-bold mt-1">{apmMetrics?.topSlowEndpoints?.length || 0}</p>
                    <p className="text-xs mt-1 opacity-60">{t('metrics.topSlowEndpoints', 'Endpoints les plus lents')}</p>
                  </div>
                  <ClockIcon className="w-10 h-10 opacity-50" />
                </div>
                {apmMetrics?.topSlowEndpoints && apmMetrics.topSlowEndpoints.length > 0 ? (
                  <div className="overflow-x-auto max-h-48">
                    <table className="w-full text-sm">
                      <thead>
                        <tr className="border-b border-rose-200 dark:border-rose-700">
                          <th className="text-left py-2 px-2 font-medium opacity-70">{t('metrics.endpoint', 'Endpoint')}</th>
                          <th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.count', 'Nb')}</th>
                          <th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.avgMs', 'Moy.')}</th>
                          <th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.maxMs', 'Max')}</th>
                        </tr>
                      </thead>
                      <tbody>
                        {apmMetrics.topSlowEndpoints.slice(0, 5).map((item, index) => (
                          <tr key={index} className="border-b border-rose-100 dark:border-rose-800">
                            <td className="py-2 px-2 font-mono text-xs truncate max-w-[150px]" title={item.endpoint}>{item.endpoint}</td>
                            <td className="py-2 px-2 text-right font-semibold">{item.count}</td>
                            <td className="py-2 px-2 text-right opacity-70">{item.avgDuration}ms</td>
                            <td className="py-2 px-2 text-right text-rose-700 dark:text-rose-300">{item.maxDuration}ms</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                ) : (
                  <p className="text-sm opacity-60 text-center py-4">{t('metrics.noData', 'Aucune donn├®e')}</p>
                )}
              </motion.div>
            </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className="rounded-xl border bg-blue-50 text-blue-600 border-blue-200 dark:bg-gray-800 dark:text-blue-400 dark:border-blue-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.httpMethods')}</p>
                  <p className="text-2xl font-bold mt-1">{formatNumber(safeNumber(metrics.requests?.total))}</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.totalApiRequests')}</p>
                </div>
                <ChartBarIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="space-y-2">
                {metrics.requests?.byMethod && Object.entries(metrics.requests.byMethod).map(([method, count]) => (
                  <ProgressBar key={method} label={method} value={safeNumber(count)} max={safeNumber(metrics.requests?.total, 1)} color={method === 'GET' ? 'blue' : method === 'POST' ? 'green' : method === 'PUT' ? 'yellow' : 'red'} />
                ))}
              </div>
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }} className="rounded-xl border bg-yellow-50 text-yellow-600 border-yellow-200 dark:bg-gray-800 dark:text-yellow-400 dark:border-yellow-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.httpStatus')}</p>
                  <p className="text-2xl font-bold mt-1">{formatNumber(safeNumber(metrics.requests?.byStatus?.['2xx']))}</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.successfulRequests')}</p>
                </div>
                <ExclamationTriangleIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="space-y-2">
                {metrics.requests?.byStatus && Object.entries(metrics.requests.byStatus).sort(([a], [b]) => a.localeCompare(b)).map(([status, count]) => (
                  <ProgressBar key={status} label={status} value={safeNumber(count)} max={safeNumber(metrics.requests?.total, 1)} color={status.startsWith('2') ? 'green' : status.startsWith('3') ? 'blue' : status.startsWith('4') ? 'yellow' : 'red'} />
                ))}
              </div>
            </motion.div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }} className="rounded-xl border bg-purple-50 text-purple-600 border-purple-200 dark:bg-gray-800 dark:text-purple-400 dark:border-purple-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.llmUsage')}</p>
                  <p className="text-2xl font-bold mt-1">{formatNumber(safeNumber(metrics.llm?.requests))}</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.llmCalls')}</p>
                </div>
                <SparklesIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="grid grid-cols-2 gap-4 text-sm mb-4">
                <div className="bg-purple-100 dark:bg-purple-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.tokensConsumed')}</p><p className="font-semibold">{formatNumber(safeNumber(metrics.llm?.totalTokens))}</p></div>
                <div className="bg-purple-100 dark:bg-purple-900/30 rounded-lg p-3"><p className="opacity-70">{t('metrics.estimatedCost')}</p><p className="font-semibold">${parseFloat(String(metrics.llm?.estimatedCost || 0)).toFixed(2)}</p></div>
              </div>
              {metrics.llm?.byProvider && Object.keys(metrics.llm.byProvider).length > 0 && (
                <div className="overflow-x-auto max-h-48">
                  <table className="w-full text-sm">
                    <thead><tr className="border-b border-purple-200 dark:border-purple-700"><th className="text-left py-2 px-2 font-medium opacity-70">{t('metrics.model')}</th><th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.calls')}</th></tr></thead>
                    <tbody>
                      {Object.entries(metrics.llm.byProvider)
                        .sort(([, a], [, b]) => {
                          const countA = typeof a === 'object' ? (a.requests || 0) : (a || 0);
                          const countB = typeof b === 'object' ? (b.requests || 0) : (b || 0);
                          return countB - countA;
                        })
                        .map(([model, stats]) => {
                          const count = typeof stats === 'object' ? (stats.requests || 0) : (stats || 0);
                          return (
                            <tr key={model} className="border-b border-purple-100 dark:border-purple-800">
                              <td className="py-2 px-2 font-mono text-xs truncate max-w-[200px]">{model}</td>
                              <td className="py-2 px-2 text-right font-semibold">{formatNumber(count)}</td>
                            </tr>
                          );
                        })}
                    </tbody>
                  </table>
                </div>
              )}
            </motion.div>

            <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.5 }} className="rounded-xl border bg-cyan-50 text-cyan-600 border-cyan-200 dark:bg-gray-800 dark:text-cyan-400 dark:border-cyan-700 p-6">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <p className="text-sm font-medium opacity-80">{t('metrics.topEndpoints')}</p>
                  <p className="text-2xl font-bold mt-1">{metrics.requests?.topEndpoints?.length || 0}</p>
                  <p className="text-xs mt-1 opacity-60">{t('metrics.activeEndpoints')}</p>
                </div>
                <ServerIcon className="w-10 h-10 opacity-50" />
              </div>
              <div className="overflow-x-auto max-h-48">
                <table className="w-full text-sm">
                  <thead><tr className="border-b border-cyan-200 dark:border-cyan-700"><th className="text-left py-2 px-2 font-medium opacity-70">{t('metrics.route')}</th><th className="text-right py-2 px-2 font-medium opacity-70">{t('metrics.calls')}</th></tr></thead>
                  <tbody>
                    {metrics.requests?.topEndpoints?.slice(0, 5).map((endpoint, index) => (
                      <tr key={index} className="border-b border-cyan-100 dark:border-cyan-800">
                        <td className="py-2 px-2 font-mono text-xs truncate max-w-[200px]">{endpoint.endpoint || endpoint.path || 'N/A'}</td>
                        <td className="py-2 px-2 text-right font-semibold">{formatNumber(safeNumber(endpoint.count))}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </motion.div>
          </div>
        </>
      ) : (
        <div className="text-center py-12">
          <ExclamationTriangleIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <p className="text-gray-500">{t('metrics.error')}</p>
          <button onClick={fetchMetrics} className="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">{t('metrics.retry')}</button>
        </div>
      )}
    </motion.div>
  );
};

export default MetricsPage;

/**
 * MissionsPage Component
 * TypeScript version
 */

import { useState, useEffect, useRef, useCallback, FormEvent } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { BriefcaseIcon } from '@heroicons/react/24/outline';
import { useAuth } from '../context/AuthContext';
import { useAuthFetch } from '../hooks/useAuthFetch';
import toast from 'react-hot-toast';
import logger from '../utils/logger.frontend';
import { formatDate } from '../utils/dateFormatter';

import { StatsCards, SearchAndActions } from '../components/MissionsPage';
import Pagination from '../components/Pagination';
import { loadTinyMCE } from '../utils/lazyTinyMCE';
import { SkeletonMissionList } from '../components/ui/Skeleton';
import Breadcrumbs from '../components/Breadcrumbs';
import MissionCard from './MissionCard';
import MissionFormModal from './MissionFormModal';
import MissionPreviewModal from './MissionPreviewModal';

interface Mission {
  id: string;
  Title?: string;
  Content?: string;
  Firm?: string;
  'Firm ID'?: string;
  'Created At'?: string;
  Status?: 'Active' | 'Closed' | 'Draft';
  'Client ID'?: string;
  'Client Name'?: string;
  'Client Type'?: string;
  'Contact ID'?: string;
  'Contact Name'?: string;
  'Contact Email'?: string;
  'Contact Role'?: string;
  'Deal ID'?: string;
  'Deal Title'?: string;
  'Deal Status'?: string;
  [key: string]: unknown;
}

interface Client {
  id: string;
  name: string;
  type: string;
}

interface Contact {
  id: string;
  name: string;
  email?: string;
  role?: string;
}

interface Deal {
  id: string;
  title: string;
  status: string;
  client_name?: string;
}

interface FormData {
  Title: string;
  Content: string;
  Status: 'Active' | 'Closed' | 'Draft';
  'Client ID': string;
  'Contact ID': string;
  'Firm ID': string;
  'Deal ID': string;
}

interface Stats {
  total: number;
  firms: number;
}

// TinyMCE types are declared in src/types/tinymce.d.ts

const MissionsPage = (): JSX.Element => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const { authGet, authPost, authPut, authDelete } = useAuthFetch();
  const [missions, setMissions] = useState<Mission[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [debouncedSearch, setDebouncedSearch] = useState<string>('');
  
  // Server-side pagination state
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [totalCount, setTotalCount] = useState<number>(0);
  const [hasMore, setHasMore] = useState<boolean>(false);
  const pageSize = 12;
  const [showModal, setShowModal] = useState<boolean>(false);
  const [editingMission, setEditingMission] = useState<Mission | null>(null);
  const [formData, setFormData] = useState<FormData>({
    Title: '',
    Content: '',
    Status: 'Active',
    'Client ID': '',
    'Contact ID': '',
    'Firm ID': '',
    'Deal ID': ''
  });
  const editorRef = useRef<{ setContent: (content: string) => void; getContent: () => string } | null>(null);
  const [editorReady, setEditorReady] = useState<boolean>(false);
  const [tinymceLoaded, setTinymceLoaded] = useState<boolean>(false);
  const [previewMission, setPreviewMission] = useState<Mission | null>(null);
  const [clients, setClients] = useState<Client[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [loadingClients, setLoadingClients] = useState<boolean>(false);
  const [loadingContacts, setLoadingContacts] = useState<boolean>(false);
  const [deals, setDeals] = useState<Deal[]>([]);
  const [loadingDeals, setLoadingDeals] = useState<boolean>(false);

  useEffect(() => {
    let mounted = true;
    loadTinyMCE()
      .then(() => {
        if (mounted) setTinymceLoaded(true);
      })
      .catch((err) => {
        logger.error('Failed to load TinyMCE:', err);
      });
    return () => { mounted = false; };
  }, []);

  // Fetch clients when modal opens
  const fetchClients = useCallback(async (): Promise<void> => {
    try {
      setLoadingClients(true);
      const response = await authGet('/api/clients?limit=100&status=active');
      if (response.ok) {
        const data = await response.json();
        setClients(data.data || data || []);
      }
    } catch (error) {
      logger.error('Error fetching clients:', error);
    } finally {
      setLoadingClients(false);
    }
  }, [authGet]);

  // Fetch deals
  const fetchDeals = useCallback(async (): Promise<void> => {
    try {
      setLoadingDeals(true);
      const response = await authGet('/api/deals?limit=100');
      if (response.ok) {
        const data = await response.json();
        setDeals(data.data || []);
      }
    } catch (error) {
      logger.error('Error fetching deals:', error);
    } finally {
      setLoadingDeals(false);
    }
  }, [authGet]);

  // Fetch contacts when client changes
  const fetchContacts = useCallback(async (clientId: string): Promise<void> => {
    if (!clientId) {
      setContacts([]);
      return;
    }
    try {
      setLoadingContacts(true);
      const response = await authGet(`/api/clients/${clientId}/contacts`);
      if (response.ok) {
        const data = await response.json();
        setContacts(data || []);
      }
    } catch (error) {
      logger.error('Error fetching contacts:', error);
    } finally {
      setLoadingContacts(false);
    }
  }, [authGet]);

  // Load clients and deals when modal opens
  useEffect(() => {
    if (showModal) {
      fetchClients();
      fetchDeals();
    }
  }, [showModal, fetchClients, fetchDeals]);

  // Load contacts when client changes
  useEffect(() => {
    if (formData['Client ID']) {
      fetchContacts(formData['Client ID']);
    } else {
      setContacts([]);
    }
  }, [formData['Client ID'], fetchContacts]);

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchTerm);
      setCurrentPage(1); // Reset to first page on search
    }, 300);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  const fetchMissions = useCallback(async (): Promise<void> => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      params.append('page', currentPage.toString());
      params.append('limit', pageSize.toString());
      if (debouncedSearch) params.append('search', debouncedSearch);

      const response = await authGet(`/api/missions?${params.toString()}`);
      if (!response.ok) throw new Error('Failed to fetch missions');
      const data = await response.json();
      
      // Handle paginated response
      if (data.data && data.pagination) {
        setMissions(data.data);
        setTotalCount(data.pagination.totalCount || data.data.length);
        setHasMore(data.pagination.hasMore || false);
      } else {
        // Fallback for non-paginated response
        setMissions(Array.isArray(data) ? data : []);
        setTotalCount(Array.isArray(data) ? data.length : 0);
        setHasMore(false);
      }
    } catch (error) {
      // Don't log or show toast for session expiration - user will be redirected
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching missions:', error);
        toast.error('Erreur lors du chargement des missions');
      }
    } finally {
      setLoading(false);
    }
  }, [authGet, currentPage, debouncedSearch]);

  useEffect(() => {
    fetchMissions();
  }, [fetchMissions]);

  // Handle navigation state for editing a mission from MissionViewPage
  useEffect(() => {
    const state = location.state as { editMissionId?: string } | null;
    if (state?.editMissionId && missions.length > 0) {
      const missionToEdit = missions.find(m => m.id === state.editMissionId);
      if (missionToEdit) {
        handleEdit(missionToEdit);
        // Clear the state to prevent re-opening on refresh
        navigate(location.pathname, { replace: true, state: {} });
      }
    }
  }, [location.state, missions, navigate, location.pathname]);

  // Calculate total pages
  const totalPages = Math.ceil(totalCount / pageSize);

  // Pagination handler
  const goToPage = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  const handleSubmit = async (e: FormEvent<HTMLFormElement>): Promise<void> => {
    e.preventDefault();
    try {
      // Prepare data - convert empty strings to null for optional fields
      const dataToSend: Record<string, unknown> = {
        Title: formData.Title,
        Content: formData.Content,
        Status: formData.Status,
        'Client ID': formData['Client ID'] || null,
        'Contact ID': formData['Contact ID'] || null,
        'Deal ID': formData['Deal ID'] || null
      };
      
      // Add firm_id if admin selected a firm (for both new and edited missions)
      if (formData['Firm ID']) {
        dataToSend['firm_id'] = formData['Firm ID'];
      }

      const response = editingMission
        ? await authPut(`/api/missions/${editingMission.id}`, dataToSend)
        : await authPost('/api/missions', dataToSend);

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.error || 'Failed to save mission');
      }

      toast.success(editingMission ? 'Mission mise ├á jour' : 'Mission cr├®├®e');
      setShowModal(false);
      resetForm();
      fetchMissions();
    } catch (error) {
      logger.error('Error saving mission:', error);
      const errorMessage = error instanceof Error ? error.message : 'Erreur lors de la sauvegarde';
      toast.error(errorMessage);
    }
  };

  const handleDelete = async (id: string): Promise<void> => {
    if (!window.confirm('├ètes-vous s├╗r de vouloir supprimer cette mission ?')) {
      return;
    }
    try {
      const response = await authDelete(`/api/missions/${id}`);
      if (!response.ok) throw new Error('Failed to delete mission');
      toast.success('Mission supprim├®e');
      fetchMissions();
    } catch (error) {
      logger.error('Error deleting mission:', error);
      toast.error('Erreur lors de la suppression');
    }
  };

  const handleEdit = (mission: Mission): void => {
    setEditingMission(mission);
    setFormData({
      Title: mission.Title || '',
      Content: mission.Content || '',
      Status: mission.Status || 'Active',
      'Client ID': mission['Client ID'] || '',
      'Contact ID': mission['Contact ID'] || '',
      'Firm ID': mission['Firm ID'] || '',
      'Deal ID': mission['Deal ID'] || ''
    });
    setShowModal(true);
  };

  const resetForm = (): void => {
    setEditingMission(null);
    setFormData({ Title: '', Content: '', Status: 'Active', 'Client ID': '', 'Contact ID': '', 'Firm ID': '', 'Deal ID': '' });
    setContacts([]);
    const tinymce = window.tinymce as unknown as { init: (config: Record<string, unknown>) => void; get: (id: string) => { remove: () => void; getContent: () => string; setContent: (content: string) => void } | null } | undefined;
    if (tinymce && tinymce.get('missionContentEditor')) {
      tinymce.get('missionContentEditor')?.remove();
    }
    setEditorReady(false);
  };

  // No client-side filtering needed - server handles it
  const filteredMissions = missions;

  const formatMissionDate = (dateString?: string): string => {
    return formatDate(dateString, 'medium') || 'Non d├®finie';
  };

  useEffect(() => {
    const tinymce = window.tinymce as unknown as { init: (config: Record<string, unknown>) => void; get: (id: string) => { remove: () => void; getContent: () => string; setContent: (content: string) => void } | null } | undefined;
    if (!showModal || !tinymceLoaded || !tinymce) return;

    const initEditor = async (): Promise<void> => {
      try {
        if (tinymce.get('missionContentEditor')) {
          tinymce.get('missionContentEditor')?.remove();
        }
        await new Promise(resolve => setTimeout(resolve, 100));

        await tinymce.init({
          selector: '#missionContentEditor',
          height: 400,
          menubar: false,
          plugins: [
            'advlist', 'autolink', 'lists', 'link', 'charmap', 'preview',
            'searchreplace', 'visualblocks', 'code', 'fullscreen',
            'table', 'help', 'wordcount'
          ],
          toolbar: 'undo redo | formatselect | bold italic underline | alignleft aligncenter alignright alignjustify | bullist numlist outdent indent | link | removeformat | code | help',
          content_style: 'body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif; font-size: 14px; }',
          branding: false,
          promotion: false,
          license_key: 'gpl',
          setup: (editor: { on: (event: string, callback: () => void) => void; setContent: (content: string) => void; getContent: () => string }) => {
            editorRef.current = editor;
            editor.on('init', () => {
              setEditorReady(true);
              editor.setContent(formData.Content || '');
            });
            editor.on('change', () => {
              setFormData(prev => ({ ...prev, Content: editor.getContent() }));
            });
          }
        });
      } catch (error) {
        logger.error('TinyMCE initialization error:', error);
        toast.error('Erreur lors de l\'initialisation de l\'├®diteur');
      }
    };

    initEditor();

    return () => {
      const tinymceCleanup = window.tinymce as unknown as { get: (id: string) => { remove: () => void } | null } | undefined;
      if (tinymceCleanup && tinymceCleanup.get('missionContentEditor')) {
        tinymceCleanup.get('missionContentEditor')?.remove();
      }
    };
  }, [showModal, tinymceLoaded]);

  useEffect(() => {
    if (editorReady && editorRef.current && showModal) {
      const currentContent = editorRef.current.getContent();
      if (currentContent !== formData.Content) {
        editorRef.current.setContent(formData.Content || '');
      }
    }
  }, [formData.Content, editorReady, showModal]);

  const stats: Stats = {
    total: missions.length,
    firms: [...new Set(missions.map(m => m.Firm).filter(Boolean))].length
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="p-6 max-w-7xl mx-auto"
    >
      <Breadcrumbs className="mb-4" />
      
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
          {t('missions.title')}
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          {t('missions.subtitle')}
        </p>
      </div>

      <StatsCards stats={stats} missionsCount={totalCount} t={t} />

      <SearchAndActions
        searchTerm={searchTerm}
        onSearchChange={setSearchTerm}
        onRefresh={fetchMissions}
        onAddMission={() => { resetForm(); setShowModal(true); }}
        onReset={() => setSearchTerm('')}
        t={t}
      />

      {/* Top pagination */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('missions.results')}
      />

      {loading ? (
        <SkeletonMissionList count={6} />
      ) : filteredMissions.length === 0 ? (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-12 text-center">
          <BriefcaseIcon className="w-16 h-16 mx-auto text-gray-400 mb-4" />
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
            {t('missions.noMissions')}
          </h3>
          <p className="text-gray-600 dark:text-gray-400">
            {searchTerm ? t('missions.noResults') : t('missions.createFirst')}
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredMissions.map((mission, index) => (
            <MissionCard
              key={mission.id}
              mission={mission}
              index={index}
              onEdit={handleEdit}
              onDelete={handleDelete}
            />
          ))}
        </div>
      )}

      {/* Pagination controls */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('missions.results')}
      />

      {previewMission && (
        <MissionPreviewModal
          mission={previewMission}
          onClose={() => setPreviewMission(null)}
          onEdit={handleEdit}
        />
      )}

      {showModal && (
        <MissionFormModal
          isEditing={!!editingMission}
          formData={formData}
          setFormData={setFormData}
          clients={clients}
          contacts={contacts}
          deals={deals}
          loadingClients={loadingClients}
          loadingContacts={loadingContacts}
          loadingDeals={loadingDeals}
          onSubmit={handleSubmit}
          onClose={() => { setShowModal(false); resetForm(); }}
        />
      )}
    </motion.div>
  );
};

export default MissionsPage;

/**
 * NewTemplatePage Component
 * TypeScript version
 */

import { useState, useEffect, useRef, useCallback, FormEvent, ChangeEvent } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { templateService } from '../utils/templateService';
import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';
import logger from '../utils/logger.frontend';
import AdminFirmSelector from '../components/AdminFirmSelector';

import { loadTinyMCE } from '../utils/lazyTinyMCE';

interface FormData {
  name: string;
  description: string;
  headerContent: string;
  templateContent: string;
  footerContent: string;
  footerHeight: number;
  stylesheet: string;
  status: string;
  popular: boolean;
  tags: string[];
  firmId: string;
}

// TinyMCE types are declared in src/types/tinymce.d.ts

const NewTemplatePage = (): JSX.Element => {
  const navigate = useNavigate();
  const { id } = useParams<{ id?: string }>();
  const headerEditorRef = useRef<{ setContent: (content: string) => void; getContent: () => string } | null>(null);
  const bodyEditorRef = useRef<{ setContent: (content: string) => void; getContent: () => string } | null>(null);
  const footerEditorRef = useRef<{ setContent: (content: string) => void; getContent: () => string } | null>(null);
  const initialContentRef = useRef<{ header: string; body: string; footer: string }>({ header: '', body: '', footer: '' });
  const editorsInitializedRef = useRef<boolean>(false);
  const [editorReady, setEditorReady] = useState<boolean>(false);
  const [tinymceLoaded, setTinymceLoaded] = useState<boolean>(false);
  const [loading, setLoading] = useState<boolean>(false);
  const [dataReady, setDataReady] = useState<boolean>(false);
  const { t } = useTranslation();

  useEffect(() => {
    let mounted = true;
    loadTinyMCE()
      .then(() => { if (mounted) setTinymceLoaded(true); })
      .catch((err) => { logger.error('Failed to load TinyMCE:', err); toast.error('Failed to load editor'); });
    return () => { mounted = false; };
  }, []);

  const [formData, setFormData] = useState<FormData>({
    name: '',
    description: '',
    headerContent: '',
    templateContent: '',
    footerContent: '',
    footerHeight: 25,
    stylesheet: '',
    status: 'Active',
    popular: false,
    tags: [],
    firmId: ''
  });

  useEffect(() => {
    const fetchTemplate = async (): Promise<void> => {
      // Check if we have an extracted template from sessionStorage
      const extractedTemplateJson = sessionStorage.getItem('extractedTemplate');
      if (extractedTemplateJson && !id) {
        try {
          const extractedTemplate = JSON.parse(extractedTemplateJson);
          const newFormData = {
            name: extractedTemplate.name || '',
            description: extractedTemplate.description || '',
            headerContent: extractedTemplate.headerContent || '',
            templateContent: extractedTemplate.templateContent || '',
            footerContent: extractedTemplate.footerContent || '',
            footerHeight: extractedTemplate.footerHeight || 25,
            stylesheet: extractedTemplate.stylesheet || '',
            status: 'Active',
            popular: false,
            tags: extractedTemplate.tags || [],
            firmId: ''
          };
          setFormData(newFormData);
          // Store initial content for editors
          initialContentRef.current = {
            header: newFormData.headerContent,
            body: newFormData.templateContent,
            footer: newFormData.footerContent
          };
          // Clear sessionStorage after loading
          sessionStorage.removeItem('extractedTemplate');
          toast.success(t('templates.extract.templateLoaded'));
          setDataReady(true);
          return;
        } catch (parseError) {
          logger.error('Error parsing extracted template:', parseError);
          sessionStorage.removeItem('extractedTemplate');
        }
      }

      if (!id) {
        // New template - data is ready immediately
        setDataReady(true);
        return;
      }
      try {
        setLoading(true);
        const template = await templateService.getTemplateById(id);
        const newFormData = {
          name: template.Name || '',
          description: template.Description || '',
          headerContent: template.HeaderContent || '',
          templateContent: template.TemplateContent || '',
          footerContent: template.FooterContent || '',
          footerHeight: template.FooterHeight || 25,
          stylesheet: template.Stylesheet || '',
          status: template.Status?.charAt(0).toUpperCase() + template.Status?.slice(1).toLowerCase() || 'Active',
          popular: template.Popular || false,
          tags: template.Tags || [],
          firmId: template.FirmId || template.firm_id || ''
        };
        setFormData(newFormData);
        // Store initial content for editors
        initialContentRef.current = {
          header: newFormData.headerContent,
          body: newFormData.templateContent,
          footer: newFormData.footerContent
        };
        setDataReady(true);
      } catch (error) {
        logger.error('Error fetching template:', error);
        toast.error(t('templates.editor.error.load'));
        navigate('/templates');
      } finally {
        setLoading(false);
      }
    };
    fetchTemplate();
  }, [id, navigate, t]);

  const handleFilePicker = (callback: (url: string, meta: { title: string; alt: string }) => void): void => {
    const input = document.createElement('input');
    input.setAttribute('type', 'file');
    input.setAttribute('accept', 'image/*');
    input.addEventListener('change', function () {
      const file = input.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = function () {
        callback(reader.result as string, { title: file.name, alt: file.name });
      };
    });
    input.click();
  };

  const handleImageUpload = (blobInfo: { base64: () => string; blob: () => Blob }): Promise<string> => {
    return new Promise((resolve, reject) => {
      try {
        if (blobInfo.base64()) {
          resolve('data:' + blobInfo.blob().type + ';base64,' + blobInfo.base64());
        } else {
          const reader = new FileReader();
          reader.readAsDataURL(blobInfo.blob());
          reader.onload = () => {
            const result = reader.result as string;
            const base64data = result.split(',')[1];
            resolve('data:' + blobInfo.blob().type + ';base64,' + base64data);
          };
          reader.onerror = (error) => reject(error);
        }
      } catch (error) {
        reject('Image upload failed');
      }
    });
  };

  // Configuration commune pour les ├®diteurs
  const baseEditorConfig = {
    skin: 'oxide',
    content_css: 'default',
    promotion: false,
    branding: false,
    license_key: 'gpl',
    convert_urls: false,
    relative_urls: false,
    remove_script_host: false,
    base_url: '/tinymce',
    document_base_url: window.location.origin,
    content_style: `body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif; line-height: 1.4; margin: 1rem; }`,
    images_upload_handler: handleImageUpload,
    file_picker_callback: handleFilePicker,
  };

  // Configuration compl├¿te pour tous les ├®diteurs
  const fullEditorConfig = {
    ...baseEditorConfig,
    menubar: true,
    file_picker_types: 'file image media',
    plugins: 'advlist autolink lists link image charmap preview anchor searchreplace visualblocks code fullscreen insertdatetime media table help wordcount',
    toolbar1: 'undo redo | blocks | bold italic | alignleft aligncenter alignright alignjustify | bullist numlist | link image',
    toolbar2: 'formatselect | forecolor backcolor | table | fullscreen code help',
    toolbar_mode: 'sliding',
    toolbar_sticky: true,
  };

  const initEditors = useCallback((): void => {
    const tinymce = window.tinymce;
    if (!tinymce || editorsInitializedRef.current) return;

    editorsInitializedRef.current = true;
    let editorsReady = 0;
    const totalEditors = 3;

    const checkAllEditorsReady = () => {
      editorsReady++;
      if (editorsReady === totalEditors) {
        setEditorReady(true);
      }
    };

    try {
      // Header Editor (complet)
      tinymce.init({
        ...fullEditorConfig,
        height: 250,
        selector: '#headerEditor',
        setup: (editor: { on: (event: string, callback: () => void) => void; setContent: (content: string) => void; getContent: () => string }) => {
          editor.on('init', () => {
            headerEditorRef.current = editor;
            editor.setContent(initialContentRef.current.header || '');
            checkAllEditorsReady();
          });
          editor.on('change', () => {
            const content = editor.getContent();
            setFormData(prev => ({ ...prev, headerContent: content }));
          });
        },
      });

      // Body Editor (complet)
      tinymce.init({
        ...fullEditorConfig,
        height: 400,
        selector: '#bodyEditor',
        setup: (editor: { on: (event: string, callback: () => void) => void; setContent: (content: string) => void; getContent: () => string }) => {
          editor.on('init', () => {
            bodyEditorRef.current = editor;
            editor.setContent(initialContentRef.current.body || '');
            checkAllEditorsReady();
          });
          editor.on('change', () => {
            const content = editor.getContent();
            setFormData(prev => ({ ...prev, templateContent: content }));
          });
        },
      });

      // Footer Editor (complet)
      tinymce.init({
        ...fullEditorConfig,
        height: 250,
        selector: '#footerEditor',
        setup: (editor: { on: (event: string, callback: () => void) => void; setContent: (content: string) => void; getContent: () => string }) => {
          editor.on('init', () => {
            footerEditorRef.current = editor;
            editor.setContent(initialContentRef.current.footer || '');
            checkAllEditorsReady();
          });
          editor.on('change', () => {
            const content = editor.getContent();
            setFormData(prev => ({ ...prev, footerContent: content }));
          });
        },
      });
    } catch (error) {
      logger.error('Error initializing TinyMCE editors:', error);
      editorsInitializedRef.current = false;
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (!loading && tinymceLoaded && dataReady && !editorsInitializedRef.current) {
      initEditors();
    }
    return () => {
      const tinymce = window.tinymce;
      if (tinymce) {
        tinymce.remove('#headerEditor');
        tinymce.remove('#bodyEditor');
        tinymce.remove('#footerEditor');
        headerEditorRef.current = null;
        bodyEditorRef.current = null;
        footerEditorRef.current = null;
        editorsInitializedRef.current = false;
      }
    };
  }, [loading, tinymceLoaded, dataReady, initEditors]);

  const handleSubmit = async (e: FormEvent<HTMLFormElement>): Promise<void> => {
    e.preventDefault();
    if (!formData.name?.trim()) { toast.error(t('templates.editor.validation.nameRequired')); return; }
    if (!formData.templateContent?.trim()) { toast.error(t('templates.editor.validation.contentRequired')); return; }

    try {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const templateData: any = {
        name: formData.name,
        description: formData.description,
        headerContent: formData.headerContent,
        templateContent: formData.templateContent,
        footerContent: formData.footerContent,
        footerHeight: formData.footerHeight,
        stylesheet: formData.stylesheet,
        tags: Array.isArray(formData.tags) ? formData.tags : [],
        popular: Boolean(formData.popular),
        status: formData.status || 'Active'
      };
      
      // Always include firm_id for admin (empty string means global template)
      templateData.firm_id = formData.firmId || '';
      
      if (id) {
        await templateService.updateTemplate(id, templateData);
        toast.success(t('templates.editor.success.update'));
      } else {
        await templateService.createTemplate(templateData);
        toast.success(t('templates.editor.success.create'));
      }
      navigate('/templates');
    } catch (error) {
      logger.error('Error saving template:', error);
      toast.error(t(id ? 'templates.editor.error.update' : 'templates.editor.error.create'));
    }
  };

  const handleChange = (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>): void => {
    const target = e.target;
    const name = target.name;
    const value = target.type === 'checkbox' ? (target as HTMLInputElement).checked : target.value;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="max-w-4xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">{t(id ? 'templates.editor.title.edit' : 'templates.editor.title.new')}</h1>
          <button onClick={() => navigate('/templates')} className="px-4 py-2 text-sm text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white">{t('common.cancel')}</button>
        </div>

        {loading ? (
          <div className="flex justify-center items-center py-12"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div></div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Admin Firm Selector - visible for admins */}
            <AdminFirmSelector
              selectedFirmId={formData.firmId}
              onFirmChange={(firmId) => setFormData({ ...formData, firmId })}
              className="mb-2"
              t={t}
            />

            <div>
              <label htmlFor="name" className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('templates.editor.name.label')}</label>
              <input type="text" id="name" name="name" required value={formData.name} onChange={handleChange} placeholder={t('templates.editor.name.placeholder')} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white" />
            </div>

            <div>
              <label htmlFor="status" className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('templates.editor.statusField.label')}</label>
              <select 
                id="status" 
                name="status" 
                value={formData.status} 
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white"
              >
                <option value="Active">{t('templates.editor.statusField.active')}</option>
                <option value="Inactive">{t('templates.editor.statusField.inactive')}</option>
              </select>
            </div>

            <div>
              <label htmlFor="description" className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('templates.editor.description.label')}</label>
              <textarea id="description" name="description" rows={3} required value={formData.description} onChange={handleChange} placeholder={t('templates.editor.description.placeholder')} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white" />
            </div>

            <div className="mt-4">
              <label htmlFor="stylesheet" className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('templates.editor.stylesheet.label')}</label>
              <textarea id="stylesheet" name="stylesheet" rows={4} placeholder={t('templates.editor.stylesheet.placeholder')} className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white" value={formData.stylesheet || ''} onChange={(e) => setFormData({ ...formData, stylesheet: e.target.value })} />
            </div>

            {/* Header Editor */}
            <div>
              <label htmlFor="headerEditor" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                {t('templates.editor.header.label')}
                <span className="ml-2 text-xs text-gray-500 dark:text-gray-400">({t('templates.editor.header.hint')})</span>
              </label>
              <div className="min-h-[250px] border rounded-md bg-white dark:bg-gray-800">
                <textarea id="headerEditor" defaultValue={formData.headerContent} className="hidden" />
              </div>
            </div>

            {/* Body Editor */}
            <div>
              <label htmlFor="bodyEditor" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                {t('templates.editor.content.label')}
              </label>
              <div className="min-h-[400px] border rounded-md bg-white dark:bg-gray-800">
                <textarea id="bodyEditor" defaultValue={formData.templateContent} className="hidden" />
              </div>
            </div>

            {/* Footer Editor */}
            <div>
              <label htmlFor="footerEditor" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                {t('templates.editor.footer.label')}
                <span className="ml-2 text-xs text-gray-500 dark:text-gray-400">({t('templates.editor.footer.hint')})</span>
              </label>
              <div className="min-h-[250px] border rounded-md bg-white dark:bg-gray-800">
                <textarea id="footerEditor" defaultValue={formData.footerContent} className="hidden" />
              </div>
            </div>

            {/* Footer Height */}
            <div>
              <label htmlFor="footerHeight" className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                {t('templates.editor.footerHeight.label', 'Hauteur du footer (mm)')}
              </label>
              <input 
                type="number" 
                id="footerHeight" 
                name="footerHeight" 
                min="10" 
                max="250" 
                value={formData.footerHeight} 
                onChange={(e) => setFormData({ ...formData, footerHeight: parseInt(e.target.value) || 25 })} 
                className="mt-1 block w-32 rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white" 
              />
              <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">{t('templates.editor.footerHeight.hint', 'Hauteur r├®serv├®e pour le footer dans le PDF (10-250mm)')}</p>
            </div>

            <div className="flex items-center">
              <input type="checkbox" id="popular" name="popular" checked={formData.popular} onChange={handleChange} className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300 rounded" />
              <label htmlFor="popular" className="ml-2 block text-sm text-gray-700 dark:text-gray-300">{t('templates.editor.popular.label')}</label>
            </div>

            <div className="flex justify-end space-x-4">
              <button type="button" onClick={() => navigate('/templates')} className="px-4 py-2 border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 bg-white hover:bg-gray-50 dark:bg-gray-700 dark:text-gray-300 dark:border-gray-600 dark:hover:bg-gray-600">{t('common.cancel')}</button>
              <button type="submit" disabled={!editorReady} className="px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 disabled:opacity-50">{t(id ? 'templates.editor.title.edit' : 'templates.editor.title.new')}</button>
            </div>
          </form>
        )}
      </motion.div>
    </div>
  );
};

export default NewTemplatePage;

/**
 * Profile Matching Page
 * Find best matching CVs for a mission
 */

import { useState, useEffect, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import toast from 'react-hot-toast';
import {
  MagnifyingGlassIcon,
  UserGroupIcon,
  DocumentTextIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';
import { useResume } from '../context/ResumeContext';
import { findMatchingProfiles, getMissions, clearMissionKeywordsCache, analyzeProfileForMission } from '../utils/profileMatchingService';
import type { 
  Mission, 
  ProfileMatchingResponse, 
  ProfileMatchWeights,
  MissionKeywords,
  DetailedProfileAnalysisResponse
} from '../types/entities';
import logger from '../utils/logger.frontend';
import Breadcrumbs from '../components/Breadcrumbs';
import ProfileMatchCard from './ProfileMatchCard';
import ProfileMatchSearchPanel from './ProfileMatchSearchPanel';

const DEFAULT_WEIGHTS: ProfileMatchWeights = {
  skills: 40,
  tools: 25,
  industries: 20,
  softSkills: 15
};

const ProfileMatchingPage = (): JSX.Element => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { setCurrentResume, resumes } = useResume();

  // State
  const [missions, setMissions] = useState<Mission[]>([]);
  const [selectedMissionId, setSelectedMissionId] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [loadingMissions, setLoadingMissions] = useState(true);
  const [results, setResults] = useState<ProfileMatchingResponse | null>(null);
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [expandedProfile, setExpandedProfile] = useState<string | null>(null);

  // Detailed analysis state
  const [analyzingProfile, setAnalyzingProfile] = useState<string | null>(null);
  const [detailedAnalysis, setDetailedAnalysis] = useState<Record<string, DetailedProfileAnalysisResponse>>({});

  // Search options
  const [limit, setLimit] = useState(10);
  const [minScore, setMinScore] = useState(0);
  const [weights, setWeights] = useState<ProfileMatchWeights>(DEFAULT_WEIGHTS);

  // Load missions on mount
  useEffect(() => {
    const loadMissions = async () => {
      try {
        setLoadingMissions(true);
        const data = await getMissions();
        // Ensure data is always an array
        const missionsArray = Array.isArray(data) ? data : [];
        setMissions(missionsArray);
        if (missionsArray.length > 0) {
          setSelectedMissionId(missionsArray[0].id);
        }
      } catch (error) {
        logger.error('Error loading missions:', error);
        toast.error(t('profileMatching.errors.loadMissions'));
      } finally {
        setLoadingMissions(false);
      }
    };
    loadMissions();
  }, [t]);

  const selectedMission = useMemo(() => 
    Array.isArray(missions) ? missions.find(m => m.id === selectedMissionId) : undefined,
    [missions, selectedMissionId]
  );

  const handleSearch = async () => {
    if (!selectedMissionId) {
      toast.error(t('profileMatching.errors.selectMission'));
      return;
    }

    try {
      setLoading(true);
      setResults(null);

      const data = await findMatchingProfiles(selectedMissionId, {
        limit,
        minScore,
        weights
      });

      setResults(data);

      if (data.profiles.length === 0) {
        toast(t('profileMatching.noResults'), { icon: '­ƒöì' });
      } else {
        toast.success(t('profileMatching.resultsFound', { count: data.profiles.length }));
      }
    } catch (error) {
      logger.error('Error searching profiles:', error);
      toast.error(t('profileMatching.errors.search'));
    } finally {
      setLoading(false);
    }
  };

  const handleRefreshKeywords = async () => {
    if (!selectedMissionId) return;

    try {
      await clearMissionKeywordsCache(selectedMissionId);
      toast.success(t('profileMatching.keywordsRefreshed'));
      // Re-run search to get fresh keywords
      if (results) {
        handleSearch();
      }
    } catch (error) {
      logger.error('Error refreshing keywords:', error);
      toast.error(t('profileMatching.errors.refreshKeywords'));
    }
  };

  const handleDetailedAnalysis = async (resumeId: string) => {
    if (!selectedMissionId) return;

    // Check if already analyzed
    if (detailedAnalysis[resumeId]) {
      setExpandedProfile(resumeId);
      return;
    }

    try {
      setAnalyzingProfile(resumeId);
      const result = await analyzeProfileForMission(selectedMissionId, resumeId);
      setDetailedAnalysis(prev => ({ ...prev, [resumeId]: result }));
      setExpandedProfile(resumeId);
      toast.success(t('profileMatching.analysisComplete'));
    } catch (error) {
      logger.error('Error analyzing profile:', error);
      toast.error(t('profileMatching.errors.analysis'));
    } finally {
      setAnalyzingProfile(null);
    }
  };

  const handleViewResume = (resumeId: string) => {
    navigate(`/resumes/${resumeId}`);
  };


  const renderKeywordsBadges = (keywords: MissionKeywords) => {
    const categories = [
      { key: 'skills', label: t('profileMatching.categories.skills'), items: keywords.skills, color: 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300' },
      { key: 'tools', label: t('profileMatching.categories.tools'), items: keywords.tools, color: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300' },
      { key: 'industries', label: t('profileMatching.categories.industries'), items: keywords.industries, color: 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-300' },
      { key: 'softSkills', label: t('profileMatching.categories.softSkills'), items: keywords.softSkills, color: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300' }
    ];

    return (
      <div className="space-y-3">
        {categories.map(cat => cat.items && cat.items.length > 0 && (
          <div key={cat.key}>
            <span className="text-xs font-medium text-gray-500 dark:text-gray-400">{cat.label}:</span>
            <div className="flex flex-wrap gap-1 mt-1">
              {cat.items.map((item, idx) => (
                <span key={idx} className={`text-xs px-2 py-0.5 rounded-full ${cat.color}`}>
                  {item}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>
    );
  };

  // Check if any loading state is active
  const isProcessing = loading || analyzingProfile !== null;

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="p-6 max-w-6xl mx-auto relative"
    >
      {/* Blur overlay during processing */}
      <AnimatePresence>
        {isProcessing && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] flex items-center justify-center bg-black/30 backdrop-blur-sm"
          >
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl p-8 flex flex-col items-center gap-4 max-w-md mx-4">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-blue-200 dark:border-blue-900 rounded-full"></div>
                <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
              </div>
              <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                {loading ? t('profileMatching.searchingProfiles') : t('profileMatching.analyzingProfile')}
              </h3>
              <p className="text-sm text-gray-500 dark:text-gray-400 text-center">
                {loading 
                  ? t('profileMatching.searchingProfilesDescription')
                  : t('profileMatching.analyzingProfileDescription')
                }
              </p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <Breadcrumbs className="mb-4" />

      {/* Header */}
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-3">
          <UserGroupIcon className="w-8 h-8 text-blue-600" />
          {t('profileMatching.title')}
        </h1>
        <p className="text-gray-600 dark:text-gray-400 mt-1">
          {t('profileMatching.subtitle')}
        </p>
      </div>

      {/* Search Panel */}
      <ProfileMatchSearchPanel
        missions={missions}
        selectedMissionId={selectedMissionId}
        setSelectedMissionId={setSelectedMissionId}
        selectedMission={selectedMission}
        loadingMissions={loadingMissions}
        loading={loading}
        showAdvanced={showAdvanced}
        setShowAdvanced={setShowAdvanced}
        limit={limit}
        setLimit={setLimit}
        minScore={minScore}
        setMinScore={setMinScore}
        weights={weights}
        setWeights={setWeights}
        hasResults={!!results}
        onSearch={handleSearch}
        onRefreshKeywords={handleRefreshKeywords}
      />

      {/* Results */}
      {results && (
        <div className="space-y-6">
          {/* Mission keywords */}
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-6">
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
              <SparklesIcon className="w-5 h-5 text-yellow-500" />
              {t('profileMatching.extractedKeywords')}
            </h2>
            {renderKeywordsBadges(results.missionKeywords)}
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-3">
              {t('profileMatching.scannedResumes', { count: results.totalResumesScanned })}
            </p>
          </div>

          {/* Profile list */}
          <div>
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-4 flex items-center gap-2">
              <DocumentTextIcon className="w-5 h-5 text-blue-500" />
              {t('profileMatching.results')} ({results.profiles.length})
            </h2>

            {results.profiles.length === 0 ? (
              <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-8 text-center">
                <UserGroupIcon className="w-12 h-12 text-gray-400 mx-auto mb-3" />
                <p className="text-gray-500 dark:text-gray-400">{t('profileMatching.noProfilesFound')}</p>
              </div>
            ) : (
              <div className="space-y-3">
                {results.profiles.map((profile, index) => (
                  <ProfileMatchCard
                    key={profile.resumeId}
                    profile={profile}
                    index={index}
                    isExpanded={expandedProfile === profile.resumeId}
                    onToggleExpand={setExpandedProfile}
                    detailedAnalysis={detailedAnalysis[profile.resumeId]}
                    analyzingProfile={analyzingProfile}
                    onDetailedAnalysis={handleDetailedAnalysis}
                    onViewResume={handleViewResume}
                  />
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Empty state */}
      {!results && !loading && (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 p-12 text-center">
          <MagnifyingGlassIcon className="w-16 h-16 text-gray-300 dark:text-gray-600 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
            {t('profileMatching.emptyState.title')}
          </h3>
          <p className="text-gray-500 dark:text-gray-400 max-w-md mx-auto">
            {t('profileMatching.emptyState.description')}
          </p>
        </div>
      )}
    </motion.div>
  );
};

export default ProfileMatchingPage;

/**
 * ResumeAnalysisPage Component
 * Dedicated page for resume analysis step
 */

import { useEffect, useState, useCallback } from 'react';
import { useParams, useNavigate, Link, useLocation } from 'react-router-dom';
import { useResume } from '../context/ResumeContext';
import { motion } from 'framer-motion';
