/**
 * ResumesPage Component
 * TypeScript version
 */

import { useEffect, useState, useMemo, useCallback, MouseEvent } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useResume } from '../context/ResumeContext';
import { motion, AnimatePresence } from 'framer-motion';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../context/AuthContext';
import { useAuthFetch } from '../hooks/useAuthFetch';
import logger from '../utils/logger.frontend';
import { 
  DocumentTextIcon, 
  CalendarIcon, 
  ChartBarIcon,
  XMarkIcon,
  TrashIcon,
  ArrowDownTrayIcon,
  EyeIcon,
  BuildingOfficeIcon,
  ListBulletIcon,
  FolderIcon
} from '@heroicons/react/24/outline';
import { formatDate } from '../utils/dateFormatter';

import { StatsCards, SearchAndActions, ManageResumeDealsModal, DealsGroupedView } from '../components/ResumesPage';
import Pagination from '../components/Pagination';
import { SkeletonResumeList } from '../components/ui/Skeleton';
import Breadcrumbs from '../components/Breadcrumbs';
import ConsentBadge from '../components/ConsentBadge';

// Import centralized types
import { Resume } from '../types/entities';

interface TagsByCategory {
  Skills: string[];
  Industries: string[];
  Tools: string[];
  'Soft Skills': string[];
  [key: string]: string[];
}

interface ExpandedCategories {
  [key: string]: boolean;
}

interface Stats {
  total: number;
  improved: number;
  processing: number;
  avgScore: number;
}

const filterContentVariants = {
  expanded: {
    height: "auto",
    opacity: 1,
    marginBottom: "2rem",
    transition: {
      height: { duration: 0.3 },
      opacity: { duration: 0.2 }
    }
  },
  collapsed: {
    height: 0,
    opacity: 0,
    marginBottom: 0,
    transition: {
      height: { duration: 0.3 },
      opacity: { duration: 0.2 }
    }
  }
};

const tagColorMap: Record<string, string> = {
  'Skills': 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300',
  'Industries': 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-300',
  'Tools': 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300',
  'Soft Skills': 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300'
};

const tagFilterColors: Record<string, { selected: string; unselected: string }> = {
  'Skills': {
    selected: 'bg-blue-500 text-white ring-2 ring-blue-300 dark:ring-blue-700',
    unselected: 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300 hover:bg-blue-100 dark:hover:bg-blue-900/50'
  },
  'Industries': {
    selected: 'bg-purple-500 text-white ring-2 ring-purple-300 dark:ring-purple-700',
    unselected: 'bg-purple-50 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300 hover:bg-purple-100 dark:hover:bg-purple-900/50'
  },
  'Tools': {
    selected: 'bg-green-500 text-white ring-2 ring-green-300 dark:ring-green-700',
    unselected: 'bg-green-50 text-green-700 dark:bg-green-900/30 dark:text-green-300 hover:bg-green-100 dark:hover:bg-green-900/50'
  },
  'Soft Skills': {
    selected: 'bg-yellow-500 text-white ring-2 ring-yellow-300 dark:ring-yellow-700',
    unselected: 'bg-yellow-50 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300 hover:bg-yellow-100 dark:hover:bg-yellow-900/50'
  }
};

function classNames(...classes: (string | boolean | undefined)[]): string {
  return classes.filter(Boolean).join(' ');
}

const ResumesPage = (): JSX.Element => {
  const { user: authUser } = useAuth();
  const { deleteResume, deleting } = useResume();
  const { authGet } = useAuthFetch();
  const navigate = useNavigate();
  const { t } = useTranslation();

  // Server-side pagination state
  const [resumes, setResumes] = useState<Resume[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [totalCount, setTotalCount] = useState<number>(0);
  const [hasMore, setHasMore] = useState<boolean>(false);
  const pageSize = 20;

  // Global stats from backend
  const [globalStats, setGlobalStats] = useState<Stats>({ total: 0, improved: 0, processing: 0, avgScore: 0 });

  // Filter state
  const [selectedTags, setSelectedTags] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [debouncedSearch, setDebouncedSearch] = useState<string>('');
  const [isFilterExpanded, setIsFilterExpanded] = useState<boolean>(true);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<boolean>(false);
  const [resumeToDelete, setResumeToDelete] = useState<Resume | null>(null);
  const [expandedCategories, setExpandedCategories] = useState<ExpandedCategories>({});
  const [allTags, setAllTags] = useState<TagsByCategory>({ Skills: [], Industries: [], Tools: [], 'Soft Skills': [] });
  const location = useLocation();
  const [viewMode, setViewMode] = useState<'list' | 'byDeal'>(
    (location.state as { viewMode?: string } | null)?.viewMode === 'list' ? 'list' : 'byDeal'
  );

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchQuery);
      setCurrentPage(1); // Reset to first page on search
    }, 300);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Fetch resumes with server-side pagination
  const fetchResumes = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      params.append('page', currentPage.toString());
      params.append('limit', pageSize.toString());
      if (debouncedSearch) params.append('search', debouncedSearch);

      const response = await authGet(`/api/resumes?${params.toString()}`);
      if (!response.ok) throw new Error('Failed to fetch resumes');
      
      const data = await response.json();
      
      // Handle paginated response
      if (data.data && data.pagination) {
        setResumes(data.data);
        setTotalCount(data.pagination.totalCount || data.data.length);
        setHasMore(data.pagination.hasMore || false);
      } else {
        // Fallback for non-paginated response
        setResumes(Array.isArray(data) ? data : []);
        setTotalCount(Array.isArray(data) ? data.length : 0);
        setHasMore(false);
      }
    } catch (error) {
      // Don't log session expiration errors - user will be redirected
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching resumes:', error);
      }
    } finally {
      setLoading(false);
    }
  }, [authGet, currentPage, debouncedSearch]);

  useEffect(() => {
    fetchResumes();
  }, [fetchResumes]);

  // Fetch global stats from backend (once on mount and after delete)
  const fetchGlobalStats = useCallback(async () => {
    try {
      const response = await authGet('/api/resumes/stats');
      if (response.ok) {
        const data = await response.json();
        setGlobalStats({
          total: data.resumes?.total || 0,
          improved: data.resumes?.improved || 0,
          processing: 0, // Not tracked in stats endpoint, will be calculated from current page as fallback
          avgScore: data.scores?.averageImproved || data.scores?.averageOriginal || 0
        });
      }
    } catch (error) {
      logger.error('Error fetching global stats:', error);
    }
  }, [authGet]);

  useEffect(() => {
    fetchGlobalStats();
  }, [fetchGlobalStats]);

  // Fetch all available cleaned tags from backend
  // Uses /api/tags/cleaned which has optimized SQL aggregation and caching
  useEffect(() => {
    const fetchAllTags = async () => {
      try {
        const scope = viewMode === 'byDeal' ? 'grouped-by-deal' : 'default';
        const response = await authGet(`/api/tags/cleaned?scope=${scope}`);
        if (response.ok) {
          const tags = await response.json();
          setAllTags(tags);
        }
      } catch (error) {
        logger.error('Error fetching cleaned tags:', error);
      }
    };
    fetchAllTags();
  }, [authGet, viewMode]);

  // Calculate total pages
  const totalPages = Math.ceil(totalCount / pageSize);

  // Use tags from backend API instead of extracting from current page
  const tagsByCategory = allTags;

  // Client-side tag filtering (tags are complex to filter server-side)
  // Priority: Cleaned tags > Raw tags
  const filteredResumes = useMemo((): Resume[] => {
    if (selectedTags.length === 0) return resumes;
    
    return resumes.filter(resume => {
      // Helper to parse JSON tags safely
      const parseTags = (value: unknown): string[] => {
        if (!value) return [];
        try {
          if (typeof value === 'string') {
            const parsed = JSON.parse(value);
            return Array.isArray(parsed) ? parsed.map(t => String(t).toLowerCase().trim()) : [];
          }
          if (Array.isArray(value)) {
            return value.map(t => String(t).toLowerCase().trim());
          }
        } catch {
          // Skip invalid JSON
        }
        return [];
      };
      
      // Get tags from cleaned fields first (with underscore), fallback to raw
      // Backend returns: Skills_cleaned, Industries_cleaned, Tools_cleaned, Soft Skills_cleaned
      const skills = parseTags(resume['Skills_cleaned' as keyof Resume]) || parseTags(resume['Skills' as keyof Resume]);
      const industries = parseTags(resume['Industries_cleaned' as keyof Resume]) || parseTags(resume['Industries' as keyof Resume]);
      const tools = parseTags(resume['Tools_cleaned' as keyof Resume]) || parseTags(resume['Tools' as keyof Resume]);
      const softSkills = parseTags(resume['Soft Skills_cleaned' as keyof Resume]) || parseTags(resume['Soft Skills' as keyof Resume]);
      
      const resumeTags = [...skills, ...industries, ...tools, ...softSkills];
      
      // Compare in lowercase for case-insensitive matching
      return selectedTags.every(selectedTag => 
        resumeTags.some(resumeTag => resumeTag === selectedTag.toLowerCase().trim())
      );
    });
  }, [resumes, selectedTags]);

  const handleTagClick = (tag: string): void => {
    setSelectedTags(prev => 
      prev.includes(tag) 
        ? prev.filter(t => t !== tag)
        : [...prev, tag]
    );
  };

  const handleResumeClick = (resume: Resume): void => {
    navigate(`/resumes/${resume.id}/analysis`);
  };

  const openDeleteConfirm = (resume: Resume, event: MouseEvent): void => {
    event.stopPropagation();
    setResumeToDelete(resume);
    setShowDeleteConfirm(true);
  };

  const closeDeleteConfirm = (): void => {
    setShowDeleteConfirm(false);
    setResumeToDelete(null);
  };

  const confirmDeleteResume = async (): Promise<void> => {
    if (resumeToDelete) {
      try {
        await deleteResume(resumeToDelete.id);
        // Refresh the list and stats after successful deletion
        await fetchResumes();
        await fetchGlobalStats();
      } catch (error) {
        logger.error("Failed to delete resume from page:", error);
      }
      closeDeleteConfirm();
    }
  };

  const clearFilters = (): void => {
    setSelectedTags([]);
    setSearchQuery('');
  };

  const handleDownloadResume = async (resume: Resume, event: MouseEvent): Promise<void> => {
    event.stopPropagation();
    try {
      const response = await authGet(`/api/resumes/${resume.id}/download`);
      if (!response.ok) {
        const error = await response.json();
        logger.error('Download failed:', error);
        return;
      }
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      // Get filename from Content-Disposition header or fallback to resume data
      const contentDisposition = response.headers.get('Content-Disposition');
      let filename = resume['Resume File']?.[0]?.filename || resume['File Name'] || resume.Name || 'resume';
      if (contentDisposition) {
        const match = contentDisposition.match(/filename="?([^";\n]+)"?/);
        if (match) filename = decodeURIComponent(match[1]);
      }
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      logger.error('Error downloading resume:', error);
    }
  };

  const getTagCategory = (tag: string): string => {
    for (const [category, tags] of Object.entries(tagsByCategory)) {
      if (tags.includes(tag)) return category;
    }
    return 'Skills';
  };

  const formatResumeDate = (dateString?: string): string => {
    return formatDate(dateString, 'medium') || 'Invalid date';
  };

  // Stats from backend API (global stats, not page-specific)
  // Processing count is calculated from current page as it's not tracked in stats endpoint
  const stats: Stats = {
    total: globalStats.total || totalCount,
    improved: globalStats.improved,
    processing: resumes.filter(r => r.Status?.toLowerCase() === 'processing' || r.Status?.toLowerCase() === 'analyzing').length,
    avgScore: globalStats.avgScore
  };

  // Pagination handlers
  const goToPage = (page: number) => {
    if (page >= 1 && page <= totalPages) {
      setCurrentPage(page);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="p-6 max-w-7xl mx-auto"
    >
      <Breadcrumbs className="mb-4" />
      
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
          {t('resumes.title')}
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          {t('resumes.subtitle')}
        </p>
      </div>

      <StatsCards stats={stats} t={t} />

      {/* View mode toggle */}
      <div className="flex items-center gap-2 mb-4">
        <span className="text-sm text-gray-600 dark:text-gray-400">{t('resumes.viewMode', 'Affichage')} :</span>
        <div className="flex bg-gray-100 dark:bg-gray-800 rounded-lg p-0.5">
          <button
            onClick={() => setViewMode('byDeal')}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
              viewMode === 'byDeal'
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm'
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'
            }`}
          >
            <FolderIcon className="w-4 h-4" />
            {t('resumes.viewByDeal', 'Par affaire')}
          </button>
          <button
            onClick={() => setViewMode('list')}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-colors ${
              viewMode === 'list'
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm'
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300'
            }`}
          >
            <ListBulletIcon className="w-4 h-4" />
            {t('resumes.viewList', 'Liste')}
          </button>
        </div>
      </div>

      {viewMode === 'byDeal' ? (
        <DealsGroupedView allTags={allTags} />
      ) : (
      <>
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-6">
        <SearchAndActions
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          isFilterExpanded={isFilterExpanded}
          onToggleFilter={() => setIsFilterExpanded(!isFilterExpanded)}
          selectedTagsCount={selectedTags.length}
          onRefresh={fetchResumes}
          onUpload={() => navigate('/upload?new')}
          onBatchUpload={authUser?.role?.toLowerCase() === 'admin' ? () => navigate('/batch-upload') : undefined}
          onReset={clearFilters}
          t={t}
        />

        <AnimatePresence>
          {isFilterExpanded && totalCount > 0 && (
            <motion.div
              variants={filterContentVariants}
              initial="collapsed"
              animate="expanded"
              exit="collapsed"
              className="px-4 pb-4 border-t border-gray-200 dark:border-gray-700"
            >
              <div className="pt-4 space-y-4">
                {selectedTags.length > 0 && (
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-sm text-gray-600 dark:text-gray-400">{t('resumes.activeFilters')}:</span>
                    <div className="flex flex-wrap gap-2">
                      {selectedTags.map(tag => {
                        const category = getTagCategory(tag);
                        return (
                          <span key={tag} className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-sm ${tagColorMap[category]}`}>
                            {tag}
                            <button onClick={() => handleTagClick(tag)} className="hover:opacity-70">
                              <XMarkIcon className="w-3 h-3" />
                            </button>
                          </span>
                        );
                      })}
                    </div>
                    </div>
                )}
                {Object.entries(tagsByCategory).map(([category, tags]) => {
                  const isExpanded = expandedCategories[category];
                  const displayedTags = isExpanded ? tags : tags.slice(0, 15);
                  const hasMore = tags.length > 15;
                  
                  return tags.length > 0 && (
                    <div key={category}>
                      <h3 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                        {t(`resumes.filters.${category.toLowerCase().replace(' ', '')}`)}
                      </h3>
                      <div className="flex flex-wrap gap-2">
                        {displayedTags.map((tag) => (
                          <button
                            key={tag}
                            onClick={() => handleTagClick(tag)}
                            className={`inline-flex items-center px-3 py-1 rounded-full text-sm transition-all ${
                              selectedTags.includes(tag)
                                ? tagFilterColors[category]?.selected || 'bg-blue-500 text-white'
                                : tagFilterColors[category]?.unselected || 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300'
                            }`}
                          >
                            {tag}
                          </button>
                        ))}
                        {hasMore && (
                          <button
                            onClick={() => setExpandedCategories(prev => ({ ...prev, [category]: !isExpanded }))}
                            className="text-sm text-blue-600 dark:text-blue-400 hover:underline py-1 font-medium"
                          >
                            {isExpanded ? t('resumes.showLess') : `+${tags.length - 15} ${t('resumes.more')}`}
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Top pagination info */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('resumes.results')}
      />

      {loading ? (
        <SkeletonResumeList count={6} />
      ) : filteredResumes.length === 0 ? (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-12 text-center">
          <DocumentTextIcon className="w-16 h-16 mx-auto text-gray-400 mb-4" />
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
            {t('resumes.noResults')}
          </h3>
          <p className="text-gray-600 dark:text-gray-400">
            {searchQuery || selectedTags.length > 0 ? t('resumes.noResultsFiltered') : t('resumes.uploadFirst')}
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredResumes.map((resume, index) => (
            <motion.div
              key={resume.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
              className="bg-white dark:bg-gray-800 rounded-lg shadow-md border border-gray-200 dark:border-gray-700 hover:shadow-lg transition-shadow overflow-hidden cursor-pointer"
              onClick={() => handleResumeClick(resume)}
            >
              <div className="p-4 border-b border-gray-200 dark:border-gray-700">
                <div className="flex items-start justify-between">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <DocumentTextIcon className="w-5 h-5 text-gray-400 flex-shrink-0" />
                      <h3 className="font-semibold text-gray-900 dark:text-white truncate">
                        {resume.Name || resume['Resume File']?.[0]?.filename || t('resumes.untitled')}
                      </h3>
                    </div>
                    {resume.Title && (
                      <p className="text-sm text-gray-600 dark:text-gray-400 mt-1 truncate">{resume.Title}</p>
                    )}
                  </div>
                  <span className={classNames(
                    'ml-2 px-2 py-1 rounded-full text-xs font-medium flex-shrink-0',
                    resume.Status?.toLowerCase() === 'improved' 
                      ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300'
                      : resume.Status?.toLowerCase() === 'analyzed'
                      ? 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300'
                      : resume.Status?.toLowerCase() === 'processing'
                      ? 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300'
                      : resume.Status?.toLowerCase() === 'pending'
                      ? 'bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-300'
                      : resume.Status?.toLowerCase() === 'error' || resume.Status?.toLowerCase() === 'failed'
                      ? 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'
                      : resume.Status?.toLowerCase() === 'archived'
                      ? 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300'
                      : 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300'
                  )}>
                    {t(`resumes.status.${resume.Status?.toLowerCase() || 'new'}`)}
                  </span>
                </div>
              </div>

              <div className="p-4">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <ChartBarIcon className="w-5 h-5 text-gray-400" />
                    <span className="text-sm text-gray-600 dark:text-gray-400">{t('resumes.score_label')}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    {resume['Improved Global Rating'] && resume['Improved Global Rating'] !== resume['Global Rating'] ? (
                      <>
                        <span className="text-sm text-gray-400 line-through">{resume['Global Rating'] != null ? `${resume['Global Rating']}%` : '0%'}</span>
                        <span className="text-lg font-bold text-green-600 dark:text-green-400">{resume['Improved Global Rating'] != null ? `${resume['Improved Global Rating']}%` : '0%'}</span>
                      </>
                    ) : (
                      <span className="text-lg font-bold text-gray-900 dark:text-white">{resume['Global Rating'] != null ? `${resume['Global Rating']}%` : '0%'}</span>
                    )}
                  </div>
                </div>

                <div className="flex items-center justify-between gap-2 text-sm text-gray-500 dark:text-gray-400 mb-2">
                  <div className="flex items-center gap-2">
                    <CalendarIcon className="w-4 h-4" />
                    {formatResumeDate(resume['Created At'])}
                  </div>
                  {resume.consent_status && (
                    <ConsentBadge
                      status={resume.consent_status}
                      candidateName={resume.candidate_name}
                      candidateEmail={resume.candidate_email}
                      consentTokenExpiresAt={resume.consent_token_expires_at}
                      retentionUntil={resume.retention_until}
                      compact={true}
                    />
                  )}
                </div>
                
                {/* Firm badge */}
                {resume.FirmName && (
                  <div className="flex items-center gap-1 mb-3">
                    <BuildingOfficeIcon className="w-3 h-3 text-gray-400" />
                    <span className="text-xs text-gray-400 dark:text-gray-500">
                      {resume.FirmName}
                    </span>
                  </div>
                )}

                <div className="flex flex-wrap gap-1">
                  {(['Skills', 'Industries', 'Tools', 'Soft Skills'] as const).map(category => {
                    let tags: string[] = [];
                    try {
                      // Try cleaned tags first
                      const cleanedField = `${category} Cleaned`;
                      const cleanedValue = resume[cleanedField as keyof Resume];
                      if (cleanedValue && typeof cleanedValue === 'string') {
                        const cleanedTags = JSON.parse(cleanedValue);
                        if (Array.isArray(cleanedTags) && cleanedTags.length > 0) {
                          tags = cleanedTags;
                        }
                      }
                      // Fallback to raw tags
                      if (tags.length === 0) {
                        const rawValue = resume[category];
                        if (rawValue && typeof rawValue === 'string') {
                          tags = JSON.parse(rawValue);
                        }
                      }
                    } catch {
                      tags = [];
                    }
                    return tags.slice(0, 2).map((tag, idx) => (
                      <span key={`${category}-${idx}`} className={`text-xs px-2 py-0.5 rounded-full ${tagColorMap[category]}`}>
                        {tag}
                      </span>
                    ));
                  })}
                </div>
              </div>

              <div className="flex items-center gap-2 p-4 pt-0">
                <button
                  onClick={(e) => { e.stopPropagation(); handleResumeClick(resume); }}
                  className="flex-1 flex items-center justify-center gap-1 px-3 py-2 text-sm bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
                >
                  <EyeIcon className="w-4 h-4" />
                  {t('resumes.view')}
                </button>
                {resume['Resume File']?.[0] && (
                  <button
                    onClick={(e) => handleDownloadResume(resume, e)}
                    className="p-2 text-blue-600 dark:text-blue-400 hover:bg-blue-100 dark:hover:bg-blue-900/30 rounded-lg transition-colors"
                    title={resume['File Name'] || resume['Resume File']?.[0]?.filename || t('resumes.downloadResume')}
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" />
                  </button>
                )}
                <ManageResumeDealsModal 
                  resumeId={resume.id} 
                />
                <button
                  onClick={(e) => openDeleteConfirm(resume, e)}
                  className="p-2 text-red-600 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                  title={t('resumes.deleteResume')}
                >
                  <TrashIcon className="w-4 h-4" />
                </button>
              </div>
            </motion.div>
          ))}
        </div>
      )}

      {/* Bottom pagination */}
      <Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalCount={totalCount}
        pageSize={pageSize}
        onPageChange={goToPage}
        loading={loading}
        itemName={t('resumes.results')}
      />

      </>
      )}

      {showDeleteConfirm && resumeToDelete && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-md w-full"
          >
            <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-gray-700">
              <h3 className="text-xl font-bold text-gray-900 dark:text-white">{t('resumes.confirmDeleteTitle')}</h3>
              <button onClick={closeDeleteConfirm} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                <XMarkIcon className="w-6 h-6" />
              </button>
            </div>
            <div className="p-4">
              <p className="text-gray-700 dark:text-gray-300 mb-6">
                {t('resumes.confirmDeleteMessage', { filename: resumeToDelete['Resume File']?.[0]?.filename || resumeToDelete.Name || 'this resume' })}
              </p>
              <div className="flex justify-end gap-3">
                <button
                  onClick={closeDeleteConfirm}
                  className="px-4 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
                >
                  {t('common.cancel')}
                </button>
                <button
                  onClick={confirmDeleteResume}
                  disabled={deleting}
                  className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors disabled:opacity-50"
                >
                  {deleting ? t('common.deleting') : t('common.delete')}
                </button>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </motion.div>
  );
};

export default ResumesPage;

/**
 * SettingsPage Component
 * TypeScript version
 */

import { useState, useEffect, ForwardRefExoticComponent, RefAttributes, SVGProps } from 'react';
import { motion } from 'framer-motion';
import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';
import { Cog6ToothIcon, SparklesIcon, ScaleIcon, DocumentTextIcon, ChatBubbleLeftRightIcon, ShieldCheckIcon, UserCircleIcon } from '@heroicons/react/24/outline';
import { useAuthFetch } from '../hooks/useAuthFetch';
import { useChatbot } from '../context/ChatbotContext';
import logger from '../utils/logger.frontend';

import { LLMTab, PromptsTab, WeightsTab, ChatbotTab, GdprTab, DpoTab } from '../components/SettingsPage';
import Breadcrumbs from '../components/Breadcrumbs';

type HeroIcon = ForwardRefExoticComponent<Omit<SVGProps<SVGSVGElement>, 'ref'> & { title?: string; titleId?: string } & RefAttributes<SVGSVGElement>>;

interface Settings {
  id?: string;
  llmModel?: string;
  cvMode?: 'nominative' | 'anonymous';
  chatbotEnabled?: 'on' | 'off';
  'Analysis Prompt'?: string;
  'Improvement Prompt'?: string;
  'Match Analysis Prompt'?: string;
  'Adaptation Prompt'?: string;
  'Executive Summary Weight'?: number;
  'Skills Weight'?: number;
  'Experience Weight'?: number;
  'Education Weight'?: number;
  'ATS Weight'?: number;
  'Hobbies Languages Weight'?: number;
  'DPO Name'?: string;
  'DPO Email'?: string;
  'DPO Phone'?: string;
  analysisPrompt?: string;
  improvementPrompt?: string;
}

interface SettingsFormData {
  llmModel: string;
  cvMode: 'nominative' | 'anonymous';
  chatbotEnabled: 'on' | 'off';
  'Analysis Prompt': string;
  'Improvement Prompt': string;
  'Match Analysis Prompt': string;
  'Adaptation Prompt': string;
  'Executive Summary Weight': number;
  'Skills Weight': number;
  'Experience Weight': number;
  'Education Weight': number;
  'ATS Weight': number;
  'Hobbies Languages Weight': number;
  'DPO Name': string;
  'DPO Email': string;
  'DPO Phone': string;
  [key: string]: string | number | boolean;
}

interface Tab {
  id: string;
  name: string;
  icon: HeroIcon;
}

const SettingsPage = (): JSX.Element => {
  const { t } = useTranslation();
  const { authGet, authPost, authPut } = useAuthFetch();
  const { setChatbotEnabled } = useChatbot();
  const [settings, setSettings] = useState<Settings | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [saving, setSaving] = useState<boolean>(false);
  const [activeTab, setActiveTab] = useState<string>('llm');

  const [formData, setFormData] = useState<SettingsFormData>({
    llmModel: 'chatgpt-4o-latest',
    cvMode: 'nominative',
    chatbotEnabled: 'on',
    'Analysis Prompt': '',
    'Improvement Prompt': '',
    'Match Analysis Prompt': '',
    'Adaptation Prompt': '',
    'Executive Summary Weight': 20,
    'Skills Weight': 20,
    'Experience Weight': 20,
    'Education Weight': 15,
    'ATS Weight': 15,
    'Hobbies Languages Weight': 10,
    'DPO Name': '',
    'DPO Email': '',
    'DPO Phone': ''
  });

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async (): Promise<void> => {
    try {
      const response = await authGet('/api/settings');
      if (!response.ok) throw new Error('Failed to fetch settings');

      const data: Settings = await response.json();
      setSettings(data);
      setFormData({
        llmModel: data.llmModel || 'chatgpt-4o-latest',
        cvMode: data.cvMode || 'nominative',
        chatbotEnabled: data.chatbotEnabled || 'on',
        'Analysis Prompt': data['Analysis Prompt'] || '',
        'Improvement Prompt': data['Improvement Prompt'] || '',
        'Match Analysis Prompt': data['Match Analysis Prompt'] || '',
        'Adaptation Prompt': data['Adaptation Prompt'] || '',
        'Executive Summary Weight': data['Executive Summary Weight'] || 20,
        'Skills Weight': data['Skills Weight'] || 20,
        'Experience Weight': data['Experience Weight'] || 20,
        'Education Weight': data['Education Weight'] || 15,
        'ATS Weight': data['ATS Weight'] || 15,
        'Hobbies Languages Weight': data['Hobbies Languages Weight'] || 10,
        'DPO Name': data['DPO Name'] || '',
        'DPO Email': data['DPO Email'] || '',
        'DPO Phone': data['DPO Phone'] || ''
      });
      
      logger.log('[Settings] Prompts loaded:', {
        analysisPromptLength: data.analysisPrompt?.length || 0,
        improvementPromptLength: data.improvementPrompt?.length || 0
      });
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : '';
      if (!errorMessage.includes('Session expired')) {
        logger.error('Error fetching settings:', error);
        toast.error(t('settings.loadError'));
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async (): Promise<void> => {
    try {
      setSaving(true);

      const totalWeight = 
        Number(formData['Executive Summary Weight']) +
        Number(formData['Skills Weight']) +
        Number(formData['Experience Weight']) +
        Number(formData['Education Weight']) +
        Number(formData['ATS Weight']) +
        Number(formData['Hobbies Languages Weight']);

      if (totalWeight !== 100) {
        toast.error(`La somme des poids doit ├¬tre ├®gale ├á 100% (actuellement: ${totalWeight}%)`);
        setSaving(false);
        return;
      }

      // Ensure chatbotEnabled is 'on' or 'off' string (not boolean)
      const chatbotValue = formData.chatbotEnabled;
      const dataToSave = {
        ...formData,
        chatbotEnabled: chatbotValue === 'on' || (chatbotValue as unknown) === true ? 'on' : 'off'
      };

      logger.log('[SettingsPage] Saving settings with data:', JSON.stringify(dataToSave, null, 2));

      let response: Response;
      if (settings?.id) {
        response = await authPut(`/api/settings/${settings.id}`, dataToSave);
      } else {
        response = await authPost('/api/settings', dataToSave);
      }

      if (!response.ok) throw new Error('Failed to save settings');

      const data = await response.json();
      setSettings(data);
      
      // Update chatbot state in context immediately
      setChatbotEnabled(dataToSave.chatbotEnabled === 'on');
      
      toast.success(t('settings.saveSuccess'));
    } catch (error) {
      logger.error('Error saving settings:', error);
      toast.error(t('settings.saveError'));
    } finally {
      setSaving(false);
    }
  };

  const handleInputChange = (field: string, value: string | number | boolean): void => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const resetToDefaults = (): void => {
    if (window.confirm(t('settings.resetConfirm'))) {
      setFormData({
        llmModel: 'chatgpt-4o-latest',
        cvMode: 'nominative',
        chatbotEnabled: 'on',
        'Analysis Prompt': '',
        'Improvement Prompt': '',
        'Match Analysis Prompt': '',
        'Adaptation Prompt': '',
        'Executive Summary Weight': 20,
        'Skills Weight': 20,
        'Experience Weight': 20,
        'Education Weight': 15,
        'ATS Weight': 15,
        'Hobbies Languages Weight': 10,
        'DPO Name': '',
        'DPO Email': '',
        'DPO Phone': ''
      });
      toast.success(t('settings.resetSuccess'));
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen">
        <div className="text-xl">{t('settings.loading')}</div>
      </div>
    );
  }

  const tabs: Tab[] = [
    { id: 'llm', name: t('settings.tabs.llm'), icon: SparklesIcon },
    { id: 'prompts', name: t('settings.tabs.prompts'), icon: Cog6ToothIcon },
    { id: 'weights', name: t('settings.tabs.weights'), icon: ScaleIcon },
    { id: 'chatbot', name: t('settings.tabs.chatbot'), icon: ChatBubbleLeftRightIcon },
    { id: 'gdpr', name: t('settings.tabs.gdpr'), icon: ShieldCheckIcon },
    { id: 'dpo', name: t('settings.tabs.dpo'), icon: UserCircleIcon },
    { id: 'swagger', name: t('settings.tabs.apiDocs'), icon: DocumentTextIcon }
  ];

  const totalWeight = 
    Number(formData['Executive Summary Weight']) +
    Number(formData['Skills Weight']) +
    Number(formData['Experience Weight']) +
    Number(formData['Education Weight']) +
    Number(formData['ATS Weight']) +
    Number(formData['Hobbies Languages Weight']);

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="p-6 max-w-6xl mx-auto"
    >
      <Breadcrumbs className="mb-4" />
      
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">
          {t('settings.title')}
        </h1>
        <p className="text-gray-600 dark:text-gray-400">
          {t('settings.subtitle')}
        </p>
      </div>

      <div className="border-b border-gray-200 dark:border-gray-700 mb-6">
        <nav className="-mb-px flex space-x-8">
          {tabs.map((tab) => {
            const IconComponent = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`
                  flex items-center py-4 px-1 border-b-2 font-medium text-sm
                  ${activeTab === tab.id
                    ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-300'
                  }
                `}
              >
                <IconComponent className="w-5 h-5 mr-2" />
                {tab.name}
              </button>
            );
          })}
        </nav>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6">
        {activeTab === 'llm' && (
          <LLMTab formData={formData} onInputChange={handleInputChange} t={t} />
        )}

        {activeTab === 'prompts' && (
          <PromptsTab formData={formData} onInputChange={handleInputChange} t={t} />
        )}

        {activeTab === 'weights' && (
          <WeightsTab 
            formData={formData} 
            onInputChange={handleInputChange} 
            totalWeight={totalWeight}
            t={t} 
          />
        )}

        {activeTab === 'chatbot' && (
          <ChatbotTab formData={formData} onInputChange={handleInputChange} t={t} />
        )}

        {activeTab === 'gdpr' && (
          <GdprTab t={t} />
        )}

        {activeTab === 'dpo' && (
          <DpoTab formData={formData} onInputChange={handleInputChange} t={t} />
        )}

        {activeTab === 'swagger' && (
          <div className="space-y-6">
            <div>
              <h3 className="text-lg font-medium text-gray-900 dark:text-white mb-2">
                {t('settings.apiDocs.title')}
              </h3>
              <p className="text-gray-600 dark:text-gray-400 mb-4">
                {t('settings.apiDocs.description')}
              </p>
            </div>
            
            <div className="bg-gray-50 dark:bg-gray-700 rounded-lg p-6">
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="font-medium text-gray-900 dark:text-white">{t('settings.apiDocs.swaggerUi')}</h4>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                    {t('settings.apiDocs.swaggerUiDescription')}
                  </p>
                </div>
                <button
                  onClick={() => window.open(`/api/docs/ui?v=${Date.now()}`, '_blank')}
                  className="inline-flex items-center px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 font-medium text-sm"
                >
                  <DocumentTextIcon className="w-5 h-5 mr-2" />
                  {t('settings.apiDocs.openSwagger')}
                </button>
              </div>
            </div>

            <div className="bg-gray-50 dark:bg-gray-700 rounded-lg p-6">
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="font-medium text-gray-900 dark:text-white">{t('settings.apiDocs.openApiJson')}</h4>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                    {t('settings.apiDocs.openApiJsonDescription')}
                  </p>
                </div>
                <button
                  onClick={() => window.open(`/api/docs?v=${Date.now()}`, '_blank')}
                  className="inline-flex items-center px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-md hover:bg-gray-100 dark:hover:bg-gray-600 font-medium text-sm"
                >
                  {t('settings.apiDocs.viewJson')}
                </button>
              </div>
            </div>
          </div>
        )}

        <div className="mt-8 flex items-center justify-between pt-6 border-t border-gray-200 dark:border-gray-700">
          <button
            onClick={resetToDefaults}
            className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white"
          >
            {t('settings.reset')}
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            className="px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed font-medium"
          >
            {saving ? t('settings.saving') : t('settings.save')}
          </button>
        </div>
      </div>
    </motion.div>
  );
};

export default SettingsPage;

/**
 * TagsManagement Page
 * TypeScript version
 */

import { useState, useEffect, ChangeEvent, KeyboardEvent, ForwardRefExoticComponent, RefAttributes, SVGProps, useMemo } from 'react';
import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';
import { tagService } from '../utils/tagService';
import { motion } from 'framer-motion';
import logger from '../utils/logger.frontend';
import {
  TagIcon,
  PencilSquareIcon,
  ArrowPathIcon,
  XMarkIcon,
  WrenchScrewdriverIcon,
  BriefcaseIcon,
  SparklesIcon,
  HeartIcon,
  MagnifyingGlassIcon,
  BeakerIcon,
  DocumentTextIcon,
  GlobeEuropeAfricaIcon
} from '@heroicons/react/24/outline';
import Breadcrumbs from '../components/Breadcrumbs';

type HeroIcon = ForwardRefExoticComponent<Omit<SVGProps<SVGSVGElement>, 'ref'> & { title?: string; titleId?: string } & RefAttributes<SVGSVGElement>>;

interface CategoryConfig {
  icon: HeroIcon;
  color: string;
  bgLight: string;
  textColor: string;
  tagBg: string;
  tagText: string;
  tagBorder: string;
}

interface Tags {
  [category: string]: string[];
}

interface EditingTag {
  category: string;
  tag: string;
}

interface CleanedTags {
  [category: string]: string[];
}

interface EscoTagItem {
  label: string;
  uri: string;
