import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';
import { 
  UserCircleIcon, 
  ShieldCheckIcon, 
  KeyIcon,
  EnvelopeIcon,
  PhoneIcon,
  BriefcaseIcon
} from '@heroicons/react/24/outline';
import { useAuth } from '../context/AuthContext';
import { useAuthFetch } from '../hooks/useAuthFetch';
import Breadcrumbs from '../components/Breadcrumbs';
import logger from '../utils/logger.frontend';
import TwoFactorSettings from '../components/TwoFactorSettings';

interface UserProfile {
  id: string;
  name: string;
  email: string;
  jobTitle?: string;
  phone?: string;
  firm?: string;
}

const UserProfilePage = (): JSX.Element => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { authGet, authPut } = useAuthFetch();
  const [activeTab, setActiveTab] = useState<'profile' | 'security'>('profile');
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    jobTitle: '',
    phone: ''
  });

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await authGet('/api/auth/me');
      if (response.ok) {
        const data = await response.json();
        setProfile(data.user);
        setFormData({
          name: data.user.name || '',
          jobTitle: data.user.jobTitle || data.user.job_title || '',
          phone: data.user.phone || ''
        });
      }
    } catch (error) {
      logger.error('[UserProfile] Failed to fetch profile:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const response = await authPut(`/api/users/${user?.id}`, {
        name: formData.name,
        jobTitle: formData.jobTitle,
        phone: formData.phone
      });

      if (response.ok) {
        toast.success('Profil mis ├á jour');
        fetchProfile();
      } else {
        toast.error('Erreur lors de la mise ├á jour');
